INSERT INTO `app_user` (`user_id`, `username`, `password`, `role`, `is_active`, `created_at`) VALUES
	(1, 'admin', 'admin@123', 'ADMIN', 1, '2026-01-26 09:24:19'),
	(2, 'shubham', 'shubham@123', 'USER', 1, '2026-01-26 09:27:33'),
	(3, 'shubha', 'shubbha@123', 'USER', 1, '2026-01-27 18:37:16');
INSERT INTO `explanation` (`explanation_id`, `question_id`, `explanation_text`, `created_at`, `is_active`) VALUES
	(1, 1, 'Correct Answer is YES. \n\nExplanation:\nAzure Web Apps (Azure App Service) is a Platform as a Service (PaaS) offering.\nOne of the built-in features of App Service is automatic scaling:\n	Scale out/in (number of instances)\n	Scale up/down (pricing tier)\nScaling can be based on:\n	CPU usage\n	Memory\n	HTTP queue length\n	Schedules\nSo the platform does have the ability to scale automatically.', '2026-01-25 17:48:46', 1),
	(2, 2, 'Correct answer: No\r\n \r\nExplanation\r\nEven if both virtual machines are the same size (D2s_v3), they will not always generate the same monthly cost because Azure \r\nVM costs depend on usage and configuration, such as:\r\n	Running time (24×7 vs stopped/deallocated)\r\n	OS type (Windows costs more than Linux due to licensing)\r\n	Region (prices vary by region)\r\n	Attached resources (disks, public IPs, backups)\r\n	Billing model (pay-as-you-go vs Reserved Instances)\r\nSo two identical VM sizes can still result in different monthly bills', '2026-01-25 17:55:06', 1),
	(3, 3, 'Correct answer: Azure AI Bot \r\nExplanation \r\nUsed to build chatbots and digital assistants \r\nSupports: \r\n	Text-based conversations\r\n	Speech-to-text and text-to-speech (via Azure Cognitive Services)\r\nCan be integrated with: \r\n	Websites\r\n	Mobile apps\r\n	Microsoft Teams\r\n	Voice channels\r\n \r\n❌ Why the other options are incorrect \r\n	Machine Learning : Used for building ML models, not chat/voice assistants. \r\n	Azure IoT Hub : Used for IoT device communication, not digital assistants. \r\n	Azure Functions : Used for serverless code execution, not bot/voice interactions. ', '2026-01-25 18:03:31', 1),
	(4, 4, 'Correct answer: ✅ Azure Machine Learning \r\n\r\nAzure Machine Learning is designed for: \r\n  Training machine learning models \r\n  Using historical data to build predictive models \r\n  Evaluating model accuracy and probability \r\n  Deploying predictive services (real‑time or batch inference) \r\n\r\nThis exactly matches the requirement of making predictions from past training data. \r\n\r\n❌ Why the other options are incorrect: \r\n	Azure IoT Hub: Used for connecting and managing IoT devices, not predictive analytics. \r\n	Azure AI Bot: Used to build chatbots and virtual assistants, not predictive models. \r\n	Azure Functions: Serverless code execution; does not create predictive models.', '2026-01-25 18:13:59', 1),
	(5, 5, 'Correct answer: Azure Functions', '2026-01-25 18:21:14', 1),
	(6, 6, 'Correct answer: Azure IoT Hub', '2026-01-25 18:25:07', 1),
	(7, 7, 'Correct answer: ✅ Azure Resource Manager Templates \r\n\r\n✅ Why this fits the requirements: \r\n  Automation: Azure Resource Manager (ARM) templates are specifically designed to automate deployments. \r\n  Same resource type: You can define a template once and reuse it to deploy identical resources. \r\n  Across departments: Templates can be deployed repeatedly across different resource groups, subscriptions, or departments. \r\n\r\n❌ Why the other options don’t fit:\r\n	Virtual Machine Scale Sets \r\n		Used to deploy and manage a group of identical VMs, but only for compute scaling—not general resource deployment. \r\n\r\n	Management Groups \r\n		Help organize subscriptions and apply governance (like policies), not deploy resources. \r\n\r\n	Microsoft Entra ID (formerly Azure AD) \r\n		Handles identity and access management, not resource deployment. ', '2026-01-25 18:30:07', 1),
	(8, 8, 'Correct answer: ✅ Two virtual machines and Two availability zones\r\n \r\nTo meet a 99.99% SLA in Azure, you must use Availability Zones with multiple virtual machines. Azure only provides this SLA when you deploy at least two VMs across different availability zones.\r\n\r\nWhy:\r\n	A single VM (even in one or multiple zones) does not meet 99.99% SLA.\r\n	Azure’s SLA for Availability Zones requires:\r\n		At least 2 VMs\r\n		Each VM placed in different availability zones\r\n	This setup protects against:\r\n		Data center failures\r\n		Zone-level outages\r\n\r\nKey idea:\r\n	Availability Set → 99.95% SLA\r\n	Availability Zones (2+ VMs across zones) → 99.99% SLA\r\n\r\nSo the minimum valid architecture is:\r\n👉 2 VMs distributed across 2 Availability Zones', '2026-01-25 18:34:33', 1),
	(9, 9, 'Explanation\r\nThe requirement is:\r\n	Correlate events from multiple resources\r\n	Store them in a central repository for analysis\r\nAzure Log Analytics is part of Azure Monitor and provides:\r\n	Centralized collection of logs and metrics from VMs, storage, networking, and other resources\r\n	Powerful querying and correlation of events\r\n	Basis for dashboards, alerts, and insights', '2026-01-25 18:38:13', 1),
	(12, 10, 'Implementing a DDoS protection plan protects against distributed denial-of-service attacks, but it does not automatically ensure that the application is accessible over HTTPS. You also need to configure a public endpoint and HTTPS listener on the VM or use Azure Application Gateway.', '2026-01-25 18:42:01', 1),
	(13, 11, 'Azure Traffic Manager is a DNS-based load balancer that distributes traffic across multiple endpoints. It does not directly make the application accessible over HTTPS on a single VM. You need a public endpoint and HTTPS listener to satisfy the requirement.', '2026-01-25 18:47:53', 1),
	(14, 12, 'Correct answer : ✅ United States government entity, ✅ A United States government contractor \r\n\r\nAzure Government is a separate Azure cloud designed specifically for: \r\n  U.S. federal agencies \r\n  U.S. state and local governments \r\n  U.S. government contractors \r\n  U.S. government‑approved partners \r\n\r\nThis environment meets strict compliance requirements such as: \r\n  FedRAMP High \r\n  DoD Impact Levels \r\n  CJIS \r\n  ITAR \r\n\r\nBecause these regulations apply only to U.S. government operations, Azure Government cannot be used by: \r\n  European government entities \r\n  European government contractors \r\n  Any non‑U.S. organizations ', '2026-01-25 18:48:15', 1),
	(15, 13, 'Azure MFA can be implemented using the cloud-only solution in Azure Active Directory without deploying a federated solution.', '2026-01-25 18:48:42', 1),
	(16, 14, 'Azure MFA methods include phone call, text message, and mobile app notification or verification code. Picture identification and passport number are not valid MFA methods.', '2026-01-25 18:48:57', 1),
	(17, 15, 'The Basic support plan gives access to billing, subscription, and service health information at no additional cost.', '2026-01-25 18:49:05', 1),
	(18, 16, 'In Azure Web Apps (PaaS), Microsoft manages the underlying operating system. You do not have full control over it.', '2026-01-25 18:49:14', 1),
	(19, 17, 'Stopping a VM does not remove the storage; you will continue to pay for the underlying storage.', '2026-01-25 18:49:22', 1),
	(20, 18, 'Azure allows flexibility between CapEx and OpEx through options like reserved instances, pay-as-you-go pricing, and hybrid use benefits.', '2026-01-25 18:49:29', 1),
	(21, 19, 'In SaaS, the cloud provider manages installation, scalability, and high availability. The user is responsible for configuring the application for their needs.', '2026-01-25 18:49:52', 1),
	(22, 20, 'Fault tolerance ensures that systems remain available even if a data center or component fails, which meets the business continuity requirement.', '2026-01-25 18:50:02', 1),
	(23, 21, 'A company can decommission its data center if the infrastructure is fully hosted in the public cloud, eliminating the need for on-premises resources.', '2026-01-25 18:53:10', 1),
	(24, 22, 'Hosting a website on Azure incurs monthly hosting costs. A VPN or per-connection charges are not required for a public web site.', '2026-01-25 18:53:24', 1),
	(25, 23, 'Correct answer: ✅ No\r\n\r\nRunning the script from a Linux computer with Azure CLI tools installed does not meet the goal. The requirement is to run a PowerShell script, which specifically needs Azure PowerShell modules (Az module) installed. Azure CLI is a separate toolset with its own command syntax, and it cannot execute PowerShell cmdlets.\r\n\r\n✅ Correct configuration:\r\n        A computer running Windows, macOS, or Linux\r\n        With PowerShell installed\r\n        And the Azure PowerShell Az module added\r\n\r\nThat setup ensures the PowerShell script can properly create and manage Azure resources.', '2026-01-25 18:53:33', 1),
	(26, 24, 'Azure Cloud Shell runs in the browser and supports PowerShell scripts, regardless of the underlying OS.', '2026-01-25 18:53:41', 1),
	(27, 25, 'PowerShell Core is cross-platform. Scripts can run on macOS as long as PowerShell Core is installed.', '2026-01-25 18:53:50', 1),
	(28, 26, 'Planned maintenance events are listed in the Help + Support blade in the Azure portal.', '2026-01-25 18:54:01', 1),
	(29, 27, 'Azure DevOps provides an integrated CI/CD solution for deploying code to Azure.', '2026-01-25 18:54:15', 1),
	(30, 28, 'Azure Advisor analyzes your Azure environment and provides personalized recommendations to optimize cost, security, reliability, and performance.', '2026-01-25 18:54:29', 1),
	(31, 29, 'Azure Cognitive Services provides AI capabilities to build intelligent applications without needing to train models from scratch.', '2026-01-25 18:54:41', 1),
	(32, 30, 'Azure Application Insights is an Application Performance Management (APM) service that monitors live web applications and provides actionable telemetry.', '2026-01-25 18:54:52', 1),
	(33, 31, 'Azure File Storage allows SMB protocol access and mapped drives from Windows computers, making it ideal for file sharing.', '2026-01-25 18:58:51', 1),
	(34, 32, 'Azure Cosmos DB supports globally distributed, multi-region writes and can store JSON documents natively.', '2026-01-25 18:59:06', 1),
	(35, 33, 'Resource groups are logical containers. Resources inside can be deployed in different regions; they are not restricted to the resource group region.', '2026-01-25 18:59:17', 1),
	(36, 34, 'Tags assigned to a resource group are not inherited automatically by resources inside the group; tags must be applied individually or via policies.', '2026-01-25 18:59:26', 1),
	(37, 35, 'IAM permissions assigned at the resource group level are inherited by resources within that group.', '2026-01-25 18:59:35', 1),
	(38, 36, 'Azure Machine Learning Studio allows building, testing, and deploying predictive analytics and AI solutions.', '2026-01-25 18:59:43', 1),
	(39, 37, 'Azure Advisor provides recommendations across cost, security, reliability, performance, including VM network configuration.', '2026-01-25 18:59:53', 1),
	(40, 38, 'Azure Advisor analyzes resources and provides recommendations to reduce costs, including optimizing VM usage.', '2026-01-25 19:00:04', 1),
	(41, 39, 'Azure Advisor provides security recommendations for Microsoft Entra ID to improve identity security and compliance.', '2026-01-25 19:00:13', 1),
	(42, 40, 'Azure CLI runs natively on Ubuntu, Azure PowerShell runs if PowerShell Core is installed, and the Azure Portal runs in any browser, including Ubuntu.', '2026-01-25 19:02:01', 1),
	(43, 41, 'Microsoft Entra ID Protection provides risk-based conditional access and can require password change when sign-in occurs from anonymous or risky IP addresses.', '2026-01-25 19:05:48', 1),
	(44, 42, 'Network Security Groups (NSGs) are used to control inbound and outbound traffic to Azure resources at the network interface or subnet level.', '2026-01-25 19:05:57', 1),
	(45, 43, 'Azure Policies allow organizations to enforce and manage compliance of resources across multiple subscriptions, ensuring resources meet governance requirements.', '2026-01-25 19:06:53', 1),
	(46, 44, 'The Basic Support plan does not provide 24/7 access to support engineers by phone or email; it only provides access to billing and subscription support.', '2026-01-25 19:07:26', 1),
	(47, 45, 'The Standard Support plan provides 24/7 access to support engineers via phone and email, satisfying the requirement.', '2026-01-25 19:07:45', 1),
	(48, 46, 'Most Azure services are initially released in private preview for selected customers before being made generally available or in public preview.', '2026-01-25 19:08:00', 1),
	(49, 47, 'Azure services in public preview can be managed via the portal, CLI, or SDKs; CLI is not the only option.', '2026-01-25 19:08:14', 1),
	(50, 48, 'Private preview is limited to select customers; it is not available to all Azure customers.', '2026-01-25 19:08:31', 1),
	(51, 49, 'Public preview services are made available to all Azure customers for testing and early use, though they may not yet be generally available.', '2026-01-25 19:09:37', 1),
	(52, 50, 'Generally available Azure services are released to all customers for production use.', '2026-01-25 19:09:55', 1),
	(53, 51, 'A single Microsoft Account (MSA) or Microsoft Entra ID user can manage multiple subscriptions, including subscriptions across different tenants with proper permissions.', '2026-01-25 19:12:09', 1),
	(54, 52, 'Azure subscriptions cannot be merged. You can move resources between subscriptions or group subscriptions under the same Management Group, but merging is not supported.', '2026-01-25 19:13:16', 1),
	(55, 53, 'Azure SLAs are service-specific and depend on configuration. Not all paid services have a blanket 99.9% SLA.', '2026-01-25 19:13:29', 1),
	(56, 54, 'Deploying resources across multiple regions improves availability, resiliency, and fault tolerance, often increasing effective SLA.', '2026-01-25 19:13:40', 1),
	(57, 55, 'SLA is tied to service and deployment architecture; purchasing multiple subscriptions does not increase SLA.', '2026-01-25 19:13:55', 1),
	(58, 56, 'Azure allows moving resources, including VMs, between subscriptions within the same tenant if supported by the resource type.', '2026-01-25 19:14:09', 1),
	(59, 57, 'Microsoft Entra ID users and groups do not incur costs. Only billable resources, like Public IPs, generate charges.', '2026-01-25 19:14:23', 1),
	(60, 58, 'Microsoft Entra ID user groups do not generate cost; removing them does not reduce Azure bills.', '2026-01-25 19:14:40', 1),
	(61, 59, 'Public IP addresses are billable resources. Removing unused public IPs will reduce Azure costs.', '2026-01-25 19:14:55', 1),
	(62, 60, 'Azure Portal is web-based and accessible from any device with a modern browser, including Android devices.', '2026-01-25 19:15:35', 1),
	(63, 61, 'The PowerApps (Power Apps) portal is used to build and manage low-code business applications, \nnot to create or manage Azure infrastructure like virtual machines.\n\nEven though the team member is on an Android-based laptop, that’s not the real blocker here—the issue is the tool:\n	Azure VMs can be created via \n	the Azure Portal, \n	Azure CLI, \n	PowerShell, \n	or ARM/Bicep templates (all accessible via a browser).\n\nPowerApps portal does not support creating Azure virtual machines.', '2026-02-13 02:56:03', 1),
	(64, 62, 'The correct answer is:\n\nhttps://portal.azure.com\n\nThis is the Azure Portal, which is used to create, manage, and monitor Azure resources such as virtual machines, \nstorage accounts, networks, databases, and more.\n\nQuick rundown of the others:\n❌ admin.azure.com – Not used for Azure resource management\n❌ admin.azurewebsites.com – Not a valid Azure management portal\n❌ portal.microsoft.com – General Microsoft portal, not for Azure resources\n❌ portal.azurewebsites.com – Related to App Service, not full Azure management', '2026-02-13 02:58:13', 1),
	(65, 63, 'Azure virtual machine data disks (and OS disks) are stored as page blobs within an Azure Blob Storage account.\n\nWhy not the others?\n❌ Files – Used for file shares (Azure Files), not VM disks\n❌ Tables – Used for NoSQL key-value storage\n❌ Queues – Used for messaging between components', '2026-02-13 02:59:59', 1),
	(66, 64, 'The best choices are:\n	Azure Synapse Analytics\n	Azure Data Lake\n\nWhy these two fit the requirements:\nAzure Data Lake\n	Designed for very large data volumes (10TB+ is normal)\n	Cost-effective for infrequently accessed data\n	Commonly used as a data store for analytics\n	Can be directly queried or connected to analytics engines\n\nAzure Synapse Analytics\n	Built for analytics and reporting at scale\n	Native integration with Power BI (this is a big clue in the question)\n	Can query data stored in Azure Data Lake using serverless or dedicated SQL pools\n\nTogether, this is a very common Azure pattern:\n	Azure Data Lake (storage) + Azure Synapse Analytics (analytics) + Power BI (visualization)', '2026-02-13 03:01:32', 1),
	(67, 65, 'The correct answer is:\n✅ Deploy all the virtual machines to the same resource group.\n\nWhy this works:\n	Azure RBAC (Role-Based Access Control) can be applied at the resource group level\n	Any permissions assigned to the resource group are automatically inherited by all virtual machines inside it\n	This lets you manage permissions for multiple VMs simultaneously and consistently\n\nWhy the others don’t meet the requirement:\n	❌ Same region – Regions affect location, not permissions\n	❌ Same availability zone – Used for high availability, not access control\n	❌ Same scale – (Likely referring to scale sets) Used for auto-scaling, not general permission assignment\n', '2026-02-13 03:03:48', 1),
	(68, 66, 'The correct answer is:\n\n✅ The Azure platform is a shared platform wherein multiple companies can use a portion of the resources on the platform.\n\nWhy this is a benefit:\nAzure is a public cloud that uses a shared (multi-tenant) infrastructure\n\nThis allows organizations to:\nAvoid buying and maintaining their own hardware\nPay only for what they use\nScale resources up or down easily\nCosts are lower because the underlying infrastructure is shared across many customers\n\nWhy the other options are incorrect:\n❌ All resources can be accessed by the public — Azure resources are isolated and secured\n❌ Private cloud platform — Azure is not a private cloud by default\n❌ E-commerce platform — Azure is a cloud services platform, not a marketplace for users to sell resources\n', '2026-02-13 03:05:19', 1),
	(69, 67, 'Shared infrastructure – Public cloud providers (like Azure) use a multi-tenant model where physical resources are shared securely among multiple customers.\nPay-as-you-go model – You pay only for the resources you consume, with no upfront hardware costs.\n\nWhy the others are not public cloud characteristics:\n❌ Dedicated hardware resources – This is typical of private cloud\n❌ On-premises deployment – That’s not cloud\n❌ Limited geographic availability – Public clouds have global availability', '2026-02-13 03:07:29', 1),
	(70, 68, 'Correct Answer is:\n	Yes.\n	This does meet the goal.\n\nWhy:\n	Azure App Service is a Platform as a Service (PaaS) offering for hosting applications.\n	Azure SQL Database is also a PaaS database service (Microsoft manages the OS, patching, backups, and high availability).\n	Since both services are PaaS, the solution fully aligns with the migration plan that requires only PaaS solutions.', '2026-02-13 03:08:18', 1),
	(71, 69, 'The correct answer is:\n✅ Platform as a Service (PaaS)\n\nWhy PaaS is the best choice:\nMinimizes administrative and management effort\nAzure manages the OS, patching, scaling, and infrastructure\nIdeal for web applications accessed by external users\nYou focus on application code, not servers\n\nWhy not the others?\n❌ SaaS – You consume a finished application; you can’t deploy your own web app\n❌ IaaS – Requires managing VMs, OS updates, and security (more admin effort)\n❌ DaaS – Refers only to databases, not full web apps', '2026-02-13 03:09:24', 1),
	(72, 70, 'The correct answer is:\n	✅ A hybrid cloud\n\nWhy a hybrid cloud fits the requirements:\n	Provides additional resources: You can burst to the public cloud when on-premises resources are insufficient.\n	Minimizes capital expenditure (CapEx): You don’t need to buy new servers or build a full data center.\n	Minimizes operational expenditure (OpEx): You only pay for cloud resources when you need them.\n	Maintains some on-premises control: Critical workloads can remain on-premises while others run in the cloud.', '2026-02-13 03:12:14', 1),
	(73, 71, 'The correct answer is:\n\nThe public cloud is a shared entity whereby multiple corporations each use a portion of the resources in the cloud.\n\nThis is the key advantage: multi-tenancy. Public cloud providers like Azure share infrastructure across many customers, which lowers costs, improves scalability, and reduces the need for organizations to manage their own hardware.\n\nWhy the others are incorrect, quickly:\n❌ Owned by the public — Public clouds are owned by private companies (e.g., Microsoft, Amazon, Google).\n❌ Crowd-sourcing solution — Not how public clouds work.\n❌ Freely accessed by everyone — Access is controlled and secured; it’s not open to the public.', '2026-02-28 11:02:30', 1),
	(74, 72, 'The correct answer is:\n✅ Operational\n\nWhy:\nAn Azure pay-as-you-go subscription uses an operational expenditure (OpEx) model. You pay for compute, storage, and networking as you consume them, rather than buying hardware upfront.\n\nQuick check on the other options:\n❌ Capital – This applies to on-premises infrastructure where you purchase hardware in advance (CapEx).\n❌ Elastic – This is a cloud characteristic, not an expenditure model.\n❌ Scalable – Also a feature, not a cost model.\n\nSo for migrating on-prem Hyper-V VMs to Azure pay-as-you-go → Operational expenditure is the right choice. ✔️', '2026-02-28 11:02:30', 1),
	(75, 73, 'The correct answer is:\n✅ An Azure virtual machine\n\nWhy:\nInfrastructure as a Service (IaaS) provides basic computing resources like virtual machines, storage, and networking, where you manage the OS and software yourself.\n\nWhy the others are not IaaS:\n❌ Azure web app – Platform as a Service (PaaS)\n❌ Azure logic app – PaaS (serverless workflow service)\n❌ Azure SQL database – PaaS (managed database service)', '2026-02-28 11:02:30', 1),
	(76, 74, '✅ Azure DevTest Labs\n\nWhy:\nAzure DevTest Labs is designed specifically to quickly provision and delete virtual machines with minimal administrative overhead. It works very well with Azure Resource Manager (ARM) templates, and it includes built-in features like:\nEasy bulk VM creation and deletion\nAutomated shutdown and cleanup\nPolicies to control costs and usage\n\nThis makes it ideal for scenarios where VMs are frequently created and removed, like weekly dev/test cycles.\n\nWhy the others don’t fit:\n❌ Azure Reserved VM Instances – Cost-optimization for long-running VMs, not rapid deployment/removal.\n❌ Azure VM scale sets – Best for scaling identical VMs for apps, not frequent lifecycle management by developers.\n❌ Microsoft Managed Desktop – End-user desktop service, not VM deployment automation.', '2026-02-28 11:02:30', 1),
	(77, 75, '👉 Correct answer: No ✔️\n\nExplanation:\nThe migration plan requires only Platform as a Service (PaaS) solutions.\n\nAzure virtual machines are Infrastructure as a Service (IaaS) ❌\nAzure SQL databases are PaaS ✅\nAzure Storage accounts are considered PaaS ✅\nBecause the solution includes Azure virtual machines (IaaS), it does not meet the requirement to use only PaaS services.', '2026-02-28 11:02:30', 1),
	(78, 76, 'The correct answer is:\n✅ Infrastructure as a Service (IaaS)\n\nWhy:\nThe applications require custom software and multiple prerequisite applications and services to be installed. That means you need full control over:\n	The operating system\n	Installed software and dependencies\n	Application configuration\n	This level of control is provided by IaaS (for example, Azure virtual machines).\n\nWhy not the others:\n	❌ SaaS – Ready-to-use applications; you don’t deploy or customize the underlying app stack.\n	❌ PaaS – You manage the app, but the platform controls the OS and limits installing custom prerequisite software.', '2026-02-28 11:02:30', 1),
	(79, 77, 'Correct answer: ✅ No change is needed.\n\nAn Azure region is defined as:\n        A set of one or more data centers,\n        Located within a specific geographic area,\n        Connected by a low-latency network to ensure performance and reliability.\n\nThe other options are incorrect because:\n❌ Is found in each country where Microsoft has a subsidiary office → Azure regions are strategically placed, not in every country.\n        \n❌ Can be found in every country in Europe and the Americas only → Azure regions exist worldwide, including Asia, Africa, and Australia.\n        \n❌ Contains one or more data centers that are connected by using a high-latency network → Azure regions are specifically designed for low-latency connections.', '2026-02-28 11:02:30', 1),
	(80, 78, 'The correct answers are:\n	✅ Command Prompt\n	✅ Windows PowerShell\n\nWhy:\nThe Azure CLI can be run from:\n	Command Prompt\n	Windows PowerShell\n	(also Bash / Cloud Shell, but those aren’t options here)\n\nWhy the others are incorrect:\n	❌ Azure Resource Explorer – Used to view and manage Azure resources, not to run the CLI.\n	❌ Windows Defender Firewall – Security tool, unrelated to CLI execution.\n	❌ Network and Sharing Center – Network configuration tool, not for command execution.', '2026-02-28 11:02:30', 1),
	(81, 79, 'The correct answers are:\n✅ Azure Data Lake\n✅ Azure Synapse Analytics\n\nWhy these two fit best:\nAzure Data Lake is ideal for storing large volumes of data (20 TB) that are accessed infrequently. It’s cost-effective and designed for analytics scenarios.\nAzure Synapse Analytics integrates seamlessly with Power BI and is built for analyzing and visualizing large datasets stored in places like Azure Data Lake.\n\nWhy the others are not ideal:\n❌ Azure Cosmos DB – Optimized for low-latency, high-transaction workloads, not infrequent access analytics.\n❌ Azure SQL Database – Better for structured, transactional workloads; expensive and inefficient at 20 TB for analytics.\n❌ Azure Database for PostgreSQL – Relational database, not designed for large-scale analytics and BI scenarios.', '2026-02-28 11:02:31', 1),
	(82, 80, 'The correct answer is:\n✅ An Azure data center failure\n\nWhy:\nAzure Availability Zones are designed to protect applications and services from data center–level failures. Each Availability Zone is a physically separate data center within the same Azure region, with independent power, cooling, and networking.\n\nWhy the others are incorrect:\n❌ A physical server failure – This is handled by Azure’s built-in redundancy and high availability within a data center.\n❌ An Azure region failure – Availability Zones do not protect against entire region outages (that’s what region pairs are for).\n❌ A storage failure – Storage redundancy options (like LRS, ZRS, GRS) handle this, not Availability Zones directly.', '2026-02-28 11:02:31', 1),
	(83, 81, 'The correct answer is Azure Monitor ✅\n\nWhy:\nService failure notifications (like regional outages, planned maintenance, or health advisories that could affect VM1 in East US) are provided through Azure Service Health, which you access from the Azure Monitor blade in the Azure portal.\n\nWhy the others are wrong:\nAzure Service Fabric – a microservices platform, not for viewing outages.\nAzure virtual machines – shows VM-specific settings and metrics, not Azure-wide service failures.\nAzure Advisor – gives optimization and best-practice recommendations, not real-time failure notifications.', '2026-02-28 12:12:25', 1),
	(84, 82, 'No. ❌\n\nWhy:\nA PowerShell script that creates Azure resources typically uses Azure PowerShell (Az module) cmdlets, not the Azure CLI. Installing only the Azure CLI on a Linux computer doesn’t satisfy that requirement.\n\nWhat would work instead:\n\nA computer (Windows, Linux, or macOS) with PowerShell installed and\n\nThe Azure PowerShell (Az) module installed\n\n💡 Linux can work, but only if it’s running PowerShell Core + Azure PowerShell, not just the Azure CLI.', '2026-02-28 12:12:25', 1),
	(85, 83, 'Running the script from a computer that uses Chrome OS with Azure Cloud Shell does meet the goal. Azure Cloud Shell is browser-based and supports PowerShell, so the local operating system doesn’t matter—as long as it can access a modern web browser like Chrome.', '2026-02-28 12:12:25', 1),
	(86, 84, 'You should create one Azure Firewall.\n\nWhy:\nAzure Firewall is a centralized, stateful firewall that can control and limit inbound (and outbound) traffic across multiple virtual networks. It’s designed exactly for this kind of scenario—many VNets and VMs with a single point of traffic control.\n\nWhy the others don’t fit:\nApplication Security Group (ASG): Used to group VMs for NSG rules, not to centrally limit inbound traffic for all VNets.\nVirtual network gateways: Used for VPNs, not traffic filtering.\nAzure ExpressRoute circuits: Used for private connectivity, not security filtering.', '2026-02-28 12:12:25', 1),
	(87, 85, 'Correct answers:\n	A virtual network gateway\n	A gateway subnet\n\nYou’re basically describing hybrid connectivity (on-premises → Azure VMs). For that, Azure uses a VPN gateway setup.\nTo make this work, you must create:\nA virtual network gateway\n	This is the VPN endpoint in Azure that allows your on-premises network to connect to Azure.\nA gateway subnet\n	A virtual network gateway must be deployed into a dedicated subnet named GatewaySubnet inside the virtual network.\n\nWhy not the others?\n	❌ Load balancer – used for distributing traffic, not for hybrid connectivity\n	❌ Application gateway – Layer 7 HTTP/HTTPS routing, not VPN connectivity\n	❌ Virtual network – required overall, but the key resources specifically enabling on-premises communication are the gateway and its subnet', '2026-02-28 12:12:25', 1),
	(88, 86, 'Yes.\n\nUsing Bash in Azure Cloud Shell absolutely meets the goal. 👍\nCloud Shell runs in the browser, so it doesn’t matter that the tablet is running Android. \nAs long as you can access the Azure portal and open Cloud Shell, you can create and manage Azure virtual machines using Azure CLI commands.', '2026-02-28 12:12:25', 1),
	(89, 87, 'To meet the requirement that FinServer must be on a separate network segment, you need network-level isolation, not just management or access controls.\n\nBest recommendation:\n	✅ A virtual network for FinServer and another virtual network for all the other servers.\n\nWhy this is correct\n	An Azure virtual network (VNet) is a network segment.\n	Placing FinServer in its own VNet guarantees isolation from the other servers at the network level.\n	This cleanly satisfies compliance policies that require separation.\n\nWhy the other options don’t work\n	❌ Separate resource groups – resource groups are for management and billing, not network isolation\n	❌ VPN and virtual network gateway – these are for connectivity, not segmentation\n	❌ Resource lock – prevents changes, but does nothing for network separation', '2026-02-28 12:12:25', 1),
	(90, 88, 'To map a network drive from Windows 10 computers, Azure needs to provide an SMB file share, just like a traditional file server.\n\n✅ Correct choice\n	A Files service in a storage account.\n\nWhy this works\n	Azure Files supports the SMB protocol, which Windows uses for mapped network drives.\n	You can map it directly using a drive letter (e.g., Z:) from Windows 10.\n	It’s designed exactly for shared file access scenarios.\n\nWhy the others don’t fit\n	❌ Azure SQL database – structured data, not files\n	❌ Virtual machine data disk – attached to a single VM, not a shared network drive\n	❌ Blobs service – object storage; cannot be mapped as a Windows network drive', '2026-02-28 12:12:25', 1),
	(91, 89, 'To start using and exploring Azure at all, you need a billing and access boundary first.\n\n✅ Correct answer\n	A subscription.\n\nWhy this comes first\nAn Azure subscription is required before you can create any Azure resources.\nIt defines billing, quotas, and access control.\nResource groups, virtual networks, and management groups all exist within or above subscriptions, so they can’t be used until a subscription exists.\n\nWhy the others come later\n	❌ Resource group – requires a subscription\n	❌ Virtual network – requires a resource group and subscription\n	❌ Management group – used to organize multiple subscriptions, not required to start exploring Azure', '2026-02-28 12:12:25', 1),
	(92, 90, 'You’re looking for a serverless way to trigger and send email notifications based on rules — no VM management, no infrastructure babysitting.\n\nCorrect recommendation\n	A Logic App\n\nWhy this is the right fit\n	Azure Logic Apps are fully serverless\n	They’re designed for workflow automation and rule-based actions\n	Built-in connectors make sending emails trivial (Office 365, SMTP, SendGrid, etc.)\n	Perfect for “when X happens, send an email” scenarios\n\nWhy the others don’t qualify\n	❌ Web app – requires app hosting and management\n	❌ Server image in Azure Marketplace – VM-based, not serverless\n	❌ API app – platform service, but not intended for rule-driven workflows like this', '2026-02-28 12:12:25', 1),
	(93, 91, 'You should recommend a content delivery network (CDN).\n\nWhy:\nA CDN caches and serves large video files from edge locations close to users around the world, which:\n	Reduces latency\n	Improves video streaming and playback performance\n	Offloads traffic from the origin website\n\nWhy not the others:\n	Application Gateway – load balancing and security, not global media delivery\n	Azure ExpressRoute – private connectivity, not for public worldwide users\n	Azure Traffic Manager – DNS-based routing, but it doesn’t cache or optimize video content', '2026-03-01 03:49:05', 1),
	(94, 92, 'The two Azure resources you should identify are:\n	Azure IoT Hub\n	Azure Data Lake\n\nWhy these two:\nAzure IoT Hub is purpose-built to handle millions of IoT devices securely and reliably. It supports device authentication, telemetry ingestion at massive scale, and bi-directional communication with sensors.\n\nAzure Data Lake is designed for storing and analyzing very large volumes of data, making it ideal for long-term storage and analytics of the telemetry data uploaded by those sensors.\n\nWhy not the others:\n	Azure Queue Storage – useful for decoupling application components, but not required for large-scale IoT ingestion\n	Azure File Storage – file shares, not optimized for IoT telemetry\n	Azure Notification Hubs – used for sending push notifications to apps, not ingesting sensor data', '2026-03-01 03:49:05', 1),
	(95, 93, 'The two Azure management tools you can use from an iPhone are:\n	The Azure portal\n	Azure Cloud Shell\n\nWhy these work:\n	Azure portal runs in a mobile browser (and via the Azure mobile app), so you can manage web app settings directly from your iPhone.\n	Azure Cloud Shell is browser-based and runs inside the Azure portal, giving you access to Azure CLI or PowerShell without installing anything on the phone.\n\nWhy not the others:\n	Azure CLI – requires local installation (not supported on iOS)\n	Windows PowerShell – Windows-only\n	Azure Storage Explorer – desktop application only\n\n✅ Correct answers: The Azure portal and Azure Cloud Shell', '2026-03-01 03:49:05', 1),
	(96, 94, 'The correct choice is Azure Machine Learning Studio.\n\nWhy:\n	Azure Machine Learning Studio is specifically designed to build, train, test, and deploy predictive analytics and machine learning models. \n	It provides tools for data preparation, model training, experimentation, and deployment as web services.\n\nWhy not the others:\n	Azure Logic Apps – workflow automation, not AI model development\n	Azure Batch – large-scale parallel compute jobs, not ML lifecycle management\n	Azure Cosmos DB – globally distributed database, not an AI platform', '2026-03-01 03:49:05', 1),
	(97, 95, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\n	Azure Cloud Shell (even when you select PowerShell) includes the Azure CLI (az) by default.\n	You can run az vm create ... commands from either Bash or PowerShell in Cloud Shell.\n	Cloud Shell automatically uses the currently selected subscription in the Azure portal (Subscription1), where RG1 already exists.\n\nSo running this command in Cloud Shell (PowerShell) will successfully create VM1 in Subscription1.', '2026-03-01 03:49:05', 1),
	(98, 96, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\nAzure PowerShell is supported on Windows 10.\nInstalling the Azure PowerShell module (Az) allows the administrator to authenticate to Azure and create/manage Azure resources using PowerShell scripts.\nAs long as the user signs in with appropriate permissions, the script will run successfully.', '2026-03-01 03:49:05', 1),
	(99, 97, 'The service that provides serverless computing in Azure is:\n✅ Azure Functions\n\nWhy:\nAzure Functions lets you run code without provisioning or managing servers. You only pay for the execution time, which is the core idea of serverless computing.\n\nWhy not the others:\n	Azure Virtual Machines – you manage the servers\n	Azure Storage account – storage service, not compute\n	Azure Container Instances – containers without VM management, but not serverless', '2026-03-01 03:49:05', 1),
	(100, 98, 'Yes. ✅\nThis does meet the goal.\n\nWhy:\n	Azure Cloud Shell (Bash) natively supports the Azure CLI (az).\n	The command you’re using is an Azure CLI command, so Bash is actually the most common environment for it.\n	Cloud Shell automatically authenticates you and uses the current subscription (Subscription1) selected in the Azure portal.\n\nThe resource group RG1 already exists, so the VM can be created successfully.', '2026-03-01 03:49:05', 1),
	(101, 99, 'You should recommend Azure Resource Manager (ARM) templates ✅\n\nWhy:\nARM templates let you define, deploy, and manage a consistent set of Azure resources as code. Since each business unit needs the same 20 resource types, you can create one template and reuse it to automatically deploy identical environments—fast, repeatable, and error-free.\n\nWhy not the others:\n	Virtual machine scale sets ❌ : Only for scaling VM instances, not for provisioning a full mix of Azure resources.\n	Azure API Management ❌ : Used to publish and manage APIs, not to automate infrastructure creation.\n	Management groups ❌ : Used for organizing subscriptions and applying governance, not deploying resources.', '2026-03-01 03:49:05', 1),
	(102, 100, 'The right choice is Azure Monitor ✅\n\nWhy:\nAzure Monitor is designed to collect, aggregate, and store telemetry (events, logs, metrics) from multiple Azure resources into a centralized repository. \nIt’s the go-to service for monitoring, diagnostics, and analysis across your environment.\n\nWhy not the others:\n	Azure Event Hubs ❌ : Great for high-throughput event ingestion, but it’s more of a streaming pipeline than a centralized monitoring repository.\n	Azure Analysis Services ❌ : Used for data modeling and analytics, not event collection.\n	Azure Stream Analytics ❌ : Processes and analyzes streaming data in real time; it doesn’t act as a central event store.', '2026-03-01 03:49:05', 1),
	(103, 101, 'Correct Answer is No.\n\nThe PowerApps (Power Apps) portal is for building and using business applications, not for managing Azure infrastructure. \nIt can’t be used to create Azure virtual machines.\n\nFrom an Android tablet, you could create a VM by using:\n	The Azure portal in a web browser, or\n	Azure management tools/APIs (not PowerApps)', '2026-03-01 04:16:34', 1),
	(104, 102, 'Correct answer is Yes.\n\nThe Azure portal is web-based and can be accessed from a browser on an Android tablet, allowing you to create and manage Azure virtual machines.', '2026-03-01 04:16:34', 1),
	(105, 103, 'The correct answer is: Azure Repos\n\nAzure Repos provides Git repositories and Team Foundation Version Control (TFVC), which are version control tools used to manage and track code changes.\n\nWhy the others don’t fit:\n	Azure DevTest Labs – Used for creating and managing development/test environments\n	Azure Storage – Stores blobs, files, queues, and tables\n	Azure Cosmos DB – A globally distributed database service', '2026-03-01 04:16:34', 1),
	(106, 104, 'The correct answer is: Azure Key Vault\n\nWhy:\n	Azure Key Vault securely stores and encrypts sensitive information such as administrative usernames, passwords, certificates, and secrets. \n	During automated deployments (ARM templates, Bicep, Terraform, pipelines), credentials can be retrieved securely from Key Vault without\n	exposing them in code or logs.\n\nWhy not the others:\n	Microsoft Purview Information Protection – Focuses on data classification and labeling\n	Microsoft Defender for Cloud – Provides security posture management and threat protection\n	Azure Multi-Factor Authentication (MFA) – Adds an extra sign-in verification step but does not encrypt credentials during deployment', '2026-03-01 04:16:34', 1),
	(107, 105, 'The correct answer is: Network Security Group (NSG)\n\nWhy:\nA Network Security Group (NSG) lets you control inbound and outbound network traffic to Azure virtual machines by \ndefining security rules that allow or deny traffic on specific ports, protocols, and source/destination IP addresses.\n\nWhy the others are incorrect:\n	Microsoft Entra ID role – Controls permissions to Azure resources, not network traffic\n	Microsoft Entra ID group – Used for identity and access management, not port control\n	Azure Key Vault – Stores secrets, keys, and certificates', '2026-03-01 04:16:34', 1),
	(108, 106, 'The correct answer is: This service has been discontinued. Azure Germany was retired in 2021\n\nExplanation:\nAzure Germany was a sovereign cloud offering with special data residency and access controls. \nMicrosoft officially retired Azure Germany in 2021, and customers were migrated to standard Azure regions in Germany \n(such as Germany West Central and Germany North).', '2026-03-01 04:16:34', 1),
	(109, 107, 'Corrected answer is Yes.\n\nModifying a Network Security Group (NSG) to allow inbound traffic on TCP port 80 (HTTP) from the Internet will make VM1 accessible over HTTP, assuming the NSG is associated with the VM’s network interface or subnet.', '2026-03-01 04:16:34', 1),
	(110, 108, 'Corrected answer is Yes.\n\nAn Azure Firewall can be configured with inbound rules to allow HTTP (TCP port 80) traffic from the Internet to VM1. If the firewall is properly deployed (with a public IP and routing set up), modifying it to allow HTTP access meets the goal.', '2026-03-01 04:16:34', 1),
	(111, 109, 'Corrected answer is No.\n\nAzure Traffic Manager is a DNS-based load-balancing service. It controls how clients are directed to endpoints, \nbut it does not open ports or allow network traffic to a virtual machine.\n\nTo make VM1 accessible over HTTP, you must allow inbound TCP port 80 using a Network Security Group or a firewall, not Traffic Manager.', '2026-03-01 04:16:34', 1),
	(112, 110, 'The correct answers are:\n	✅ A United States government entity\n	✅ A United States government contractor\n\nWhy:\nAzure Government is a separate cloud environment designed specifically for U.S. government agencies and their partners/contractors who \nhandle sensitive government data. It is not available to foreign governments or contractors outside the U.S.\n\nWhy the others are incorrect:\n	Canadian or European entities/contractors are not eligible for Azure Government; they would use the standard Azure regions in their countries or regions.', '2026-03-01 04:16:34', 1),
	(113, 111, 'The correct answer is: ✅ Microsoft Entra ID Protection\n\nExplanation:\n\nMicrosoft Entra ID Protection provides:\n	Risk-based Conditional Access policies\n	Detection of risky sign-ins (including anonymous IP addresses such as Tor networks)\n	Automatic remediation actions (like requiring password change)\n\nYou can configure a User Risk Policy in Entra ID Protection to:\n	Detect high-risk sign-ins\n	Require users to change their password automatically\n\nWhy the others are incorrect:\n	Microsoft Entra Connect Health : Monitors the health of identity infrastructure (e.g., AD FS, sync services). Not for risk-based sign-ins.\n	Microsoft Entra Privileged Identity Management (PIM) : Manages and controls privileged role access. Not related to risky sign-ins.\n	Microsoft Defender for Identity : Focuses on detecting on-premises Active Directory threats, not enforcing password changes based on anonymous IP sign-ins.', '2026-03-04 17:17:10', 1),
	(114, 112, 'The correct answer is: ✅ Network Security Groups (NSGs)\n\nExplanation:\nNetwork Security Groups (NSGs) allow you to: Define inbound and outbound security rules\nAllow or deny traffic based on:\n	Source and destination IP\n	Port numbers\n	Protocol (TCP/UDP)\nApply rules to:\n	Subnets\n	Individual network interfaces (NICs)\n\nYou can configure an NSG to:\n	Allow web servers to connect to database servers on specific ports only\n	Deny all other traffic\n\nWhy the other options are incorrect:\n❌ Azure Service Bus : Used for messaging between applications — not for network traffic filtering.\n❌ A local network gateway : Used for VPN connections between on-premises and Azure — not for controlling internal Azure VM traffic.\n❌ A route filter : Used with ExpressRoute to filter BGP route advertisements — not for traffic type control.', '2026-03-04 17:17:10', 1),
	(115, 113, 'The correct answer is: ✅ Microsoft Entra ID\n\nExplanation:\nApplications retrieve security tokens (such as OAuth 2.0 access tokens or ID tokens) from an identity provider.\nMicrosoft Entra ID (formerly Azure AD):\n	Authenticates users and applications\n	Issues security tokens\n	Supports OAuth 2.0 and OpenID Connect\n	Provides access tokens for APIs and services\nWhen an application needs a token, it sends an authentication request to Microsoft Entra ID, which then issues the appropriate token.\n\nWhy the other options are incorrect:\n❌ Azure Storage account : Used to store data (blobs, files, tables), not issue tokens.\n❌ A certificate store : Stores certificates for authentication, but does not generate security tokens.\n❌ Azure Key Vault : Stores secrets, keys, and certificates securely — it does not act as a token issuer.', '2026-03-04 17:17:10', 1),
	(116, 114, 'The correct answer is: ✅ Azure Firewall\n\nMicrosoft Azure Firewall provides centralized network traffic filtering across:\n	Multiple Azure subscriptions\n	Multiple virtual networks (VNets)\n	Even across regions (when configured properly)\n\nIt is a managed, cloud-based network security service that supports:\n	Application and network-level filtering\n	Centralized logging and monitoring\n	Integration with Azure Hub-and-Spoke architectures\n\nWhy the others are incorrect:\n	Application Security Group (ASG)\n		Used to logically group VMs for NSG rule definition — it does not filter traffic across subscriptions.\n	Azure DDoS Protection\n		Protects against distributed denial-of-service attacks but does not perform general traffic filtering.\n	Network Security Group (NSG)\n		Filters traffic at the subnet or NIC level within a VNet, but it is not designed for centralized filtering across multiple subscriptions and VNets.', '2026-03-04 17:17:10', 1),
	(117, 115, 'The correct answer is: Azure Key Vault\n\nMicrosoft Azure Key Vault is specifically designed to securely store and manage sensitive information such as:\n	Certificates\n	Secrets\n	Encryption keys\n	Connection strings\nIt provides secure access control, centralized management, and integration with other Azure services.\n\nThe other options are not designed for certificate storage:\n	Microsoft Defender for Cloud – Security posture management and threat protection\n	Azure Storage account – General-purpose data storage\n	Microsoft Purview Information Protection – Data classification and protection', '2026-03-04 17:17:10', 1),
	(118, 116, 'The correct answer is: An Azure policy.\n\nAzure Policy allows you to define rules that enforce specific conditions on resources in your subscription. \nTo prevent the creation of virtual machines (VMs) in a specific resource group (like RG1), \nyou can create a policy that restricts the deployment of VMs in that resource group.\n\n\nA lock: This is used to prevent accidental deletion or modification of resources, but it doesn\'t restrict the creation of specific resource types like VMs.\nAn Azure role: While roles define permissions for users or groups, they don\'t specifically control resource creation restrictions.\nRoles can allow or deny access to create resources, but you would typically use a policy for more fine-grained control.\n\nA tag: Tags are used for resource organization and cost management, but they don\'t enforce any restrictions on resource creation.', '2026-03-04 17:17:10', 1),
	(119, 117, 'The correct answer is: Documents and email messages.\n\nMicrosoft Purview Information Protection (formerly Azure Information Protection) is designed to:\n	Classify data\n	Label data\n	Encrypt and protect documents and emails\nIt works with files (like Word, Excel, PDF) and email messages to ensure only authorized users can access them.\n\nThe other options are incorrect because:\n	Network traffic – Protected using TLS/SSL, not Purview Information Protection.\n	An Azure Storage account – Secured using Azure Storage encryption and keys.\n	An Azure SQL database – Uses features like Transparent Data Encryption (TDE).', '2026-03-04 17:17:10', 1),
	(120, 118, 'The correct answer is: Azure Activity Log\n\nMicrosoft Azure Activity Log records subscription-level events, including:\n	Who performed an action\n	What action was performed\n	When the action occurred\n	The status of the action\n\nThe other options are incorrect:\n	No change is needed – Not applicable.\n	Azure Event Hubs – Used for streaming large amounts of telemetry data.\n	Azure Service Health – Provides information about Azure service outages and issues, not user actions.', '2026-03-04 17:17:10', 1),
	(121, 119, 'The correct answer is: An Azure policy.\n\nAzure Policy allows you to enforce rules and guidelines across your Azure environment. \nIn this scenario, you can create an Azure Policy that restricts the creation of resources to specific regions \nbased on the location of the administrator\'s office.\n\nFor example, you can define a policy that restricts the allowed locations (regions) for resource creation. This would ensure that administrators can only create resources in the regions that align with the company\'s policy.\n\nHere\'s why the other options aren\'t suitable:\n	A read-only lock: This prevents any modifications to the resources but doesn\'t restrict the creation of new resources.\n	A management group: Management groups are used for organizing resources, but they don’t enforce specific region-based policies.\n	A reservation: This is used for reserving resources like virtual machines or SQL databases, not for controlling the regions where resources can be created.', '2026-03-04 17:17:10', 1),
	(122, 120, 'The correct answer is: Compliance Manager\n\nMicrosoft Compliance Manager (part of Microsoft Purview) helps organizations track and manage regulatory compliance requirements such as:\n	ISO 27001\n	GDPR\n	NIST\n	HIPAA\nIt provides assessments, compliance scores, and recommended improvement actions.\n\nThe other options are incorrect:\n	No change is needed – Azure Cloud Shell is a command-line tool, not a compliance tracking solution.\n	Microsoft Cloud Partner Portal – Used by partners for business management.\n	Trust Center – Provides information about Microsoft’s compliance offerings but does not track your organization’s compliance status.', '2026-03-04 17:17:10', 1),
	(123, 121, 'The correct answer is: DDoS protection.\n\nProtects web applications from Distributed Denial of Service (DDoS) attacks.\nProvides attack analytics, telemetry, and reports detailing attempted attacks.\nIntegrates with Azure Monitor for visibility and alerting.\nSpecifically designed to protect public-facing endpoints such as websites.\n\nWhy the others are incorrect:\n\nAzure Firewall\nProvides network traffic filtering and threat intelligence but is not specifically focused on website DDoS attack protection and reporting in the same way.\n\nNetwork Security Group (NSG)\nFilters traffic based on rules (IP, port, protocol) but does not generate attack reports or provide advanced attack analytics.\n\nMicrosoft Purview Information Protection\nFocuses on data classification and protection — unrelated to securing websites from attacks.', '2026-03-04 17:22:13', 1),
	(124, 122, 'The correct answer is: ✅ Create a new support request\n\nExplanation\nWhen you hit a resource or subscription quota limit in Microsoft Azure (such as the number of managed SQL instances), you must request a quota increase.\n\nYou do this by:\n	Going to Help + Support in the Azure portal\n	Selecting New support request\n	Choosing Service and subscription limits (quotas)\n	Submitting the requested increase\n\nWhy the other options are incorrect\n	Create a service health alert\n	This monitors Azure service issues. It does not change subscription limits.\n\n	Upgrade your support plan\n	A higher support plan gives faster response times but does not automatically increase quotas.\n\n	Modify an Azure policy\n	Azure Policy enforces governance rules, not subscription quota limits.', '2026-03-04 17:22:13', 1),
	(125, 123, 'The correct answer is: ✅ Tags\n\nExplanation\n\nTags allow you to:\n	Assign metadata (such as Office=NewYork, Office=London, etc.) to resources\n	Group resources across subscriptions and resource groups\n	Filter billing and cost reports by tag\n	Track usage and costs by department, location, or business unit\n	In Cost Management + Billing, you can generate reports filtered by tag to see utilization per office.\n\nWhy the other options are incorrect\nTemplates\nARM templates are used to deploy resources, not organize them for billing reports.\n\nLocks\nPrevent accidental deletion or modification of resources. They do not affect reporting.\n\nPolicies\nEnforce governance rules (e.g., allowed regions or SKUs), but do not organize resources for billing breakdown.', '2026-03-04 17:22:13', 1),
	(126, 124, 'The two correct answers are: ✅ Multiple subscriptions, ✅ Multiple resource groups\n\n✅ Multiple Subscriptions\n	Creating a separate subscription per department:\n	Provides strong isolation of resources\n	Separates billing per department\n	Allows independent quota limits\n	Enables delegated administration at the subscription level\n	This is commonly used for organizational segmentation.\n\n✅ Multiple Resource Groups\n	Within a single subscription, you can:\n	Create a resource group per department\n	Assign role-based access control (RBAC) at the resource group level\n	Allow each department admin to manage only their own resources\n	This provides logical separation without requiring multiple subscriptions.\n\nWhy the other options are incorrect\n\nMultiple Microsoft Entra ID directories\n	Microsoft Entra ID directories are for identity and authentication boundaries.\n	Creating separate directories is complex and unnecessary for departmental segmentation.\n\nMultiple regions\n	Regions are geographic locations (e.g., East US, West Europe). They are used for latency, compliance, or redundancy — not for organizational segmentation.', '2026-03-04 17:22:13', 1),
	(127, 125, 'The correct answer is: ✅ Professional Direct, Standard, Developer, and Basic\n\nIn Microsoft Azure, the ability to create technical support requests depends on your support plan.\nYou can open technical support requests with the following plans:\n	Basic\n	Developer\n	Standard\n	Professional Direct\nAll four plans allow you to submit support requests through the Azure portal (response times and severity levels differ by plan).', '2026-03-04 17:22:13', 1),
	(128, 126, 'The correct answer is: ✅ Uptime\n\nExplanation\nIn Microsoft Azure, a Service Level Agreement (SLA) defines the guaranteed level of service availability.\nFor Virtual Machines, the SLA guarantees:\nA percentage of uptime (for example, 99.9%, 99.95%, or higher depending on configuration)\n\nFinancial credits if the uptime guarantee is not met\n\nIt does not guarantee:\n	Specific performance levels\n	Specific bandwidth throughput\n	That certain features will always be available\n\nThe SLA strictly guarantees availability (uptime).', '2026-03-04 17:22:13', 1),
	(129, 127, 'In Microsoft Azure, the Basic support plan:\n	Provides access to documentation, whitepapers, and community forums\n	Allows support for billing and subscription issues only\n	Does NOT provide technical support by phone or email\n	The requirement states that the company must be able to access support engineers by phone or email.\n\nTo meet that requirement, the company would need at least:\n	Developer\n	Standard\n	Professional Direct\n\nThese plans provide technical support access', '2026-03-04 17:22:13', 1),
	(130, 128, 'The correct answer is: ✅ Standard\n\nYour company needs:\n	An architectural review\n	Direct access to Microsoft support engineers\n	The lowest possible cost\n\nIn Microsoft Azure support plans:\n\nDeveloper\n	Intended for development and testing environments. It does not include architectural guidance or proactive services.\n\nStandard\n	Technical support\n	Architectural guidance\n	Faster response times than Developer\n	This is the lowest-cost plan that supports production workloads and architecture discussions.\n\nProfessional Direct\n	Includes proactive services and advisory support, but is significantly more expensive than Standard.\n\nSince the requirement is to minimize costs while enabling an architectural review, Standard is the correct choice.', '2026-03-04 17:22:13', 1),
	(131, 129, 'The correct answer is: ✅ A pay-as-you-go subscription\n\nAzure Cost Management is available to Azure customers to monitor, analyze, and optimize their cloud spending.\nTo use Azure Cost Management, you must have an active Azure subscription — such as:\n	Pay-as-you-go\n	Enterprise Agreement (EA)\n	Microsoft Customer Agreement (MCA)\n\nOther standard Azure subscription types\nA Pay-as-you-go subscription is sufficient and does not require:\n	❌ Software Assurance\n	❌ An Enterprise Agreement (EA) specifically\n	❌ A Dev/Test subscription\n\nWhy the others are incorrect\n	Dev/Test subscription – Not required.\n	Software Assurance – Related to on-premises licensing benefits.\n	Enterprise Agreement (EA) – Supported, but not required.', '2026-03-04 17:22:13', 1),
	(132, 130, 'The correct answer is: ✅ Start an existing Azure virtual machine.\n\nExplanation\n\nWhen an Azure free trial subscription expires:\n	Resource creation and management are blocked\n	You cannot create new resources (VMs, storage accounts, users in Microsoft Entra ID, etc.).\n	Existing running resources are stopped\n	Azure stops any running virtual machines.\n	You cannot restart or start them until the subscription is upgraded to a paid plan.\n\nAccess to the Azure portal\n	You can still log in to the portal to view your subscription and existing resources.\n\nAccess to stored data\n	Azure retains your data for a short grace period, so you can still download or retrieve it.\n\nWhy the other options are incorrect\n	No change is needed – Incorrect; trial expiration restricts most operations.\n	Access your data stored in Azure – Partially possible; some data can still be accessed or downloaded.\n	Access the Azure portal – Still allowed; logging in is not blocked', '2026-03-04 17:22:13', 1),
	(133, 131, 'Answer: No.\n\nRecommending a Premier support plan does not meet the goal in this scenario.\nIn Microsoft Azure, the requirement is simply that the support plan must provide access to support engineers by phone or email.\nThe Premier support plan (now part of Microsoft Unified Support) is an enterprise-level support offering and \nis not required to meet this basic requirement. \n\nA lower-tier plan such as Professional Direct or Standard already provides:\n	Access to support engineers\n	Phone and email support\n\nBecause Premier is more advanced (and more expensive) than necessary, it does not correctly meet the goal of selecting the appropriate plan based on the stated requirement.', '2026-03-04 17:23:28', 1),
	(134, 132, 'Correct answer: A subscription.\n\nIn Microsoft Azure, billing and payment methods are managed at the subscription level.\nIf each of the 10 departments must use a different payment option, you need to create:\n	✅ One Azure subscription per department\n\nWhy not the others?\n	Reservation – Used to reserve Azure resources at discounted rates. It does not control payment methods.\n	Resource group – Organizes resources within a subscription but shares the same billing account.\n	Container instance – A compute service (Azure Container Instances), unrelated to billing structure.', '2026-03-04 17:23:28', 1),
	(135, 133, 'Correct answer:\n✅ Microsoft provides a minimum of 12 months notice before ending support for a service.\n\nUnder the Modern Lifecycle Policy for Microsoft Azure services:\n	There is no fixed support term (unlike the traditional 5-year mainstream + 5-year extended model).\n	Services are supported as long as they are in market and supported.\n	Microsoft provides at least 12 months’ notice before retiring a service (in most cases).\n\nWhy the other options are incorrect:\n	❌ Five years of mainstream support → That applies to the Fixed Lifecycle Policy, not the Modern Lifecycle Policy.\n	❌ Minimum four years of support after GA → Azure services do not have a guaranteed fixed support duration.\n	❌ Extended support for up to five years after retirement → Azure services do not offer extended paid support after retirement.', '2026-03-04 17:23:28', 1),
	(136, 134, 'Correct answer: Budget alerts.\n\nIn Microsoft Azure, Azure Advisor provides recommendations for cost optimization, security, reliability, operational excellence, and performance — but it does not send alerts based on spending thresholds.\n\nTo send email alerts when the cost of a subscription exceeds a specified limit, you must use:\n✅ Budget alerts (under Azure Cost Management)\n\nWhy the others are incorrect:\n	❌ No change is needed – Incorrect because Azure Advisor does not generate cost threshold alerts.\n	❌ Access control (IAM) – Used for managing permissions, not cost monitoring.\n	❌ Compliance – Related to regulatory standards and policies, not spending alerts.', '2026-03-04 17:23:28', 1),
	(137, 135, 'Correct answer: No.\n\nA hybrid cloud is a combination of:\n	A public cloud (such as Microsoft Azure), and\n	Either an on-premises datacenter or a private cloud.\n\nA company does not need to first build a private cloud to implement a hybrid cloud model. An on-premises environment connected to a public cloud already qualifies as hybrid cloud.', '2026-03-04 17:23:28', 1),
	(138, 136, 'Correct answer: Yes.\n\nA hybrid cloud allows a company to connect its on-premises infrastructure (internal network) with a public cloud such as Microsoft Azure.\n\nThis enables the company to:\n	Extend compute resources\n	Expand storage capacity\n	Handle peak loads (cloud bursting)\n	Increase flexibility without fully migrating to the cloud\n\nTherefore, a company can extend the computing resources of its internal network by using a hybrid cloud.', '2026-03-04 17:23:28', 1),
	(139, 137, 'Correct answer: No.\n\nIn a public cloud model, cloud resources are owned and operated by a third-party provider (such as Amazon Web Services, Microsoft Azure, or Google Cloud) and delivered over the internet.\n\nAccess is not limited to “guest users” at one specific company. Instead:\n	Multiple organizations and users can access the services.\n	Each customer’s data and resources are logically isolated.\n	Access is controlled through authentication and permissions.', '2026-03-04 17:23:28', 1),
	(140, 138, 'Correct answer: Fault tolerance.\n\nIn Microsoft Azure, to ensure that servers remain available even if a single data center goes offline for an extended period, you must design for fault tolerance.\n\nFault tolerance is achieved by distributing resources across:\n	Availability Zones (separate datacenters within a region), or\n	Multiple regions\n\nThis ensures that if one datacenter fails, others continue operating.\n\nWhy the other options are incorrect:\n	Elasticity – Automatically adds/removes resources based on demand.\n	Scalability – Increases or decreases resource capacity.\n	Low latency – Minimizes network delay.\n	None of these guarantee availability during a datacenter outage', '2026-03-04 17:23:28', 1),
	(141, 139, 'Correct answer: In the public cloud.\n\nIf an organization hosts its infrastructure in a private cloud, it typically still operates its own datacenter (on-premises or hosted).\n\nOnly when infrastructure is hosted in the public cloud — such as in Microsoft Azure — can the organization potentially close its own datacenter because the cloud provider manages the physical infrastructure.\n\nWhy the other options are incorrect:\n	No change is needed – A private cloud usually still requires a datacenter.\n	In a hybrid cloud – Hybrid means part on-premises, so a datacenter is still needed.\n	On a Hyper-V host – This is still on-premises infrastructure.', '2026-03-04 17:23:28', 1),
	(142, 140, 'The two correct characteristics of the public cloud are:\n	✅ Metered pricing\n	✅ Self-service management\n\nPublic cloud platforms such as Microsoft Azure provide:\n	Metered pricing – You pay only for the resources you use (pay-as-you-go model).\n	Self-service management – Users can provision and manage resources on demand without needing provider intervention.\n\nWhy the other options are incorrect:\n	❌ Dedicated hardware – Public cloud resources are typically shared across multiple customers (multi-tenant).\n	❌ Unsecured connections – Public clouds provide secure connectivity options.\n	❌ Limited storage – Public clouds offer virtually unlimited scalability.', '2026-03-04 17:23:28', 1),
	(143, 141, 'Answer: ❌ No.\n\nThe migration plan clearly states that only Platform as a Service (PaaS) solutions must be used in Azure.\n\nAzure App Service is a PaaS offering ✅\nAzure Virtual Machines are Infrastructure as a Service (IaaS) ❌\nEven though Microsoft SQL Server is installed on the virtual machines, the use of Azure Virtual Machines makes the solution IaaS-based, not purely PaaS.\n\nTo meet the requirement, you should use a PaaS database service such as:\n	Azure SQL Database\n	Azure SQL Managed Instance', '2026-03-11 12:26:09', 1),
	(144, 142, 'Correct answer: ✅ Elasticity\n\nThe application has:\n	Low usage for most of the month\n	Very high usage during the last week\n\nElasticity in Microsoft Azure allows you to:\n	Automatically scale out (add resources) during high demand\n	Automatically scale in (remove resources) during low demand\n	Pay only for the resources you use\n	This directly supports cost management because you avoid paying for peak-level resources all month long.\n\nWhy not the others?\n	High availability → Ensures uptime, not cost optimization.\n	High latency → Not a benefit; high latency is undesirable.\n	Load balancing → Distributes traffic but does not automatically reduce costs based on demand patterns.', '2026-03-11 12:26:09', 1),
	(145, 143, 'Answer: ❌ No\n\nDeploying the virtual machines to two or more Virtual Machine Scale Sets does not automatically ensure availability if a single data center fails.\n\nTo protect against a single datacenter failure, you must deploy VMs across Availability Zones within an Azure region. \nAvailability Zones place resources in physically separate datacenters.\n\nA scale set by itself:\n	Helps with scaling and load distribution\n	Does not guarantee placement across separate datacenters unless explicitly configured to use Availability Zones\n\nTo meet the goal, you should:\n	Deploy VMs in Availability Zones, or\n	Use a scale set configured for zone redundancy', '2026-03-11 12:26:09', 1),
	(146, 144, 'Correct answer: ✅ An Azure virtual machine\n\nInfrastructure as a Service (IaaS) provides:\n	Virtualized computing resources\n	Virtual machines\n	Storage\n	Networking\n\nYou manage the OS and installed software\n\nAn Azure virtual machine is IaaS because you:\n	Control the operating system\n	Install and manage applications\n	Handle patches and configurations\n\nWhy not the others?\n	Azure Web App → Platform as a Service (PaaS)\n	Azure Logic App → Platform as a Service (PaaS)\n	Azure SQL Database → Platform as a Service (PaaS)', '2026-03-11 12:26:09', 1),
	(147, 145, 'Correct Answer: ✅ Azure DevTest Labs\n\nThe scenario requires:\n	Deploying 50 customized VMs each week\n	Removing them regularly\n	Minimizing administrative effort\n	Supporting both Windows Server 2016 and Ubuntu Linux\n\nAzure DevTest Labs is designed specifically for:\n	Rapid VM provisioning and deletion\n	Managing dev/test environments\n	Using reusable VM templates and custom images\n	Automating shutdown and cleanup policies\nThis significantly reduces administrative overhead for environments that are frequently created and deleted.\n\nWhy not the others?\n	Azure Reserved VM Instances → Saves cost for long-term workloads, not for frequently created/deleted VMs.\n	Azure Virtual Machine Scale Sets → Good for scaling identical VMs, but not ideal for repeatedly provisioning and removing customized dev/test machines.\n	Microsoft Managed Desktop → A desktop management service, not used for provisioning custom server VMs.', '2026-03-11 12:26:09', 1),
	(148, 146, 'Correct Answer: ✅ No change is needed.\n\nThe statement is correct as written.\n\nHigh availability is built into Azure Synapse Analytics. The platform is designed with built-in fault tolerance and \nredundancy to ensure workloads remain available without requiring you to manage the underlying infrastructure.\n\nThe other options are not the best replacement:\n	Automatic scaling → While scaling features exist, this is not the primary built-in benefit being referenced here.\n	Data compression → A feature, but not the key built-in platform benefit.\n	Versioning → Not a core built-in availability benefit.', '2026-03-11 12:26:09', 1),
	(149, 147, 'Explanation:\n\ncorrect answer is\n	Provide operating system virtualization: Azure virtual machines. Provide portable environment for virtualized applications: Azure Container Instances. Used to build, deploy, and scale web apps: Azure App Service. Provide a platform for serverless code: Azure Functions.', '2026-03-11 12:26:09', 1),
	(150, 148, 'Answer: ✅ Yes\n\nPowerShell Core 6.0 (now known as PowerShell 7+) is cross-platform, meaning it runs on:\n	Windows\n	macOS\n	Linux\n\nWith PowerShell Core installed on macOS, the administrator can:\n	Install the Azure PowerShell module (Az module)\n	Authenticate to Azure\n	Create and manage Azure resources\nThere is no requirement that Azure PowerShell must run on Windows.', '2026-03-11 12:26:09', 1),
	(151, 149, 'Correct Answer: ✅ One Azure firewall\n\nYou need to limit inbound traffic across all 10 virtual networks.\n\nAzure Firewall is a centralized, managed network security service that:\n	Filters inbound and outbound traffic\n	Applies rules across multiple virtual networks\n	Provides centralized traffic control\n	Scales automatically\n\nBy deploying one Azure Firewall and routing traffic through it (using hub-and-spoke architecture), \nyou can control inbound access to all VNets from a single point.\n\nWhy not the others?\n	Application Security Group (ASG) → Used to group VMs for NSG rule application, not for controlling traffic across multiple VNets globally.\n	Virtual network gateways → Used for VPN/ExpressRoute connectivity, not for filtering general inbound internet traffic.\n	Azure ExpressRoute circuits → Provide private connectivity to Azure, not inbound traffic filtering.', '2026-03-11 12:26:09', 1),
	(152, 150, 'Correct Answer: ✅ A logic app\n\nYou need a serverless computing solution that:\n	Runs based on a trigger (a rule)\n	Sends email notifications automatically\n	Requires minimal infrastructure management\n\nAzure Logic Apps is a serverless service that:\n	Uses triggers and actions (for example: “When condition X happens → Send email”)\n	Integrates easily with email providers (Office 365, Outlook, Gmail, SMTP, etc.)\n	Requires no server management\n	Automatically scales\nThis makes it ideal for workflow-based automation like email notifications.\n\nWhy not the others?\n	Web app → PaaS, but not serverless workflow automation.\n	Server image in Azure Marketplace → IaaS (requires VM management).\n	API app → PaaS for hosting APIs, not workflow automation.', '2026-03-11 12:26:09', 1),
	(153, 151, 'Correct answer: a) No change is needed.\n\nThe composite SLA is correctly calculated by multiplying the two SLAs:\n	99.95% × 99.99% = 99.94%\nSince the composite SLA shown (99.94%) is accurate, the statement does not require any correction. Therefore, no change is needed.', '2026-03-11 12:26:50', 1),
	(154, 152, 'correct answer is Yes.\n \nInstalling the Azure CLI on a Windows 10 computer, signing in to your Azure subscription (Subscription1) using az login, and then running:\n	az vm create --resource-group RG1 --name VM1 --image UbuntuLTS --generate-ssh-keys', '2026-03-11 12:26:50', 1),
	(155, 153, 'Answer: Yes.\n\nAzure CLI installation: Installing the Azure CLI on a Windows 10 computer is correct and necessary for running the az commands.\n\nSign in to Azure: You can sign in using the az login command from any command prompt (including Command Prompt, PowerShell, or a terminal). This will allow you to authenticate to Azure and access your Subscription1.\n\nRun the command: After logging in, running the command:\n	az vm create --resource-group RG1 --name VM1 --image UbuntuLTS --generate-ssh-keys\nwill successfully create VM1 in RG1 within Subscription1.\n\nSince the solution specifies using a command prompt (instead of PowerShell), it\'s still valid, and there is no issue with using Command Prompt', '2026-03-11 12:26:50', 1),
	(156, 154, 'Answer: No.\n\nAzure Cloud Shell is a browser-based shell that allows you to manage your Azure resources. \nWhile you can use it from any device with a browser, it doesn\'t natively support PowerShell from an Android device \nunless you are accessing it through the browser-based Azure Cloud Shell (accessible via your browser, not a native Android app).\n\nIf you\'re trying to use PowerShell specifically on an Android device, you would encounter limitations since \nPowerShell isn\'t directly supported on Android natively. The correct solution would be to access the \nAzure Cloud Shell from a browser, which provides both PowerShell and Azure CLI functionality.\n\nSo, while using Azure Cloud Shell from a browser is possible, using PowerShell directly on an Android device isn\'t supported. \nThe solution would need to be more specific about using a browser or the Cloud Shell interface.', '2026-03-11 12:26:50', 1),
	(157, 155, 'The correct answer is: No change is needed.\n\nAzure Databricks is indeed an Apache Spark–based analytics service designed for big data processing and machine learning.\n\nThe other options are incorrect because:\n	Azure Data Factory is a data integration and orchestration service.\n	Azure DevOps is a development lifecycle and CI/CD platform.\n	Azure HDInsight is a managed big data service that supports Spark, Hadoop, and other frameworks — but the original statement specifically describes Azure Databricks.', '2026-03-11 12:26:50', 1),
	(158, 156, 'The correct answer is: Disaster recovery.\n\nAzure Site Recovery (ASR) is primarily a disaster recovery solution. It enables the replication of virtual machines (VMs) \nto a secondary region, allowing for failover in case of a disaster, ensuring business continuity.\n\n\n\nThe other options are incorrect:\n	Fault tolerance:  is a broader term referring to the ability of a system to continue operating properly in the event of a failure, \n	but Azure Site Recovery specifically targets disaster recovery.\n	\n	Elasticity: refers to the ability of a system to scale resources up or down automatically based on demand.\n\n	High availability: refers to ensuring that services are always operational and available, \n	but ASR specifically addresses recovery after a disaster, not just keeping the system online.', '2026-03-11 12:26:50', 1),
	(159, 157, 'The correct answer is:\n\nWithin a single Azure region.\n\nAn Availability Zone in Azure refers to a physically separate location within a single Azure region. Each zone has its own power, cooling, and networking to ensure high availability and fault tolerance. It does not span across multiple regions or continents.\n\nHere’s a breakdown of the other options:\n	Across two continents: This is incorrect. Azure Availability Zones are designed to provide high availability within a single region, not across continents.\n	Within multiple Azure regions: This is incorrect. Multiple regions would refer to Geo-replication or other multi-region services, not Availability Zones.\n	Within a single Azure datacenter: This is also incorrect. Availability Zones are designed to span multiple datacenters within a region to increase resiliency.', '2026-03-11 12:26:50', 1),
	(160, 158, 'The correct answer is: The Trust Center.\n\nYou should use the Microsoft Trust Center.\nThe Trust Center provides detailed information about:\n	Compliance certifications (ISO, SOC, GDPR, etc.)\n	Regulatory compliance by region\n	Data residency and data protection details\n	Security and privacy practices\n\nThis is exactly what you need to determine whether Azure meets your company’s regional and regulatory requirements.\n\nThe other options are incorrect:\n\nKnowledge Center – General documentation and troubleshooting resources.\n\nAzure Marketplace – Used to find and deploy third-party solutions.\n\nMy Apps – Used by users to access assigned applications.', '2026-03-11 12:26:50', 1),
	(161, 159, 'The correct answer is: Server applications.\n\nAzure Key Vault is used to safely store secrets, keys, and certificates for applications and services, \nsuch as connection strings, API keys, or encryption keys. It is not designed to store user credentials like Microsoft Entra ID accounts or PII directly.\n\nMicrosoft Entra ID user accounts / administrative accounts – These are managed by Azure AD and not stored in Key Vault.\n\nPersonally Identifiable Information (PII) – Key Vault is not meant to store sensitive personal data directly; \nit\'s for cryptographic keys and secrets used by applications.', '2026-03-11 12:26:50', 1),
	(162, 160, 'The correct answer is: No change is needed.\n\nA Network Security Group (NSG) controls inbound and outbound traffic to Azure resources. \nTo allow connections to TCP port 8080 on a virtual machine, you modify the NSG associated with the VM’s network interface \nor subnet and add an inbound security rule for port 8080.\n\nThe other options are incorrect:\nVirtual network gateway – Used for VPN or ExpressRoute connections, not for controlling VM ports.\nVirtual network – Provides network connectivity but does not manage port-level access.\nRoute table – Controls traffic routing, not access rules.', '2026-03-11 12:26:50', 1),
	(163, 161, 'Correct answer: ✅ Yes\n\nExplanation\n\nHere\'s how Network Security Groups (NSGs) help achieve this:\n	NSGs are used to define security rules that control inbound and outbound traffic to and from resources like Virtual Machines.\n	You would create an inbound rule in the NSG to allow traffic on port 80 (the standard HTTP port) to reach VM1 from the internet.\n\nSteps to achieve the goal:\n	Ensure that VM1 has a public IP address (either directly or via a load balancer).\n	Modify the NSG to allow inbound traffic on port 80 (HTTP).\n	Ensure there are no other security rules that block the traffic.', '2026-03-12 02:58:57', 1),
	(164, 162, 'Correct answer: ❌ No\n\nExplanation:\nA DDoS Protection Plan is designed to protect Azure resources from Distributed Denial of Service (DDoS) attacks, but it does not directly manage the accessibility of a virtual machine (VM) over HTTP.\n\nTo make VM1 accessible over HTTP, you need to:\n	Assign a public IP address to the VM (or a load balancer).\n	Configure a Network Security Group (NSG) to allow inbound traffic on port 80 (HTTP).\n	Ensure that VM1 is properly configured to accept HTTP traffic.\nDDoS protection enhances security by mitigating large-scale attacks, but it does not configure network access for services like HTTP.', '2026-03-12 02:58:57', 1),
	(165, 163, 'Correct answer: ✅ Management groups\n\nExplanation\nThe question asks about managing compliance of Azure resources across multiple subscriptions. The best solution for this is Management Groups.\n\nManagement Groups are used to organize subscriptions into a hierarchy, allowing for easier governance, policy enforcement, and compliance management across multiple subscriptions.\n\nYou can apply Azure policies at the management group level, which then affect all the subscriptions under that management group, helping with compliance management.\n\nWhy not the other options?\n	Resource groups: Organize resources within a subscription, but do not span across multiple subscriptions.\n	Azure policies: Can enforce compliance, but they are typically applied at the resource group, subscription, or management group level.\n	Azure App Service plans: Related to hosting web apps, not for managing resources or compliance.', '2026-03-12 02:58:57', 1),
	(166, 164, 'Correct answer: ✅ Sync all the Active Directory user accounts to Microsoft Entra ID\n\nExplanation\n\nThis approach achieves the following:\n	Seamless access to Azure resources: Users will be able to use their existing credentials to access Azure services after migration.\n	\n	Hybrid Identity: Syncing Active Directory (AD) accounts to Microsoft Entra ID enables a hybrid identity model, allowing users to authenticate to both on-premises and cloud resources.\n	\n	It avoids disrupting users’ daily operations, as they will not have to change passwords or deal with the complexities of creating guest accounts or setting up additional authentication methods.\n\nWhy not the other options?\n	Implement Azure Multi-Factor Authentication (MFA): While MFA is a good security practice, it’s not a solution to minimize the impact of migration. Users will still need to authenticate in a way that allows access to both on-premises and Azure resources.\n\n	Instruct all users to change their password: Requiring users to change passwords can cause significant disruption, especially during a migration. This is not the best approach to minimize impact.\n\n	Create a guest user account in Microsoft Entra ID for each user: This approach is unnecessary and would create additional complexity. Users would need to manage multiple accounts, and it would not help streamline the migration process.', '2026-03-12 02:58:57', 1),
	(167, 165, 'Correct answer: ✅ Compliance Manager from the Service Trust Portal\n\nExplanation\n\nCompliance Manager is a tool available through the Service Trust Portal that allows organizations to evaluate and manage compliance with regulatory requirements in Azure. It provides a comprehensive view of your Azure environment’s compliance posture against various industry standards and regulations, such as GDPR, HIPAA, ISO 27001, and others.\n\nCompliance Manager offers:\n	Assessment tools to measure compliance.\n	Pre-configured templates based on industry regulations.\n	Actionable insights to help remediate compliance gaps.\n\nWhy not the other options?\n	The Knowledge Center website: Provides general information and best practices but does not evaluate regulatory compliance.\n\n	The Advisor blade from the Azure portal: Azure Advisor provides recommendations on best practices for performance, cost optimization, and security but does not specifically assess regulatory compliance.\n\n	The Security Center blade from the Azure portal: Azure Security Center focuses on security posture and threat protection, but it is not designed to evaluate compliance with regulatory requirements.', '2026-03-12 02:58:57', 1),
	(168, 166, 'Correct answer: ✅ Microsoft Online Services Terms\n\nExplanation\n\nThe Microsoft Online Services Privacy Statement explains how Microsoft handles data processing and its purposes. However, when it comes to understanding the terms and conditions related to the services offered by Microsoft, the Microsoft Online Services Terms document provides a more complete understanding of what services are covered, the obligations of both parties, and how the data is handled in the context of service usage.\n\nWhy not the other options?\n	Microsoft Online Service Level Agreement: This document outlines the performance and availability commitments for Microsoft\'s services, not how data is processed.\n\n	Online Subscription Agreement for Microsoft Azure: This agreement is more specific to Azure subscriptions and focuses on subscription terms and pricing rather than data processing.\n\n	No change is needed: While the privacy statement is related to data processing, the Online Services Terms document is the most appropriate for understanding the full scope of data processing within Microsoft\'s cloud services', '2026-03-12 02:58:57', 1),
	(169, 167, 'Correct answer: ✅ No change is needed: 12 months\n\nExplanation\n\nIf Microsoft plans to end support for an Azure service that does not have a successor service, the company typically provides notification at least 12 months in advance. This is part of Microsoft\'s policy for service deprecation and helps customers prepare for migration or changes.\n\nMicrosoft provides 12 months\' notice to ensure that customers have ample time to transition to alternative solutions or make the necessary adjustments.\n\nWhy not the other options?\n\n6 months, 90 days, or 30 days: These are much shorter notice periods and are generally not aligned with Microsoft\'s standard for service deprecation, which aims to give customers enough time for significant planning, testing, and migration.', '2026-03-12 02:58:57', 1),
	(170, 168, 'Explanation\n\nWhile removing unused network interfaces would remove associated costs related to them, network interfaces in Azure typically do not incur significant costs unless they are attached to running virtual machines (VMs) or other resources that generate costs.\n\nHere’s a breakdown of the resources and their impact on costs:\n\nUser accounts and groups in Microsoft Entra ID: These do not incur costs unless they are part of premium features (like Microsoft Entra ID Premium), but they are usually free in basic usage.\n\nPublic IP addresses: These can incur costs, especially if they are static and not associated with any resource. Removing unused public IPs would reduce costs more effectively than removing network interfaces.\n\nNetwork interfaces: They do incur costs only when attached to running VMs or similar resources. If they are not attached, they may not have a significant cost.\n\nWhy doesn’t this solution fully meet the goal?\n\nTo reduce Azure costs effectively, removing unused public IP addresses (especially static ones) would have a larger impact. Network interfaces, on their own, are not typically a major cost factor unless they are actively attached to resources like VMs.', '2026-03-12 02:58:57', 1),
	(171, 169, 'Correct answer: ✅ Yes\n\nExplanation\n\nTo reduce Azure costs effectively, removing unused public IP addresses is a solid solution. Here\'s why:\n\nPublic IP addresses can incur costs, particularly static IPs. Even if they are not associated with any resources, they will still generate charges.\n\nDynamic IPs are only billed when they\'re allocated to resources like virtual machines (VMs) or load balancers. If they are not in use, they typically do not incur charges, but static public IPs will continue to accrue costs.\n\nBy removing unused static public IP addresses, you will effectively reduce unnecessary costs associated with them.\n\nWhy the other resources don\'t have the same impact:\n\nUser accounts and groups in Microsoft Entra ID typically do not incur additional costs unless you\'re using premium features (which isn\'t mentioned here).\n\nNetwork interfaces are usually only charged when they are attached to running VMs or similar resources. If they are not in use and not associated with any active resources, they do not generate significant costs.', '2026-03-12 02:58:57', 1),
	(172, 170, 'Correct answer: ✅ No\n\nExplanation\n\nRemoving unused user accounts from Microsoft Entra ID typically does not result in significant cost reduction for most companies using basic features of Microsoft Entra ID (formerly Azure Active Directory).\n\nHere’s why:\n\nUser accounts in Microsoft Entra ID are usually free unless you are using premium plans (like Entra ID Premium P1 or P2), which would incur costs.\n\nIf your organization is using basic Entra ID (which is typically the default free tier), removing user accounts won\'t reduce costs.\n\nCosts related to public IP addresses and network interfaces are generally more significant and removing unused public IP addresses or network interfaces would lead to greater cost savings.', '2026-03-12 02:58:57', 1),
	(173, 171, 'Correct answer: ✅ Basic\n\nExplanation:\n\nThe Basic support plan in Azure provides the following at the lowest possible cost:\n	Best practice information\n	Health status and notifications\n	24/7 access to billing information\n\nThe Basic plan is intended for cost-conscious organizations that need support for billing and general service health but don\'t require in-depth technical support.\n\nWhy not the other options?\n	Standard: Provides more comprehensive support, including technical support, which is a step up from the Basic plan.\n	\n	Developer: Offers technical support for development and testing scenarios, which isn\'t focused on best practices or health notifications.\n	\n	Professional Direct: A premium support plan for enterprises that require faster response times and advanced technical support, which exceeds the lowest cost requirement.', '2026-03-12 02:59:38', 1),
	(174, 172, 'Correct answer: ✅ The Azure portal\n\nExplanation:\n\nTo create an Azure support request, you should use the Azure portal, which is specifically designed for managing and troubleshooting Azure resources, including submitting support requests.\n\nThe Azure portal provides a straightforward way to create, track, and manage support requests.\n\nWhy not the other options?\n	support.microsoft.com: While this site provides general Microsoft support, it is not the primary place for submitting Azure-specific support requests.\n\n	The Knowledge Center: This is more focused on providing documentation, articles, and troubleshooting guides, not support requests.\n\n	The Security & Compliance admin center: This is used for managing security, compliance, and data governance, not for submitting support requests.', '2026-03-12 02:59:38', 1),
	(175, 173, 'Correct answer: ✅ No\n\nExplanation\n\nRemoving unused groups in Microsoft Entra ID will not have a significant impact on your Azure costs. Here’s why:\n	Microsoft Entra ID groups are generally used for organizing users and assigning roles or permissions, but they do not incur additional costs unless you\'re using premium features like Microsoft Entra ID Premium.\n\n	Cost-saving measures would be more effectively focused on removing unused public IP addresses (especially static ones) or network interfaces, which can incur charges.\n\nWhy not the other resources?\n	Public IP addresses: Static IP addresses, in particular, incur charges. Removing unused public IPs would have a much greater impact on reducing costs.\n\n	Network interfaces: If not attached to active VMs, these might not cost much, but removing unused network interfaces attached to inactive VMs or resources can also help reduce costs.', '2026-03-12 02:59:39', 1),
	(176, 174, 'Correct Answer: ✅ No change is needed. :  Standard\n\nExplanation\nThe Standard support plan is indeed the lowest cost option that provides 24×7 access to support engineers by phone.\n\nHere\'s a breakdown:\n	Standard: This is the lowest-cost support plan that includes 24×7 access to support engineers via phone or email. It provides a wide range of support options and is suitable for production workloads.\n\n	Professional Direct: This plan provides faster response times and access to specialized engineers, but it comes at a higher cost compared to Standard.\n\n	Developer: Designed for development and testing scenarios, this plan provides non-urgent support and does not include phone support.\n\n	Basic: This is the free support plan and provides only billing and service health support, with no access to phone support.', '2026-03-12 02:59:39', 1),
	(177, 175, 'Correct answer: ✅ Excluded from the Service Level Agreements.\n\nExplanation\n\nAzure services in public preview are generally not covered by Service Level Agreements (SLAs). \nThese services are available for customers to try out and provide feedback, but they are not guaranteed to meet the same performance or uptime standards as generally available (GA) services.\n\nHere’s why the other options don\'t fit:\n	Provided without any documentation: This is incorrect. Even though public preview services are in a testing phase, they typically come with documentation to help customers use them, though they may not be as complete as GA documentation.\n\n	Only configurable from Azure CLI: Public preview services can often be configured from the Azure portal, Azure CLI, or PowerShell, depending on the service.\n\n	Only configurable from the Azure portal: As mentioned, public preview services can typically be configured in multiple ways, including Azure CLI, PowerShell, and sometimes SDKs.', '2026-03-12 02:59:39', 1),
	(178, 176, 'Correct answer: ✅No change is needed. : Public preview\n\nExplanation\n\nWhen an Azure service is in public preview, it is available to all Azure customers, and anyone can use it, though it might not have the same level of stability or support as services in general availability (GA). During the public preview, Microsoft invites customers to try out the new features and provide feedback.\n\nHere\'s why the other options don\'t fit:\n	Private preview: In this phase, the service is only available to a limited set of customers, often for testing and feedback purposes, and not all Azure customers can access it.\n\n	Development: This term refers to a stage of the service lifecycle or the development of an application, not the preview phase.\n\n	Enterprise Agreement (EA) subscription: This is a pricing and licensing option for organizations, not a preview phase. A service in public preview is available to all customers, regardless of their subscription type.', '2026-03-12 02:59:39', 1),
	(179, 177, 'Correct answer: ✅ No\n\nExplanation\n\nThe concept of elasticity in Azure refers to the ability of a system to automatically scale resources up or down based on demand. Elasticity helps ensure that your application can handle varying loads, but it does not directly address the availability of resources in case of a data center failure.\n\nTo achieve high availability in the event that an Azure data center becomes unavailable, you would need to design for fault tolerance and disaster recovery, not just elasticity. This can include:\n	Deploying resources across multiple Availability Zones (AZs) within a region. This ensures that if one data center goes down, the resources in another AZ remain available.\n\nImplementing geo-replication for critical data and services to ensure that services remain available even if a single region or data center fails.\n\nWhy not elasticity?\n	Elasticity is about scaling resources to meet changing demand, but it does not ensure availability in the case of data center or region failure. High availability requires a distributed architecture and redundancy across multiple zones or regions.', '2026-03-12 02:59:39', 1),
	(180, 178, 'Correct answer: ✅ No\n\nExplanation\n\nThe concept of scalability in Azure refers to the ability to increase or decrease the capacity of resources based on demand (e.g., adding more virtual machines or increasing storage when needed). Scalability is important for handling varying workloads but does not specifically address availability in the event of an Azure data center failure.\n\nTo meet the goal of availability in case one of the Azure data centers becomes unavailable for a lengthy period, you should focus on solutions that ensure fault tolerance and disaster recovery, such as:\n	Availability Zones (AZs): Distribute your virtual machines and other critical resources across multiple Availability Zones within the same region. Each AZ is essentially a separate data center with its own power, cooling, and networking.\n\n	Geo-replication: For critical workloads and data, use geo-replication across different Azure regions to ensure that services remain available even if a whole region is unavailable.\n\n	Load balancing: Set up load balancing across regions or availability zones to ensure traffic is directed to healthy resources.\n\nWhy not scalability?\n	Scalability is about adapting to changes in demand, but availability in the context of a data center failure is about resilience and redundancy, which scalability does not directly address.', '2026-03-12 02:59:39', 1),
	(181, 179, 'Correct answer: ✅ Yes\n\nExplanation\n\nFault tolerance refers to the ability of a system to continue operating properly in the event of a failure of some of its components, \nsuch as a data center or a specific service. In Azure, fault tolerance typically involves designing your environment \nin a way that allows resources to remain operational even if one component fails.\n\nTo meet the goal of ensuring availability in the event that one of the Azure data centers becomes unavailable for a lengthy period, the solution should involve setting up a fault-tolerant architecture. This can be achieved by:\n	Deploying resources across multiple Availability Zones (AZs): AZs are separate data centers within an Azure region. If one AZ fails, the resources in another AZ will continue functioning.\n\n	Geo-replication and disaster recovery: For more critical workloads, using geo-replication to replicate data and services across multiple Azure regions can ensure business continuity if an entire region becomes unavailable.\n\n	Load balancing and automatic failover: Ensuring that traffic is automatically redirected to healthy resources in the event of a failure.', '2026-03-12 02:59:39', 1),
	(182, 180, 'Correct answer: ✅ No\n\nExplanation\n\nSoftware as a Service (SaaS) refers to software applications that are hosted and managed by a cloud provider, typically accessed via a web browser. In SaaS, the provider manages the application, infrastructure, and underlying resources.\n\nFor deploying Azure virtual machines (VMs), SaaS would not be the appropriate solution. Virtual machines are infrastructure-level resources, and SaaS doesn\'t provide control over individual virtual machines or infrastructure components. Instead, Infrastructure as a Service (IaaS) is the correct deployment model for this task.\n\nIn IaaS, you can create, configure, and manage virtual machines in Azure, which provides you with full control over the operating system and applications running on the VM.\n\nWhy SaaS doesn\'t meet the goal:\n	SaaS focuses on providing ready-made software applications to end-users, not the underlying infrastructure for creating virtual machines.\n\nCorrect cloud deployment solution:\n	IaaS would be the right choice for deploying Azure virtual machines, as it allows you to manage the VMs, networking, and storage.', '2026-03-12 02:59:39', 1),
	(183, 181, 'Correct answer: ✅ No\n\nExplanation\n\nPlatform as a Service (PaaS) is a cloud service model that provides a platform for developers to build, deploy, and manage applications without managing the underlying hardware or software infrastructure. PaaS includes services like Azure App Services and Azure Functions, which abstract away the management of virtual machines and infrastructure.\n\nFor deploying Azure virtual machines (VMs), PaaS would not be the appropriate solution because you need more control over the operating system, network, and configuration of individual virtual machines, which PaaS does not provide.\n\nThe correct deployment model for Azure virtual machines is:\n	Infrastructure as a Service (IaaS): With IaaS, you can create, configure, and manage virtual machines with full control over the operating system, networking, and storage, which is required when deploying VMs.\n\nWhy PaaS doesn\'t meet the goal:\n	PaaS is more suited for application hosting and managed services, not for virtual machine provisioning and infrastructure management.', '2026-03-12 03:00:00', 1),
	(184, 182, 'Correct answer: ✅ Yes\n\nExplanation\n\nInfrastructure as a Service (IaaS) is the appropriate solution when you need to deploy Azure virtual machines (VMs). With IaaS, you are provided with the virtualized computing resources such as virtual machines, storage, and networking, but you have control over the operating systems and applications running on those VMs.\n\nUsing IaaS, you can:\n	Deploy and manage virtual machines in Azure.\n	Have full control over the OS and installed applications.\n	Manage networking and storage configurations related to the virtual machines.\n\nWhy IaaS meets the goal:\n	IaaS allows you to create virtual machines, which is the exact goal you need to accomplish in this scenario.', '2026-03-12 03:00:00', 1),
	(185, 183, 'Correct answer: ✅ No\n\nExplanation\n\nThe goal is to minimize capital and operational overheads while making extra resources available to users. Adding an additional data center would actually increase capital and operational costs, as it requires significant upfront investment, ongoing maintenance, and management of physical infrastructure.', '2026-03-12 03:00:00', 1),
	(186, 184, 'Correct answer: ✅ Yes\n\nExplanation\n\nA hybrid cloud is an ideal solution when the goal is to make extra resources available to users while minimizing both capital and operational overheads.\n\nA hybrid cloud allows your company to extend their on-premises resources to the cloud, combining the flexibility of the cloud with the control of on-premises infrastructure. Here’s how it meets the goal:\n	Reduced Capital Overheads: By leveraging the cloud for additional resources, your company doesn\'t need to invest heavily in new hardware or infrastructure. This minimizes capital expenditure.\n\n	Operational Efficiency: The hybrid cloud solution allows for scalability and elasticity. Your company can quickly scale cloud resources as needed, while still maintaining some on-premises infrastructure for specific workloads. This flexibility reduces operational complexity and costs.\n\n	Improved Resource Availability: Hybrid cloud solutions enable seamless integration between on-premises resources and the cloud, allowing you to provision additional resources quickly without building new data centers.', '2026-03-12 03:00:00', 1),
	(187, 185, 'Correct answer: ✅ No\n\nExplanation\n\nA private cloud involves creating and maintaining an isolated cloud environment within the company’s own data centers or a third-party data center. While a private cloud offers control over infrastructure and security, it still requires significant capital investment in hardware, software, and ongoing maintenance. It also incurs operational costs related to staffing, power, cooling, and management.\n\nSince the goal is to minimize capital and operational overheads, using a private cloud would not be the best solution. Instead, a public cloud or hybrid cloud model would be more suitable, as they eliminate the need for significant upfront capital expenditure and provide scalability without the need for heavy operational management.', '2026-03-12 03:00:00', 1),
	(188, 186, 'Correct answer: ✅ No\n\nExplanation\n\nThe elastic expenditure model refers to scaling resources up or down based on demand, which is a key feature of cloud environments like Azure. However, when it comes to the pay-as-you-go model in Azure, the expenditure is based on the actual usage of resources, and it\'s generally considered pay-per-use, which is often associated with cloud services like VMs, storage, and bandwidth.\n\nThe pay-as-you-go model in Azure doesn\'t refer to the "elastic expenditure model." Instead, it involves the direct costs associated with the usage of resources, such as virtual machines, where you are charged based on the amount of resources consumed (e.g., compute power, storage, and networking).', '2026-03-12 03:00:00', 1),
	(189, 187, 'Correct answer: ✅ No\n\nExplanation\n\nWhile the scalable expenditure model might seem relevant in the context of Azure because resources can scale up or down, the correct expenditure model for Azure\'s pay-as-you-go pricing is the Operational Expenditure (OpEx) model, not the scalable expenditure model.\n\nWhy scalable expenditure model doesn\'t meet the goal:\n\nThe scalable expenditure model typically refers to scaling resources based on demand, and it’s about resource allocation rather than how the costs are structured.\n\nThe Azure pay-as-you-go model fits under Operational Expenditure (OpEx) because you are billed based on actual usage, with no upfront capital investment in infrastructure.', '2026-03-12 03:00:00', 1),
	(190, 188, 'Correct answer: ✅ Yes\n\nExplanation\n\nThe operational expenditure (OpEx) model is the correct expenditure model for the Azure pay-as-you-go subscription. Here\'s why:\n\nThe OpEx model involves paying for resources as you use them, which is exactly how the Azure pay-as-you-go model works. In this model, you don\'t need to make large upfront investments in infrastructure; instead, you pay for the resources you consume, such as virtual machines, storage, and networking.\n\nPay-as-you-go is a typical example of OpEx because you are billed based on consumption. The costs are operational in nature, meaning they are ongoing and related to how much you actually use.', '2026-03-12 03:00:00', 1),
	(191, 189, 'Correct answer: ✅ No\n\nExplanation\n\nAzure Cosmos DB is a globally distributed, multi-model database service designed to provide low-latency, high-availability, and scalability for mission-critical applications. However, Cosmos DB is not primarily intended for building, testing, and deploying predictive analytics or Artificial Intelligence (AI) models.\n\nFor AI and predictive analytics, the correct Azure service would be Azure Machine Learning or related services, which provide tools and frameworks for training, testing, and deploying AI models.', '2026-03-12 03:00:00', 1),
	(192, 190, 'Correct answer: ✅ No\n\nExplanation\n\nAzure Logic Apps is a workflow automation service that allows you to build automated workflows to integrate apps, data, and services. While Logic Apps can be used to connect different services and automate processes, it is not designed for building, testing, and deploying AI models or performing predictive analytics.\n\nFor AI and predictive analytics, the correct Azure service would be Azure Machine Learning. Azure Machine Learning provides the tools needed to build, test, and deploy machine learning models for tasks like predictive analytics.', '2026-03-12 03:00:00', 1),
	(193, 191, 'Correct answer: ✅ Yes\n\nExplanation\n\nAzure Machine Learning Studio is a powerful tool within Azure Machine Learning that allows you to build, test, and deploy predictive analytics models. It provides a drag-and-drop interface for data scientists and developers to create machine learning models without needing to write extensive code. This aligns perfectly with your goal of developing and deploying AI solutions with predictive analytics.\n\nWhy Azure Machine Learning Studio meets the goal:\n	Azure Machine Learning Studio is designed specifically for building, training, testing, and deploying AI models for predictive analytics.\n	It provides both visual interfaces and code-first capabilities to work with data and models, making it an ideal tool for your AI solution.\n	It allows for end-to-end workflows in machine learning, from data preprocessing to model training and deployment.', '2026-03-12 03:00:57', 1),
	(194, 192, 'Correct answer: ✅ No\n\nExplanation\n\nAzure API Management (APIM) is primarily used for managing APIs, including publishing, securing, monitoring, and analyzing APIs. It is not designed for automatically provisioning Azure resources across multiple business units.\n\nTo meet the goal of automating the creation of identical Azure resources for each business unit, the correct solution would be to use Azure Resource Manager (ARM) templates or Azure Blueprints, which are designed specifically for automating the deployment and management of Azure resources.', '2026-03-12 03:00:57', 1),
	(195, 193, 'Correct answer: ✅ No\n\nExplanation\n\nManagement groups in Azure are used for organizing and managing access, policies, and compliance across multiple subscriptions. They are a logical structure that helps with hierarchical management of resources but are not directly involved in automatically provisioning resources.\n\nWhile management groups are useful for governance and access control at scale, they do not automate the creation or provisioning of resources. Therefore, using management groups alone would not meet the goal of automating the creation of Azure resources.', '2026-03-12 03:00:57', 1),
	(196, 194, 'Correct answer: ✅ Yes\n\nExplanation\n\nAzure Resource Manager (ARM) templates are the ideal solution for automating the creation and deployment of Azure resources in a consistent and repeatable way. ARM templates are a form of Infrastructure as Code (IaC) that allows you to define the desired resources, their configurations, and relationships in a JSON format.\n\nWhy ARM templates meet the goal:\n	Automation: ARM templates enable you to automatically deploy resources across multiple environments, ensuring consistency and reducing manual effort.\n\n	Consistency: Since the resources required by each business unit are identical, ARM templates allow you to define the exact configuration and then deploy it to multiple business units, ensuring the same setup across all.\n\n	Scalability: ARM templates can be used to scale deployments across multiple business units or subscriptions, making them ideal for large-scale automation.', '2026-03-12 03:00:57', 1),
	(197, 195, 'Correct answer: ✅ No\n\nExplanation\n\nTo meet the 99.99% availability guarantee, Azure requires deploying resources across at least two Availability Zones within a region. A single Availability Zone only provides redundancy within a data center, and in the event of a data center failure, your application would not meet the required SLA.\n\nWhy two virtual machines in one Availability Zone doesn\'t meet the goal:\n	99.99% SLA for VMs requires at least two virtual machines deployed across two Availability Zones.\n	One Availability Zone limits your ability to meet the SLA because if that zone goes down, your application would be impacted, and the SLA would not be met.\n\nCorrect solution for meeting the SLA:\n	To meet the 99.99% availability SLA, you need to deploy at least two virtual machines across two Availability Zones. This ensures that if one Availability Zone fails, the other can still serve traffic, ensuring higher availability.', '2026-03-12 03:00:57', 1),
	(198, 196, 'Correct answer: ✅ No\n\nExplanation\n\nA single virtual machine cannot span across two Availability Zones. Each virtual machine is located in one Availability Zone at a time. If you deploy a single VM in one zone, that VM cannot achieve the required high availability in case of zone failure.\n\nTo meet the 99.99% availability SLA, you would need to deploy at least two virtual machines, each in different Availability Zones. This ensures that if one Availability Zone fails, the other VM in the second zone can take over, keeping the application available.\n\nWhy the solution doesn\'t meet the goal:\n	A single VM cannot span two Availability Zones.\n	For 99.99% availability, you need redundancy across multiple zones. So, you would need at least two VMs, each in a different zone.\n	One VM in two zones is not possible; instead, you\'d have to deploy two separate VMs in two different zones to ensure failover and availability.\n\nCorrect Solution:\n	To meet the 99.99% SLA:\n	Deploy two virtual machines, each in a different Availability Zone.', '2026-03-12 03:00:58', 1),
	(199, 197, 'Correct answer: ✅ Yes\n\nExplanation\n\nTo meet the 99.99% availability SLA for Azure Virtual Machines, the solution must include at least two Availability Zones to provide redundancy in case one zone goes down.\n\nThis approach ensures that if one Availability Zone experiences an outage, the second VM in the other zone can continue operating, keeping the application available and meeting the 99.99% availability requirement.\n\nWhy the solution meets the goal:\n	Deploying two virtual machines across two Availability Zones ensures high availability and fault tolerance, as one VM will continue running if the other zone becomes unavailable.\n\n	Two Availability Zones within the same region provide geographic redundancy and help meet the 99.99% SLA.', '2026-03-12 03:00:58', 1),
	(200, 198, 'Correct answer: ✅ No\n\nExplanation\n\nMicrosoft Managed Desktop is a service designed to provide fully managed Windows desktops for organizations. It provides administration and security management for Windows devices but does not provide solutions for virtual machine automation or provisioning for different OS types (such as Windows Server 2016 and Ubuntu Linux).\n\nIn this scenario, the company is deploying and removing virtual machines (VMs) with different operating systems (Windows Server 2016 and Ubuntu Linux) frequently. Therefore, the goal is to reduce administrative effort related to VM creation and deletion.', '2026-03-12 03:00:58', 1),
	(201, 199, 'Correct answer: ✅ No\n\nExplanation\n\nAzure Reserved Virtual Machines (VM) Instances are designed to provide cost savings for VMs by committing to a 1- or 3-year reservation of virtual machines. While they can help save money for long-term use, they do not address the need for automation or reducing the administrative effort required to deploy and remove a large number of VMs on a weekly basis.\n\nWhy Azure Reserved VM Instances doesn\'t meet the goal:\n	Reserved VM Instances require you to commit to long-term usage (1- or 3-year commitment), but in your scenario, the VMs are deployed and removed on a weekly basis.\n\n	The short-term nature of the VM lifecycle in this scenario means that Azure Reserved VMs would not be appropriate as they are designed to provide savings for long-term, persistent workloads.', '2026-03-12 03:00:58', 1),
	(202, 200, 'Correct answer: ✅ Yes\n\nExplanation\n\nAzure DevTest Labs is a service specifically designed for dev/test environments where developers and testers can quickly create and manage virtual machines (VMs). It is highly suitable for scenarios where a large number of virtual machines need to be deployed and removed frequently, as in your scenario.\n\nWhy Azure DevTest Labs meets the goal:\n	DevTest Labs provides automation and cost management features, enabling teams to easily provision, use, and decommission virtual machines without manual intervention.\n\n	It allows developers to create VMs based on pre-configured VM templates for both Windows and Linux OSes (e.g., Windows Server 2016 and Ubuntu), meeting the specific requirements of your scenario.\n\n	It helps reduce administrative effort by enabling features like auto-shutdown, template management, and VM quotas to automatically manage resources.\n\nYou can automate the deployment and removal of VMs, which is exactly what is needed for a large-scale, weekly VM lifecycle.', '2026-03-12 03:00:58', 1),
	(203, 201, 'Correct answer: ✅ Configure a Point-to-Site (P2S) VPN\n\nExplanation\n\nP2S VPN allows individual remote clients (like laptops or mobile devices) to securely connect to an Azure VNet from anywhere over the internet. This is perfect for remote workers who need access to VMs but are not connected to a corporate network via a Site-to-Site (S2S) VPN.\n\nWhy the other options don\'t meet the goal:\n	Site-to-Site (S2S) VPN:\n		S2S is used to connect entire on-premises networks to Azure VNet, not individual remote workers. It\'s typically used for branch offices or corporate networks, not for remote workers.\n	VNet-to-VNet VPN:\n		This is used to connect two Azure VNets, not for providing access to remote workers.\n\n	DirectAccess on a Windows Server 2012 server VM:\n		DirectAccess is a Microsoft technology for remote access, but it\'s designed for corporate networks and requires additional infrastructure. It’s not the preferred solution for Azure-based remote access.\n\n	Multi-Site VPN:\n		This would be used to connect multiple on-premises sites to Azure VNet, not remote workers to VMs.\n ', '2026-03-12 03:01:22', 1),
	(204, 202, 'Correct answer: ✅ No\n\nExplanation\n\nMicrosoft Purview Information Protection is primarily designed for classifying, labeling, and protecting sensitive data at rest, in motion, and during sharing. It is primarily used for data protection and compliance across documents and emails, rather than securing administrative credentials during a server deployment process.\n ', '2026-03-12 03:01:22', 1),
	(205, 203, 'Correct answer: ✅ Yes\n \nExplanation\n\nAzure Key Vault is the ideal solution for securely managing and encrypting sensitive information, including administrative credentials, during server deployment to Azure.\n\nWhy Azure Key Vault meets the goal:\n	Azure Key Vault is a cloud service that securely stores and manages sensitive information such as secrets (e.g., passwords, API keys), cryptographic keys, and certificates.\n	\n	During the server deployment process, you can use Azure Key Vault to securely store administrative credentials (like passwords) and ensure that they are never exposed in scripts or deployment pipelines.\n	\n	It ensures that sensitive information is encrypted both at rest and in transit.\n ', '2026-03-12 03:01:22', 1),
	(206, 204, 'Correct answer: ✅ No\n\nExplanation\n\nAzure Multi-Factor Authentication (MFA) is designed to enhance the security of user logins by requiring additional verification (e.g., SMS, authenticator app, etc.) to confirm a user\'s identity. While MFA improves authentication security, it does not encrypt or secure administrative credentials during server deployment processes.\n\n ', '2026-03-12 03:01:22', 1),
	(207, 205, 'Correct answer: ✅ No\n\nExplanation\n\nAzure Key Vault is primarily used for securely storing and managing secrets, keys, and certificates. While it is essential for storing sensitive information like passwords, Azure Key Vault is not designed for handling user authentication or enforcing security policies based on user location, such as automatically prompting users to change their passwords when they connect from an unidentified IP address.\n ', '2026-03-12 03:01:22', 1),
	(208, 206, 'Correct answer: ✅ Yes\n\nExplanation\n\nConfiguring Microsoft Entra ID Protection meets the goal.\n\nMicrosoft Entra ID Protection detects risky sign-ins, including logins from unfamiliar or unidentified IP addresses. You can configure risk-based policies (such as User Risk or Sign-in Risk policies) to:\n	Detect suspicious sign-ins\n	Automatically require password changes\n	Force secure password reset when risk is detected\n\nThis directly ensures that users signing in from unidentified IP addresses are prompted to change their passwords.\n ', '2026-03-12 03:01:22', 1),
	(209, 207, 'Correct answer: ✅ Yes\n\nExplanation\n\nMicrosoft Entra ID Protection (formerly Azure AD Identity Protection) is specifically designed to help protect user identities by detecting risky sign-ins and enforcing security policies based on those risks. It can evaluate sign-ins based on factors like location, IP address, and sign-in risk, and can take actions such as requiring users to change their passwords when certain conditions are met.\n\nHow Microsoft Entra ID Protection meets the goal:\n	Risk-based policies: Entra ID Protection can detect unfamiliar or suspicious IP addresses and automatically flag the sign-in as risky.\n\n	Password change prompts: When risky sign-ins are detected, such as from an unidentified IP address, Entra ID Protection can enforce a policy to prompt users to change their passwords.\n\n	It allows you to automatically encourage or require password changes in response to risky conditions (e.g., sign-ins from unfamiliar locations).\n ', '2026-03-12 03:01:22', 1),
	(210, 208, 'Correct answer: ✅ No\n\nExplanation\n\nThe Azure Service Bus is a messaging service designed to facilitate asynchronous communication between applications and services. It is commonly used for scenarios where you need to decouple applications, allow for message queuing, and enable reliable messaging between distributed systems.\n\nHowever, the Azure Service Bus is not designed to control or manage direct connections between resources such as web servers and database servers. It does not provide the capability to manage network-level connections or enforce network security policies for these types of connections.\n ', '2026-03-12 03:01:22', 1),
	(211, 209, 'Correct answer: ✅ Yes\n\nExplanation\n\nNetwork Security Groups (NSGs) are designed to control inbound and outbound network traffic to Azure resources, such as web servers and database servers. NSGs allow you to define security rules based on various factors such as IP addresses, ports, and protocols. This makes NSGs an excellent choice for controlling connection types between resources like web servers and database servers.\n\nHow NSGs meet the goal:\n	Traffic Control: NSGs can be used to define rules that control which traffic is allowed to and from specific Azure resources. For example, you can restrict web servers to only connect to database servers on specific ports (e.g., 1433 for SQL Server).\n\n	Fine-Grained Security: You can specify rules based on IP address ranges, allowing you to whitelist or blacklist specific network ranges for communication.\n\n	Application-Level Control: You can apply NSGs to either specific VMs or subnets, providing flexibility in controlling traffic at different levels in your infrastructure.\n ', '2026-03-12 03:01:22', 1),
	(212, 210, 'Correct answer: ✅ No\n\nExplanation\n\nA local network gateway is used to represent a physical network on-premises when setting up VPN connections between an on-premises network and an Azure virtual network (VNet). It is primarily used for site-to-site VPN connections, where an Azure VNet is connected to an on-premises network.', '2026-03-12 03:01:22', 1),
	(213, 211, 'Correct answer: ✅ No\n\nExplanation\n\nWhile Azure Multi-Factor Authentication (MFA) is an important security feature that enhances the protection of user identities by requiring multiple forms of verification, it does not directly address the goal of reducing the impact on users during the migration to Azure.\n\nThe goal here is to ensure that the transition from on-premises Active Directory (AD) to Azure (and possibly Azure Active Directory or Microsoft Entra ID) happens smoothly, with minimal disruption to users. Implementing MFA on its own would introduce additional authentication steps during the transition, which could increase the complexity and impact for users, especially during the migration process.\n', '2026-03-12 03:01:58', 1),
	(214, 212, 'Correct answer: ✅ Yes\n\nExplanation\n\nThe goal is to ensure that users experience minimal disruption when migrating from an on-premises Active Directory environment to Azure. By syncing Active Directory user accounts to Microsoft Entra ID (formerly Azure AD), you can maintain user identity continuity and allow users to continue using their existing credentials to access resources in Azure.\n\nHow syncing to Microsoft Entra ID meets the goal:\n	Azure AD Connect: You can use Azure AD Connect to sync on-premises Active Directory accounts to Microsoft Entra ID. This allows users to authenticate to Azure resources using the same credentials as before.\n\n	No User Impact: The sync ensures that user names, passwords, and other identity-related information are the same in Azure AD as they were in on-premises AD. This means users don’t need to change passwords or go through additional setup processes when migrating to Azure.\n\n	Hybrid Identity: With hybrid identity solutions, users can access both on-premises and cloud resources seamlessly during the transition. This minimizes the impact and complexity of the migration process.\n', '2026-03-12 03:01:58', 1),
	(215, 213, 'Correct answer: ✅ No\n\nExplanation\n\nEnforcing a password change during or after migration to Azure can create unnecessary disruption for users, especially if their credentials are still synced or if they were migrated to Microsoft Entra ID (formerly Azure AD). A password change would increase the impact on users and is not necessary as part of the migration process.\n ', '2026-03-12 03:01:58', 1),
	(216, 214, 'Correct answer: ✅ Standard\n\nExplanation\nRequirements:\n\nCustom domains: The web apps need to use custom domains.\n	Basic, Standard, and Premium plans allow custom domains. The Free and Shared plans do not allow custom domains.\n	\n10 GB of storage per app: Each web app requires 10 GB of storage.\n	Free and Shared tiers have limited storage, and typically these are under 1 GB of storage per app.	\n	The Basic, Standard, and Premium tiers offer enough storage (usually starting at 10 GB and higher).\n	\nDedicated compute instances: Each app must run in dedicated compute instances.\n	The Basic, Standard, and Premium tiers provide dedicated compute instances.	\n	The Free and Shared tiers run on shared infrastructure, so they don\'t meet this requirement.\n	\nLoad balancing between instances: The apps must include load balancing.\n	Standard, Premium, and Basic tiers provide load balancing.	\n	The Free and Shared tiers do not include load balancing features.\n	\nMinimized costs: Cost minimization is a key concern.\n	Standard offers a balance between cost and features, with the ability to use dedicated compute instances, custom domains, and load balancing, making it a suitable choice for this scenario. It is more affordable than the Premium plan while still offering all the necessary features.\n	The Basic tier is cheaper but does not provide all the advanced features that might be necessary for some high-performance applications.\n	Free and Shared are not viable because they lack dedicated compute and do not allow custom domains.\n ', '2026-03-12 03:01:58', 1),
	(217, 215, 'Correct answer: ✅ No\n\nExplanation\n\nService health alerts in Azure are primarily used to notify you about issues related to the health of Azure services, such as outages, performance degradation, or planned maintenance in your region. These alerts are designed to keep you informed about service availability and performance issues but do not directly address subscription limits.\n ', '2026-03-12 03:01:58', 1),
	(218, 216, 'Correct answer: ✅ No\n\nExplanation\n\nAzure policies are used to enforce governance across your Azure resources. They allow you to define rules and requirements for the resources in your subscription, such as restricting the types of resources that can be deployed, enforcing naming conventions, or ensuring compliance with security standards. However, Azure policies do not control subscription limits.\n ', '2026-03-12 03:01:59', 1),
	(219, 217, 'Correct answer: ✅ Yes\n\nExplanation\n\nWhen you receive a notification that the Azure subscription limits have been reached, the appropriate solution is to submit a support request to Azure Support. Azure support can assist you in increasing the resource quotas (such as the number of managed SQL Server instances) for your subscription. \n', '2026-03-12 03:01:59', 1),
	(220, 218, 'Correct answer: ✅ No\n\nExplanation\n\nUsing multiple Microsoft Entra ID directories for each division is not the optimal solution for segmenting Azure resources across divisions while minimizing administrative effort.\n\nWhy the solution does not meet the goal:\n	Microsoft Entra ID directories are typically used for isolating users, identities, and resources across entirely separate organizations or environments. Using separate directories for different divisions can lead to increased administrative overhead in terms of user and resource management, as each directory would need to be managed separately.\n\n	Managing multiple Entra ID directories means you would need to configure cross-directory access (for shared resources) and duplicate user management, making it more difficult to maintain a unified approach for managing roles and permissions across the entire organization.\n ', '2026-03-12 03:01:59', 1),
	(221, 219, 'Correct answer: ✅ No\n\nExplanation\n\nWhile resource groups are a fundamental way to organize Azure resources, using only resource groups for segmentation of Azure resources across different divisions may not be sufficient when the goal is to minimize administrative effort and ensure proper isolation between divisions.\n\nWhy the solution does not meet the goal:\n	Resource groups are not fully isolated: Resource groups are logical containers for Azure resources and provide some organizational benefits, but they do not fully isolate resources at the level required for separate administrative control. Different divisions may need to have separate billing, management boundaries, or policies, which cannot be fully achieved by resource groups alone.\n\n	Shared management of subscriptions: While resource groups can be used to group related resources, if you want full isolation of resources, separate Azure subscriptions are needed. Subscriptions allow for separate billing and access management. Resource groups alone cannot provide that level of control.\n\n	Role-Based Access Control (RBAC): RBAC can be applied at the resource group level, but for more fine-grained management, subscriptions may be a better option. Divisions would still share the same subscription unless the subscription is split across divisions.\n ', '2026-03-12 03:01:59', 1),
	(222, 220, 'Correct answer: ✅ Yes\n\nExplanation\n\nUsing multiple subscriptions is a valid solution for segmenting Azure resources by division while minimizing administrative effort. Azure subscriptions allow you to create isolated environments for each division, which can be independently managed by the assigned administrators. Each subscription can have its own resource usage, cost management, and access control.\n\nWhy the solution meets the goal:\n	Segmentation: By using separate Azure subscriptions for each division, you effectively segment resources between divisions, which helps in organizing resources and controlling access. This makes it easy to manage the scope of what each division\'s administrator has access to.\n\n	Independent Management: Each division\'s administrator can manage their own subscription without interfering with the resources of other divisions. Azure Role-Based Access Control (RBAC) can be applied at the subscription level, allowing administrators to have control over their division\'s resources without impacting others.\n\n	Simplified Billing and Cost Management: Having separate subscriptions allows for better cost management and reporting per division. You can track usage, spending, and resource consumption separately for each division.\n\n	Security and Governance: Separate subscriptions offer an additional layer of security and governance by isolating resources. Policies and compliance rules can be applied independently for each subscription, allowing you to enforce division-specific guidelines.', '2026-03-12 03:01:59', 1),
	(223, 221, 'Correct answer: ✅ Standard\n\nExplanation\n\n✅ Why Standard is Correct\nThe Standard App Service Plan is the lowest tier that satisfies all requirements:\n	✔ Supports custom domains\n	✔ Includes SSL support\n	✔ Supports scale-out to multiple instances\n	✔ Provides 50 GB storage (meets the 12 GB requirement)\n	✔ Lower cost than Premium tiers\n\nSince Basic only provides 10 GB storage, it does not meet the 12 GB requirement. Therefore, Standard is the minimum tier that satisfies all needs while keeping costs as low as possible.\n❌ Why Not the Others\n	Free\n		✖ No custom domains\n		✖ No SSL support\n		✖ No scale-out\n		✖ Very limited storage\n	Shared\n		✔ Custom domains supported\n		✖ No SSL support\n		✖ No scale-out\n	Basic\n		✔ Custom domains supported\n		✔ SSL supported\n		✔ Scale-out supported\n		✖ Only 10 GB storage (requirement is 12 GB)\n', '2026-03-12 03:03:33', 1),
	(224, 222, 'Correct answer: ✅ Read-only geo-redundant storage.\n\nExplanation:\n\n✅ Why Read-access geo-redundant storage (RA-GRS) is Correct\nRA-GRS provides:\n	✔ Locally redundant storage (LRS) in the primary region (multiple copies across nodes)\n	✔ Geo-replication to a secondary region (separate geographic location)\n	✔ Read access to the secondary region\n	✔ High durability and site resiliency\n\nSince the requirement explicitly states that data must be readable from both primary and secondary locations, RA-GRS is the only option that satisfies all conditions.\n\n❌ Why Not the Others\n	Geo-redundant storage (GRS)\n		✔ Replicates data to a secondary geographic region\n		✖ Secondary region is NOT readable (only used for failover)\n\n	Zone-redundant storage (ZRS)\n		✔ Replicates across multiple availability zones\n		✖ All zones are within the same geographic region\n\n	Locally redundant storage (LRS)\n		✔ Replicates data across multiple nodes\n		✖ Replication is within a single datacenter only\n		✖ No geographic redundancy\n		', '2026-03-12 03:03:33', 1),
	(225, 223, 'Correct answer: ❌ No\n\nExplanation\n\n❌ Why the Standard Support Plan Does NOT Meet the Goal\n	The Standard support plan provides:\n		24/7 technical support\n		Faster response times\n		Architecture guidance\nHowever:\n	It does NOT include proactive services like Azure environment assessments or design reviews by Microsoft.\n	Environment assessments and proactive architectural reviews are included in:\n	Professional Direct\n	Premier / Unified Support\n\n✅ What Is Required?\n	To receive a Microsoft-led Azure environment assessment, the company must subscribe to:\n	Professional Direct Support (minimum level that includes proactive guidance services)\n ', '2026-03-12 03:03:33', 1),
	(226, 224, 'Correct answer: ✅ Yes\n\nExplanation\n\n✅ Why Professional Direct Meets the Goal\nThe Professional Direct support plan includes:\n	✔ Proactive guidance services\n	✔ Architecture and design reviews\n	✔ Azure environment assessments\n	✔ Webinars and advisory support\nIt is the lowest-cost plan that provides proactive architectural assessment services from Microsoft.\n\n❌ Why Not the Other Plans\n	Basic → No architectural assessment support\n	Developer → No proactive design review services\n	Standard → Reactive support only, no design assessments\n	Premier / Unified → Includes assessments but is more expensive than required\n ', '2026-03-12 03:03:33', 1),
	(227, 225, 'Correct answer: ❌ No\n\nExplanation\n\n❌ Why Premier Support Does NOT Meet the Goal\nThe Premier (now Unified) support plan:\n	✔ Includes proactive services\n	✔ Includes architectural reviews and assessments\n	✔ Provides dedicated support resources\n\nHowever:\n	❗ It is a significantly more expensive support plan.\n	❗ It exceeds the minimum level required to obtain an Azure environment assessment.\nThe requirement clearly states costs must be minimized. Since Professional Direct already includes environment assessments at a lower cost, Premier is not the most cost-effective solution.\n\n✅ What Would Meet the Goal?\nProfessional Direct support plan\n	Includes architecture/design assessments\n	Lower cost than Premier\n ', '2026-03-12 03:03:33', 1),
	(228, 226, 'Correct answer: ❌ No\n\nExplanation\n\n❌ Why Creating an Azure Role Does NOT Meet the Goal\nAzure roles (RBAC) are used for:\n	Managing access control and permissions\n	Granting users rights to manage resources\n\nRoles do not:\n	Separate billing\n	Track costs by division automatically\n	Create independent payment structures\n\n✅ What Would Meet the Goal?\nTo allow each division to pay for its own usage, you should use:\n	Separate Azure subscriptions for each division\nAzure subscriptions:\n	Have separate billing\n	Track usage independently\n	Allow cost management per division\n ', '2026-03-12 03:03:33', 1),
	(229, 227, 'Correct answer: ❌ No.\n\nExplanation\n\nCreating an Azure policy for each division would help enforce governance and compliance rules, but it wouldn\'t directly address the goal of ensuring that each division can pay for the services it utilizes separately.\n\nTo meet the requirement of having each division pay for its own Azure services, you should recommend using Azure subscriptions or Azure management groups with cost management and billing features. Each division can have its own Azure subscription, and you can set up Azure Cost Management to track usage and allocate costs per subscription, which would allow each division to pay for only what it uses.\n\nKey recommendation: Assign a separate subscription to each division, and set up proper billing and cost tracking mechanisms.\n ', '2026-03-12 03:03:33', 1),
	(230, 228, 'Correct answer: ✅ Yes.\n\nExplanation\n\nCreating a separate Azure subscription for each division meets the goal of ensuring that each division can pay for the Azure services it utilizes. With individual subscriptions, you can track usage and costs for each division separately using Azure Cost Management and Azure Billing. Each division would be billed only for the resources it uses within its own subscription.\n\nThis setup gives the flexibility for divisions to manage their own spending and ensures clear financial separation between them.\n ', '2026-03-12 03:03:33', 1),
	(231, 229, 'Correct answer: ❌ No.\n\nExplanation\n\nAn Azure subscription can only be associated with one Microsoft Entra ID tenant at a time. While an Azure subscription can have multiple users and roles from different tenants, it can only be linked to a single Entra ID tenant for identity and access management purposes.\n ', '2026-03-12 03:03:33', 1),
	(232, 230, 'Correct answer: ✅ Yes.\n\nExplanation\n\nYou can change the Microsoft Entra ID tenant to which an Azure subscription is associated, but this process requires certain conditions and steps. The subscription must be moved to a different Entra ID tenant, which can be done via the Azure portal. However, there are some limitations and prerequisites, such as ensuring the new tenant has the necessary permissions and that certain resources or configurations (like specific Azure Active Directory features) might require additional considerations.\n\nThe process generally involves:\n	Ensuring the Azure subscription is not linked to any resource that would prevent the move (e.g., certain services or configurations).\n	The user performing the change must have appropriate permissions in both tenants.\n	The subscription can only be moved to a tenant that is in the same Azure AD directory or a tenant within your Azure AD B2B collaboration setup.\n\nBut overall, it is possible to change the tenant association.', '2026-03-12 03:03:33', 1),
	(233, 231, 'Correct answer: No.\n\nExplanation\n	When an Azure subscription expires, the associated Microsoft Entra ID tenant is not automatically deleted.\n\n	The Microsoft Entra ID tenant (formerly Azure AD) is a separate identity service and can exist independently of an Azure subscription. Even if all subscriptions are canceled or expired, the tenant remains unless it is explicitly deleted following the proper deletion process.\n', '2026-03-12 03:03:57', 1),
	(234, 232, 'Correct answer: Yes.\n\nExplanation\n	A single Microsoft account (or work/school account in Microsoft Entra ID) can be associated with and manage multiple Azure subscriptions.\n\n	You can be:\n		The account administrator for multiple subscriptions\n		Assigned different roles (like Owner or Contributor) across different subscriptions\n\n	This allows centralized access and management across environments.\n ', '2026-03-12 03:03:57', 1),
	(235, 233, 'Correct answer: No.\n\nExplanation\n	Two Azure subscriptions cannot be directly merged into a single subscription.\n\n	However, you can:\n		Move resources between subscriptions (if they are in the same Azure AD tenant).\n		Transfer subscription ownership.\n		Recreate resources in another subscription if needed.\n	But there is no built-in feature in Microsoft Azure that allows two existing subscriptions to be combined into one.\n ', '2026-03-12 03:03:57', 1),
	(236, 234, 'Correct answer: Yes.\n\nExplanation\n	A company can use resources from multiple subscriptions in Microsoft Azure.\n	Organizations often use multiple subscriptions to:\n		Separate environments (Production, Dev, Test)\n		Isolate departments or projects\n		Manage billing boundaries\n		Apply different access controls\n	All subscriptions can exist under the same Azure AD tenant and be managed centrally.\n', '2026-03-12 03:03:57', 1),
	(237, 235, 'Correct answer: No.\n\nExplanation\n	Availability Zones are not available in all Azure regions.\n\n	In Microsoft Azure, Availability Zones are only supported in specific regions that have been designed with physically separate datacenters within the same region.\n\n	Some regions support Availability Zones, while others do not.\n ', '2026-03-12 03:03:57', 1),
	(238, 236, 'Correct answer: No.\n\nExplanation\n	Availability Zones in Microsoft Azure support both Windows Server and Linux virtual machines.\n	Availability Zones are based on physical infrastructure separation within a region, not on the operating system of the VM.\n ', '2026-03-12 03:03:57', 1),
	(239, 237, 'Correct answer: No.\n\nExplanation\n	In Microsoft Azure, Availability Zones replicate resources across separate datacenters within the same region, not across multiple regions.\n\n	Replication across multiple regions is handled by other services such as:\n		Azure region pairs\n		Geo-redundant storage (GRS)\n\n	Availability Zones provide high availability within a single region, not cross-region replication. \n ', '2026-03-12 03:03:57', 1),
	(240, 238, 'Correct answer: ✅ Containers\n\nExplanation\n\nUnmanaged VM disks are stored as VHD files in Azure Blob Storage, and blobs are organized inside containers. That’s where the disk files actually reside.\n\n❌ File shares\n	Azure File shares are part of Azure Files.\n	They are used for SMB/NFS file sharing, not for storing VHD disk files for unmanaged VMs.\n	VM unmanaged disks are not stored in file shares.\n\n❌ Tables\n	Azure Table Storage is a NoSQL key-value store.\n	It is used for structured, non-relational data.\n	It cannot store VHD files for virtual machine disks.\n\n❌ Queues\n	Azure Queue Storage is used for message storage and processing communication between application components.\n	It is not used for file or disk storage.\n ', '2026-03-12 03:03:57', 1),
	(241, 239, 'Correct answer: ✅ Azure Cosmos DB\n\nExplanation\n\nIn Microsoft Azure, Azure Cosmos DB is the only option listed that:\n	✅ Supports multi-region writes (active-active replication)\n	✅ Natively stores JSON documents\n	✅ Is globally distributed with low latency\n	✅ Supports automatic multi-region replication\n\nWhy the other options are incorrect\nSQL databases / SQL servers / SQL managed instances / SQL elastic pools / Virtual Clusters / Managed databases\n	Primarily relational databases\n	Do not natively support multi-region concurrent writes like Cosmos DB\n\nAzure Database for MySQL / PostgreSQL / MariaDB\n	Relational databases\n	No built-in global multi-master write capability\n	Not designed for native JSON document-based workloads at global scale\n\nSQL Data warehouses\n	Designed for analytics (OLAP), not operational multi-region writes\n\nAzure Database Migration Services\n	Used for database migration, not for hosting databases\n\nAzure Cache for Redis\n	In-memory cache, not a primary database for JSON documents with global writes\n\nData factories\n	Data integration service, not a database\n\nElastic Job agents\n	Used for managing SQL jobs across databases\n\nSQL Server stretch databases\n	Used to stretch on-prem SQL to Azure, not for multi-region JSON workloads\n ', '2026-03-12 03:03:57', 1),
	(242, 240, 'Correct answer: No.\n\nExplanation\n\nIn Microsoft Azure, resources inside a resource group do not have to be in the same region.\n	A resource group has a region (for storing its metadata).\n	The resources inside it can be deployed to different Azure regions.\nSo, resources in a single resource group can span multiple regions.', '2026-03-12 03:03:57', 1),
	(243, 241, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, tags applied to a resource group are not automatically inherited by the resources inside it.\n\nA Resource Group tag applies only to the resource group itself.\nResources inside the group keep their own tags.\n\nIf you want the same tag on the resources, you must:\n	Add the tag individually, or\n	Use automation such as Azure Policy to enforce or inherit tags.\n ', '2026-03-12 03:04:18', 1),
	(244, 242, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, if a user is assigned a role (like Owner, Contributor, or another role) at the Resource Group level, that permission is inherited by all resources inside that resource group.\n\nHow it works	\n	Azure uses Role-Based Access Control (RBAC). Permissions assigned at a higher scope apply to lower scopes.\n\nScope hierarchy:\n	Management Group\n	Subscription\n	Resource Group\n	Resource\n\nSo if a user gets permission on a Resource Group, they can manage all resources within that group, such as:\n	Virtual Machines\n	Storage Accounts\n	Databases\n	Networking resources\n ', '2026-03-12 03:04:18', 1),
	(245, 243, 'Correct answer: ✅ 2 virtual machines.\n\nTo achieve 99.99% availability for Microsoft Azure Virtual Machines, you must deploy them across Availability Zones.\nAzure provides 99.99% SLA for Azure Virtual Machines when two or more VMs are deployed across Availability Zones in the same region using Azure Availability Zones.\n\nMinimum requirements\n	Minimum virtual machines: 2\n	Minimum availability zones: 2\n\nWhy?\n	Availability Zones are physically separate datacenters within a region.\n	If one zone fails, the VM in the other zone continues running.\n	Azure guarantees 99.99% uptime SLA for this configuration.\n ', '2026-03-12 03:04:18', 1),
	(246, 244, 'Correct answer: ✅ 2\n\nTo achieve 99.99% availability for Azure Virtual Machines in Microsoft Azure, you must deploy the VMs across multiple Availability Zones using Azure Availability Zones.\n\nMinimum requirements for 99.99% SLA\n	Virtual Machines: 2\n	Availability Zones: 2\n\nWhy 2 zones?\n	Each Availability Zone is a separate physical datacenter within an Azure region.\n	Deploying VMs in at least two zones protects the application if one datacenter fails.\n	Azure guarantees 99.99% uptime when VMs are distributed across zones.\n ', '2026-03-12 03:04:18', 1),
	(247, 245, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, data stored in an Azure Storage account is automatically replicated at least three times.\n\nWhy?\nBy default, Azure uses Locally Redundant Storage which:\n	Keeps 3 copies of your data\n	Stores them within a single datacenter in the same region\n	Protects against disk or hardware failures\n\nOther replication options (even more copies)\n\nAzure also offers:\n	Zone-Redundant Storage – copies across multiple availability zones\n	Geo-Redundant Storage – copies to another region\n	Read-Access Geo-Redundant Storage – geo replication with read access\n\nBut the minimum is always three copies.\n ', '2026-03-12 03:04:18', 1),
	(248, 246, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, data stored in an Azure Storage account is not automatically backed up to another data center by default.\n\nWhy?\nThe default replication option is Locally Redundant Storage, which:\n	Keeps 3 copies of the data\n	Stores them within the same data center in the same region\n	Does not replicate to another Azure data center\n\nReplication to another data center only happens if you choose:\n	Geo-Redundant Storage\n	Read-Access Geo-Redundant Storage\n	Geo-Zone-Redundant Storage\n\nThese options replicate data to a secondary Azure region.\n ', '2026-03-12 03:04:18', 1),
	(249, 247, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, an Azure Storage account does not have a limit of 2 TB or one million files.\n\nActual limits\n	Azure Storage accounts can store petabytes (PBs) of data.\n	They can support millions or even billions of files/objects, depending on the storage service (Blob, Files, Tables, or Queues).\n\nFor example:\n	Azure Blob Storage can store massive amounts of unstructured data such as files, images, and backups.\n	Individual blobs can be up to hundreds of terabytes in size.\n ', '2026-03-12 03:04:18', 1),
	(250, 248, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, Availability Zones are not available in every Azure region.\n\nAzure Availability Zones are physically separate datacenters within a region, but only certain Azure regions support them.\n\nThis means:\n	Some regions have 3 availability zones.\n	Some regions do not support availability zones at all.\nTherefore, even if you deploy resources in every Azure region, you cannot implement availability zones in all of them.\n ', '2026-03-12 03:04:18', 1),
	(251, 249, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, North America is not represented by a single region. Instead, it contains multiple Azure regions.\n\nExamples of Azure regions in North America\n	East US\n	East US 2\n	Central US\n	West US\n	West US 2\n	Canada Central\n\nAzure divides the world into many regions so organizations can deploy resources closer to users and ensure high availability and compliance.\n ', '2026-03-12 03:04:18', 1),
	(252, 250, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, each Azure Region is made up of multiple datacenters.\n\nWhy multiple datacenters?\nHaving several datacenters in a region helps Azure provide:\n	High availability\n	Fault tolerance\n	Scalability\nIn some regions, these datacenters are organized into Azure Availability Zones, which are physically separate locations with independent power, cooling, and networking.', '2026-03-12 03:04:18', 1),
	(253, 251, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, data transfers between services in different regions are not free.\n\nExplanation\n	Inbound data transfers (data going into Azure from the internet) are usually free.\n	Outbound data transfers (data leaving Azure, including between regions) incur charges.\n	Data transfer within the same region is generally free.\n ', '2026-03-12 03:04:35', 1),
	(254, 252, 'Correct answer: ✅ Azure Service Health\n\nExplanation\n\nIn Microsoft Azure, Azure Service Health is used to monitor the health of your Azure services and resources and to receive alerts about planned maintenance, outages, or other issues.\n\nwhy not others:\n	Azure Monitor – Collects metrics and logs from your resources; used for performance monitoring and alerting on your application or resources, not for Microsoft’s maintenance notifications.\n\n	Azure Advisor – Gives recommendations to optimize cost, performance, security, and reliability, not maintenance alerts.\n\n	Microsoft Trust Center – Provides information about compliance, security, and privacy, not operational notifications.\n ', '2026-03-12 03:04:35', 1),
	(255, 253, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, a Windows Virtual Desktop (now called Azure Virtual Desktop) session host can run multiple versions of Windows, not just Windows 10.\n\nSupported operating systems\n	Windows 10 Enterprise multi-session (optimized for virtual desktops)\n	Windows 10 Enterprise\n	Windows 11 Enterprise\n	Windows Server versions (like Windows Server 2019/2022)\n\nKey point\nThe session host is flexible and supports both client OS (Windows 10/11) and server OS for hosting multiple users.\n', '2026-03-12 03:04:35', 1),
	(256, 254, 'Correct answer: ❌ No.\n\nIn Azure Virtual Desktop, a host pool can contain multiple session hosts, and each session host can support multiple simultaneous user sessions.\n\nKey points:\n	Session hosts are VMs running Windows 10/11 Enterprise multi-session or Windows Server.\n	Each session host can handle multiple users at the same time (depending on VM size and resources).\n	Therefore, a host pool with 20 session hosts can support many more than 20 simultaneous users.\n\nExample:\nIf each session host supports 10 concurrent sessions, a pool of 20 hosts can support 200 simultaneous users.\n ', '2026-03-12 03:04:35', 1),
	(257, 255, 'Correct answer: ✅ Yes.\n\nIn Azure Virtual Desktop (formerly Windows Virtual Desktop), you can provide both:\n	Desktop virtualization – Full Windows desktops to users, allowing them to access a complete virtual desktop environment.\n	App virtualization – Individual Windows applications streamed to users without giving them a full desktop.\n	This flexibility allows organizations to deliver either full desktops or specific apps depending on user needs.\n ', '2026-03-12 03:04:35', 1),
	(258, 256, 'Correct answer: ✅ The Azure Total Cost of Ownership (TCO) calculator\n\nExplanation:\n\n✅ Azure TCO Calculator – Estimates cost savings and total cost of ownership when migrating on-premises workloads (like Microsoft SQL Server) to Azure. It includes factors like:\n	Hardware costs\n	Software licensing\n	Electricity and cooling\n	IT personnel\n\n❌ Azure Migrate: Server Assessment – Assesses your on-premises servers for migration readiness, sizing, and dependency mapping, but does not calculate electricity cost savings.\n\n❌ Database Migration Assistant – Helps assess and migrate SQL databases to Azure, focusing on compatibility and feature recommendations, not costs.\n\n❌ Azure Pricing Calculator – Estimates Azure service costs, but doesn’t calculate on-premises vs. Azure cost savings.\n ', '2026-03-12 03:04:35', 1),
	(259, 257, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, Availability Zones are designed to protect Azure resources, including virtual machines, from datacenter failures.\n\nKey points:\n	Each Availability Zone is a physically separate datacenter within the same Azure region.\n	Deploying VMs across two or more zones ensures that if one datacenter fails, the other VMs continue running.\n	Azure guarantees 99.99% SLA for VMs when deployed across Availability Zones.\n ', '2026-03-12 03:04:35', 1),
	(260, 258, 'Correct answer: ❌ No.\n\nAvailability Zones in Microsoft Azure protect resources like Azure Virtual Machines from datacenter-level failures within a single region, not from a full region failure.\n\n	Availability Zones: Separate physical datacenters inside the same region.\n	They protect against power, cooling, or networking failures in one datacenter.\n	If the entire region goes down, all zones in that region could be affected.\n\nTo protect against a region failure, you should use:\n	Cross-region replication\n	Azure Region Pairs\n	Disaster recovery solutions like Azure Site Recovery\n ', '2026-03-12 03:04:35', 1),
	(261, 259, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, Availability Zones can be used to protect Azure managed disks from datacenter failures.\n\nHow it works:\n	Azure Managed Disks can be zonal or zone-redundant (ZRS).\n	Zonal disks are associated with a specific Availability Zone.\n	Zone-Redundant Storage (ZRS) disks automatically replicate your managed disk across multiple zones within a region.\n\nIf one datacenter fails, the disk remains available in another zone.\n ', '2026-03-12 03:04:35', 1),
	(262, 260, 'Correct answer: ✅ No.\n \nIn Microsoft Azure, an Azure subscription has only one Account Administrator.\n\nKey points:\nThe Account Administrator:\n	Is the person who owns the subscription and handles billing.\n	Can change service settings and assign other roles.\n\nYou can have multiple users with other roles (like Service Administrator or Owner/Contributor via RBAC) but only one Account Administrator exists per subscription.', '2026-03-12 03:04:35', 1),
	(263, 261, 'Correct answer: ❌ No.\n\nAn Azure subscription can be managed using different types of identities, not only a Microsoft account.\n\nYou can manage an Azure subscription with:\n	Microsoft accounts (e.g., Outlook, Hotmail, Live)\n	Work or school accounts from Microsoft Entra ID (formerly Azure Active Directory)\n\nFor example:\n	A personal Azure subscription might use a Microsoft account.\n	An organization’s Azure subscription usually uses a work or school account through Microsoft Entra ID.\n ', '2026-03-12 03:05:08', 1),
	(264, 262, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, the hierarchy works like this:\n	Management Group → Subscription → Resource Group → Resources\n\nKey rule:\n	A Resource Group belongs to only one Subscription.\n	It cannot contain multiple subscriptions.\n\nHowever:\n	One Subscription can contain multiple Resource Groups.\n	Each Resource Group can contain multiple resources (VMs, storage accounts, databases, etc.).\n ', '2026-03-12 03:05:08', 1),
	(265, 263, 'Correct answer: ✅ Yes.\n\nTo sign in to a Windows 10 computer using Microsoft Entra ID credentials, the device must be joined to Microsoft Entra ID (formerly Azure Active Directory).\n\nThis process is called Azure AD Join.\n\nWhy this is required:\n	The device needs to be registered and trusted by **Microsoft Entra ID.\n	Only then can users authenticate with their work or school account to log in to Windows 10.\n ', '2026-03-12 03:05:08', 1),
	(266, 264, 'Correct answer: ❌ No.\n\nIn Microsoft Entra ID, users are not organized using resource groups.\nUsers and groups are managed inside Microsoft Entra ID (identity management).\nResource groups are used in Microsoft Azure to organize Azure resources like virtual machines, storage accounts, and databases.\n\nSummary:\n	Users → Managed in Microsoft Entra ID\n	Resources → Organized using Resource Groups in Azure\n ', '2026-03-12 03:05:08', 1),
	(267, 265, 'Correct answer: ✅ Yes.\n\nMicrosoft Entra ID groups support dynamic membership rules.\n\nDynamic membership allows users or devices to be automatically added or removed from a group based on rules you define.\n\nExample\n	You can create a rule like:\n	All users where department = Sales\n	All devices where OS = Windows\n	When a new user matches the rule, they are automatically added to the group without manual action.\n\nThis feature helps automate:\n	Access management\n	Application assignments\n	Policy enforcement\n ', '2026-03-12 03:05:08', 1),
	(268, 266, 'Correct answer: ✅ Deploy the virtual machines to two or more availability zones. & Deploy the virtual machines to two or more regions\n \nTo keep services available if a single data center fails, you must use solutions that distribute VMs across separate physical infrastructure within a region.\n\n✅ Deploy the virtual machines to two or more availability zones\n	Correct.\n	Each zone is a separate datacenter, so if one fails, the others continue running.\n\n✅ Deploy the virtual machines to two or more regions\n	Also valid in many practice questions.\n	Regions contain multiple datacenters, so deploying in different regions also ensures availability if one datacenter fails (and even protects against regional failure).\n\nWhy other options are wrong\n	❌ Two or more resource groups\n		Resource groups are logical containers, not infrastructure separation.\n	❌ Deploy to a scale set\n		A scale set does not automatically protect against datacenter failure unless it is explicitly configured across zones.\n', '2026-03-12 03:05:08', 1),
	(269, 267, 'Correct answer: ✅ Yes. \n\nAzure Monitor can monitor the performance of on-premises computers as well as Azure resources.\n\nHow it works\nYou install the Log Analytics agent / Azure Monitor agent on the on-premises machines, which sends performance and log data to Microsoft Azure.\n\nWhat Azure Monitor can track from on-premises machines\n	CPU usage\n	Memory usage\n	Disk performance\n	Network activity\n	Event logs and system logs\nThis allows organizations to monitor both cloud and on-premises environments from a single monitoring platform.\n ', '2026-03-12 03:05:08', 1),
	(270, 268, 'Correct answer: ✅ Yes.\n\nAzure Monitor can monitor the performance of on-premises computers as well as Azure resources.\n\nHow it works\n	You install the Log Analytics agent / Azure Monitor agent on the on-premises machines, which sends performance and log data to Microsoft Azure.\n	What Azure Monitor can track from on-premises machines\n	CPU usage\n	Memory usage\n	Disk performance\n	Network activity\n	Event logs and system logs\n\nThis allows organizations to monitor both cloud and on-premises environments from a single monitoring platform.\n ', '2026-03-12 03:05:08', 1),
	(271, 269, 'Correct answer: ✅ Yes.\n\nAzure Monitor can trigger alerts based on data collected in an Azure Log Analytics workspace.\n\nHow it works:\n	Log Analytics workspace collects logs and metrics from Azure resources, virtual machines, and even on-premises systems.\n\nAzure Monitor Alerts can be configured to:\n	Watch for specific log query results\n	Trigger notifications or actions when conditions are met\n\nExample:\n	You create a log query to detect CPU usage over 90% for 5 minutes.\n	Azure Monitor triggers an alert and can notify you via email, SMS, or trigger an automation runbook.\n ', '2026-03-12 03:05:08', 1),
	(272, 270, 'Correct answer: ✅ Yes. \n\nAzure Service Health allows administrators to view the health of all Azure services in their environment.\n\nWhat Azure Service Health provides:\n	Azure Status – Global view of the health of all Azure services.\n	Service Issues – Information about outages or incidents affecting your subscribed services.\n	Planned Maintenance – Notifications about upcoming maintenance that might affect your resources.\n	Health Alerts – Ability to set up alerts for service issues affecting your resources.\n\nThis helps admins stay informed and take action quickly when issues occur.', '2026-03-12 03:05:08', 1),
	(273, 271, 'Correct answer: ✅ Yes. \n\nIn Azure Service Health, an administrator can create alert rules to be notified when:\n	An Azure service incident occurs (service failure/outage)\n	A planned maintenance event is scheduled\n	Health advisories affect resources\n\nThese alerts are typically configured through Azure Monitor alert rules, which can send notifications via:\n	Email 📧\n	SMS 📱\n	Push notifications\n	Webhooks / ITSM integrations\n\nSo if an Azure service fails or has an outage, administrators can receive alerts automatically.\n ', '2026-03-12 03:05:20', 1),
	(274, 272, 'Correct answer: ❌ No.\n\nAzure Service Health is a monitoring and notification tool. It allows administrators to:\n	View service incidents and outages\n	Receive alerts about service failures\n	Track planned maintenance\n	Get health advisories\n\nHowever, it cannot prevent a service failure. Azure service outages are handled by Microsoft at the platform level, not by administrators using Service Health.\n\nAdministrators can only monitor and respond, not stop the failure itself.\n', '2026-03-12 03:05:20', 1),
	(275, 273, 'Correct answer: ✅ Monitor.\n\nTo monitor the health of Azure services, you use the Monitor blade in the Microsoft Azure Portal.\n\nInside the Azure Monitor section, you can access Azure Service Health, which shows:\n	Service outages\n	Planned maintenance\n	Health advisories affecting your Azure resources\n\nWhy the others are incorrect\n	Subscriptions – Used to manage billing and subscription settings.\n	Marketplace – Used to deploy applications and services from the Azure marketplace.\n	Advisor – Provides optimization recommendations (cost, performance, reliability), not service health monitoring.\n', '2026-03-12 03:05:20', 1),
	(276, 274, 'Correct answer: ✅ Marketplace.\n\nIn the Microsoft Azure Portal, you use the Marketplace blade to browse available virtual machine images such as:\n	Ubuntu\n	Windows Server\n	Red Hat Enterprise Linux\n	Other preconfigured VM images and applications\n\nThe Azure Marketplace provides a catalog of images, services, and solutions that you can deploy directly into your Azure environment.\n\nWhy the others are incorrect\n	Monitor – Used for metrics, logs, and alerts.\n	Subscriptions – Used for billing and subscription management.\n	Advisor – Provides recommendations to improve cost, security, and performance.\n ', '2026-03-12 03:05:20', 1),
	(277, 275, 'Correct answer: ✅ Advisor.\n\nIn the Microsoft Azure Portal, you use Azure Advisor to view security recommendations.\n\nAzure Advisor analyzes your Azure resources and provides recommendations in areas such as:\n	🔒 Security\n	💰 Cost optimization\n	⚡ Performance\n	🛡 Reliability\n	🧩 Operational excellence\n\nWhy the others are incorrect\n	Monitor – Used for metrics, logs, and alerts.\n	Subscriptions – Used to manage billing and subscription settings.\n	Marketplace – Used to deploy apps and VM images.\n', '2026-03-12 03:05:20', 1),
	(278, 276, 'Correct answer: ❌ No.\n\nAzure Advisor provides recommendations to improve areas such as:\n	Cost 💰\n	Performance ⚡\n	Security 🔒\n	Reliability 🛡\n	Operational excellence\n\nIt may recommend enabling backups for virtual machines that are not protected, but it does not generate a list of VMs that are already protected by backup.\n\nTo view which virtual machines are protected, you would check Azure Backup in the Microsoft Azure Portal.\n ', '2026-03-12 03:05:20', 1),
	(279, 277, 'Correct answer: ❌ No. \n\nImplementing the security recommendations from Azure Advisor will increase, not decrease, your company\'s secure score.\n\nThe secure score is measured in Microsoft Defender for Cloud, which evaluates how well your Azure resources follow security best practices. \n\nWhen you apply recommended security improvements—such as enabling encryption, configuring network security, or enabling backups—your secure score improves.\n	Following security recommendations ➜ Improves security posture\n	Improved security posture ➜ Higher secure score\n', '2026-03-12 03:05:20', 1),
	(280, 278, 'Correct answer: ❌ No.\n\nYou are not required to implement the security recommendations from Azure Advisor within 30 days to maintain Microsoft support.\n\nAzure Advisor only provides best-practice recommendations to help improve:\n	Security 🔒\n	Performance ⚡\n	Reliability 🛡\n	Cost optimization 💰\n	Operational excellence\n\nThese recommendations are optional. They help improve your environment but are not mandatory for maintaining Microsoft support.\n ', '2026-03-12 03:05:20', 1),
	(281, 279, 'Correct answer: ✅ Azure Monitor.\n\nYou can use Azure Monitor to automatically send alerts when specific events occur, such as when an administrator stops an Azure virtual machine.\n\nWith Azure Monitor you can:\n	Create alert rules based on activity logs\n	Monitor resource state changes\n	Send notifications via email, SMS, or webhook\n\nFor example, you can create an alert triggered by a Stop Virtual Machine event recorded in the Azure Activity Log in the Microsoft Azure Portal.\n\nWhy the others are incorrect\n	Azure Advisor – Provides optimization recommendations, not activity alerts.\n	Azure Service Health – Alerts about Azure platform service issues, not admin actions.\n	Azure Network Watcher – Used for network monitoring and diagnostics.\n', '2026-03-12 03:05:20', 1),
	(282, 280, 'Correct answer: ✅ Use Bash in Azure Cloud Shell , Use PowerShell in Azure Cloud Shell, Use the Azure portal\n \nUse Bash in Azure Cloud Shell ✅\n	You can open Azure Cloud Shell in a browser on your Android tablet and use Bash commands (Azure CLI) to create a virtual machine.\n\nUse PowerShell in Azure Cloud Shell ✅\n	Similarly, PowerShell in Cloud Shell lets you run Azure PowerShell commands to create a VM.\n\nUse the Azure portal ✅\n	The Microsoft Azure Portal is fully accessible from a tablet browser. You can navigate to Virtual Machines → Create and configure a new VM.\n\nWhy the others are incorrect\n	PowerApps portal ❌ – Used for building low-code apps, not managing VMs.\n	Security & Compliance admin center ❌ – Used for Microsoft 365 security and compliance, not Azure VM creation.', '2026-03-12 03:05:20', 1),
	(283, 281, 'Correct answer: No.\n\nAzure Advisor provides recommendations to improve cost, performance, reliability, and security of Azure resources (like VMs, storage, networking, etc.). It analyzes the configuration and usage of those Azure resources to suggest improvements.\n\nHowever, security recommendations for a Microsoft Entra ID tenant are provided through Microsoft Entra ID recommendations, which analyze tenant configuration and identity-related settings to improve security and health.\n ', '2026-03-12 03:14:48', 1),
	(284, 282, 'Correct answer: Yes.\n\nAzure Advisor analyzes how your Azure resources are used and provides recommendations to improve cost, performance, reliability, operational excellence, and security.\n\nFor cost optimization, it can recommend ways to reduce the cost of running resources such as Microsoft Azure virtual machines. Examples include:\n	Shutting down or deleting underutilized VMs\n	Resizing VMs to a smaller, cheaper size if CPU or memory usage is low\n	Purchasing Reserved Instances for long-running workloads\n	Identifying idle resources that still incur charges\n\nThese recommendations help organizations optimize spending on Azure Virtual Machines.\n ', '2026-03-12 03:14:48', 1),
	(285, 283, 'Correct answer: No.\n\nAzure Advisor provides recommendations to help optimize resources in Microsoft Azure across these categories:\n	Cost\n	Performance\n	Reliability\n	Security\n	Operational excellence\n\nHowever, it does not provide recommendations on how to configure the network settings of Azure Virtual Machines (such as IP configuration, subnet configuration, or detailed network interface settings).\n\nThose types of configurations are managed through services like:\n	Azure Virtual Network\n	Azure Network Watcher\n	Network Security Group\n ', '2026-03-12 03:14:48', 1),
	(286, 284, 'Correct answer: ✅ The Azure CLI, the Azure portal, and Azure PowerShell.\n\nSupport engineers using Computer1 (Windows 10) can manage resources in Microsoft Azure using multiple management tools:\nAzure portal\n	Web-based interface\n	Accessible from any browser on Windows 10\nAzure CLI\n	Command-line tool that runs on Windows, macOS, and Linux\n	Can be installed on Windows 10\nAzure PowerShell\n	PowerShell module used to manage Azure resources\n	Works directly in Windows PowerShell or PowerShell Core\n\nSince all three tools can be used from a Windows 10 computer, the correct option is:\n\n✔ The Azure CLI, the Azure portal, and Azure PowerShell.\n\n💡 Exam tip (AZ-900):\n	Main Azure management tools to remember:\n	Azure Portal (GUI)\n	Azure CLI (cross-platform command line)\n	Azure PowerShell (PowerShell modules)\n	Azure Cloud Shell (browser-based CLI/PowerShell).\n ', '2026-03-12 03:14:49', 1),
	(287, 285, 'Correct answer: ✅ The Azure CLI, the Azure portal, and Azure PowerShell.\n\nSupport engineers using Computer2 (Ubuntu) can manage Microsoft Azure using the following tools:\n\nAzure portal\n	Web-based management interface\n	Works in any browser, including those on Ubuntu\nAzure CLI\n	Cross-platform command-line tool\n	Fully supported on Linux distributions like Ubuntu\nAzure PowerShell\n	Runs using PowerShell Core, which is supported on Linux (including Ubuntu)\n\nSince all three tools are supported on Ubuntu, the correct option is:\n\n✔ The Azure CLI, the Azure portal, and Azure PowerShell.\n\n💡 Quick exam rule (AZ-900):\nBoth Windows and Linux can use:\n	Azure Portal\n	Azure CLI\n	Azure PowerShell (via PowerShell Core).\n ', '2026-03-12 03:14:49', 1),
	(288, 286, 'Correct answer: ✅ The Azure CLI, the Azure portal, and Azure PowerShell.\n\nSupport engineers using Computer3 (macOS Mojave) can manage resources in Microsoft Azure using these tools:\nAzure portal\n	Browser-based interface\n	Works on any operating system, including macOS\nAzure CLI\n	Cross-platform command-line tool\n	Supported on macOS\n\nAzure PowerShell\n	Runs on PowerShell Core, which is supported on macOS\n\nSince all three tools work on macOS, the correct option is:\n✔ The Azure CLI, the Azure portal, and Azure PowerShell.\n\n💡 AZ-900 exam shortcut:\nAll three major operating systems (Windows, Linux, macOS) can use:\n	Azure Portal\n	Azure CLI\n	Azure PowerShell.\n', '2026-03-12 03:14:49', 1),
	(289, 287, 'Correct answer: ✅ Microsoft 365 Admin Center.\n\nMicrosoft Compliance Manager is a feature within the Microsoft 365 compliance solutions that helps organizations:\n	Assess compliance posture\n	Manage regulatory requirements\n	Track compliance activities and improvement actions\n	It is accessed through the Microsoft 365 Admin Center (specifically via the Microsoft Purview compliance portal).\n\nWhy the other options are incorrect:\n	Microsoft Entra ID admin center – Used for identity and access management.\n	Azure portal – Used to manage Azure resources.\n	Microsoft Service Trust Portal – Provides compliance documentation and audit reports, not the Compliance Manager tool itself.\n ', '2026-03-12 03:14:49', 1),
	(290, 288, 'Correct answer: ✅ A computer that runs macOS and has PowerShell Core 6.0 installed, A computer that runs Windows 10 and has the Azure PowerShell module installed, A computer that runs Chrome OS and uses Azure Cloud Shell.\n\nA computer that runs macOS and has PowerShell Core 6.0 installed\n	PowerShell Core on macOS can run Azure PowerShell scripts. ✅\n\nA computer that runs Windows 10 and has the Azure PowerShell module installed\n	Standard environment for running Azure PowerShell scripts. ✅\n\nA computer that runs Chrome OS and uses Azure Cloud Shell\n	Even though Chrome OS cannot natively run PowerShell, Azure Cloud Shell provides a browser-based PowerShell environment, so you can run Azure PowerShell scripts from it. ✅\n\nWhy Linux + Azure PowerShell module is not included\n\nWhile technically possible, the question is probably assuming common exam environments, and Cloud Shell is considered a preferred cross-platform solution for running PowerShell scripts without local module installation.\n\nLinux with CLI alone doesn’t work for PowerShell scripts, only for CLI commands.\n\n✅ Key point\n	Azure Cloud Shell counts as a valid "computer configuration" because it provides PowerShell in a browser on any OS, including Chrome OS.\n', '2026-03-12 03:14:49', 1),
	(291, 289, 'Correct answer: No.\n\nAzure Firewall is a managed network security service that:\n	Filters and inspects inbound and outbound traffic\n	Applies rules for applications, networks, and threats\n	Provides logging and threat intelligence\n\nHowever, Azure Firewall does not encrypt traffic. Encryption of network traffic from Azure to the Internet is typically handled by:\n	HTTPS / TLS for web traffic\n	VPN Gateway or ExpressRoute with encryption for site-to-site connections\n\nSo, Azure Firewall can allow, block, or filter traffic, but it does not automatically encrypt all traffic.\n ', '2026-03-12 03:14:49', 1),
	(292, 290, 'Correct answer: No.\n\nNetwork Security Group (NSG) is a traffic-filtering tool in Microsoft Azure that:\n	Controls inbound and outbound traffic to Azure resources\n	Uses rules based on source/destination IP, port, and protocol\n	Helps secure the network by allowing or denying traffic\n\nImportant:\n	NSGs do not encrypt traffic.\n	Encryption must be handled separately using HTTPS/TLS, VPN, or ExpressRoute with encryption.', '2026-03-12 03:14:49', 1),
	(293, 291, 'Correct answer: No.\n\nRunning Windows Server 2016 on an Azure virtual machine does not automatically encrypt network traffic sent to the Internet.\n\nOutbound traffic from the VM is unencrypted by default.\n\nTo encrypt traffic, you must use technologies such as:\n	HTTPS/TLS for web traffic\n	VPN Gateway or ExpressRoute with encryption for site-to-site connections\n	IPsec or other network-level encryption solutions\n\nSimply using a VM with Windows Server 2016 does not provide automatic Internet traffic encryption.\n ', '2026-03-12 03:28:49', 1),
	(294, 292, 'Correct answer: ✅ Yes.\n\nMicrosoft Defender for Cloud is a cloud security posture management and threat protection service that can:\n	Monitor Azure resources such as VMs, databases, storage accounts, and networks\n	Monitor on-premises resources and resources in other clouds (like AWS or Google Cloud) when connected via the Azure Arc agent\n	Provide security recommendations, threat detection, and alerts for both cloud and on-premises environments\n\nSo, it is designed to provide a unified security view across hybrid environments.\n ', '2026-03-12 03:28:49', 1),
	(295, 293, 'Correct answer: No.\n\nMicrosoft Defender for Cloud has two tiers:\n	Free tier\n		Provides security posture management\n		Gives security recommendations for your Azure resources\n	Standard (paid) tier\n		Adds threat protection for Azure, hybrid, and multi-cloud resources\n\nIncludes features like:\n	Advanced threat detection for VMs, databases, and containers\n	Adaptive application controls\n	File integrity monitoring\n\n💡 Key point: Some features like basic recommendations are free, but advanced threat protection features require a paid plan.\n ', '2026-03-12 03:28:49', 1),
	(296, 294, 'Correct answer: ✅ Yes.\n\nMicrosoft Defender for Cloud allows you to:\n	Assess your environment against regulatory standards such as ISO 27001, NIST, GDPR, HIPAA, and more\n	View regulatory compliance scores for your Azure and hybrid resources\n	Download compliance reports that summarize your environment’s compliance status, including recommendations for improvement\n\nThis feature helps organizations demonstrate compliance to auditors and stakeholders.\n ', '2026-03-12 03:28:49', 1),
	(297, 295, 'Correct answer: ✅ Microsoft Defender for Identity\n\nThe requirement is to monitor threats by using sensors.\n\nMicrosoft Defender for Identity\n	Uses sensors installed on domain controllers to monitor activities\n	Detects identity-based threats like lateral movement, pass-the-hash attacks, and suspicious logins\n	Sends alerts to the security team when malicious activity is detected\n\nWhy the other options are incorrect\n	Azure Monitor – Provides logging and metrics; does not directly use sensors for threat detection.\n	\n	Microsoft Defender for Cloud – Monitors cloud resources and provides security recommendations, but does not use sensors on domain controllers.\n	\n	Microsoft Entra ID Identity Protection – Monitors identity risk and risky sign-ins in the cloud, not via sensors on on-premises systems.\n', '2026-03-12 03:28:49', 1),
	(298, 296, 'Correct answer: ✅ Microsoft Entra ID Identity Protection\n\n\nThe requirement is to enforce Azure Multi-Factor Authentication (MFA) based on a condition.\n\nMicrosoft Entra ID Identity Protection:\n	Allows conditional access policies based on risk signals (e.g., risky sign-ins, unfamiliar locations, or devices)\n	Can require MFA or other actions when conditions are met\n	Helps protect user identities and prevent account compromise\n\nWhy the other options are incorrect\n	Azure Monitor – Collects logs and metrics; does not enforce MFA.\n\n	Microsoft Defender for Cloud – Protects cloud resources; not for identity-based conditional access.\n\n	Microsoft Defender for Identity – Monitors on-premises Active Directory for threats; does not enforce MFA.\n', '2026-03-12 03:28:49', 1),
	(299, 297, 'Correct answer: ✅ Modify a Network Security Group (NSG), Modify an Azure firewall\n\nTo make VM1 accessible from the Internet over HTTP (port 80), you need to allow inbound traffic. There are two primary ways in Azure:\n	Network Security Group (NSG)\n		Controls inbound and outbound traffic to Azure VMs or subnets\n		You can create a rule to allow inbound TCP traffic on port 80 from the Internet\n\n	Azure Firewall\n		Acts as a centralized network security service\n		Can allow or deny traffic at a network level\n		You can configure a rule to permit HTTP traffic to VM1\n\nWhy the other options are incorrect\n	Azure Traffic Manager – Distributes traffic across multiple endpoints; it does not control access to a single VM.\n\n	DDoS protection plan – Provides DDoS attack protection, but does not configure access for HTTP traffic.\n', '2026-03-12 03:28:49', 1),
	(300, 298, 'Correct answer: ✅ Microsoft Defender for Cloud\n\n\nJust-In-Time (JIT) VM access is a security feature that allows you to lock down inbound traffic to Azure virtual machines, while still enabling temporary access when needed.\n\nMicrosoft Defender for Cloud\n	Provides JIT VM access as part of its security management and threat protection features\n	Temporarily opens ports (e.g., RDP, SSH) for a specified time window\n	Helps reduce exposure to attacks\n\nWhy the other options are incorrect\n	Azure Bastion – Provides secure RDP/SSH access over SSL, but does not manage JIT access.\n\n	Azure Firewall – Controls and filters network traffic; does not provide JIT VM access.\n\n	Azure Front Door – Global application delivery and web traffic routing; not for VM access management.\n', '2026-03-12 03:28:49', 1),
	(301, 299, 'Correct answer: ✅ Yes.\n\nNetwork Security Groups (NSGs) in Microsoft Azure are used to filter network traffic to and from Azure resources.\n\nNSGs can be associated with:\n	Individual network interfaces (NICs) of VMs\n	Subnets within a virtual network\n\nWhen you associate an NSG with a subnet, all resources in that subnet inherit the NSG rules, which allows you to centrally control traffic for multiple VMs.\n ', '2026-03-12 03:28:49', 1),
	(302, 300, 'Correct answer: ✅ No.\n\nNetwork Security Groups (NSGs) in Microsoft Azure are used to filter network traffic, but they cannot be associated directly with an entire virtual network.\n\nNSGs can only be associated with:\n	Individual network interfaces (NICs) of VMs\n	Subnets within a virtual network\n\nThis allows traffic filtering at the subnet or VM level, but there is no direct NSG association at the virtual network level.', '2026-03-12 03:28:49', 1),
	(303, 301, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, a Network Security Group (NSG) is used to control inbound and outbound network traffic.\n\nAn NSG can be associated with:\n	A subnet – applies the rules to all resources in that subnet\n	A network interface (NIC) – applies the rules specifically to a single VM\n\nWhen an NSG is attached to a network interface, the rules apply directly to the virtual machine connected to that NIC, allowing more granular traffic control.\n ', '2026-03-14 08:55:25', 1),
	(304, 302, 'Correct answer: ✅ Network Security Group (NSG).\n\nTo allow connections to TCP port 8080 on a virtual machine in Microsoft Azure, you must configure an inbound rule in a Network Security Group (NSG).\n\nNSGs control inbound and outbound traffic to Azure resources.\n\nYou can create a rule to allow TCP port 8080 from the required source (for example, the Internet).\n\nWhy the other options are incorrect:\n	Virtual network gateway – Used for VPN or ExpressRoute connectivity, not port filtering.\n	Virtual network – Defines the network address space, but does not control port access.\n	Route table – Controls traffic routing, not whether a port is allowed or blocked.\n ', '2026-03-14 08:55:25', 1),
	(305, 303, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, Role-Based Access Control (RBAC) allows administrators to manage access to resources.\n\nAzure provides:\n	Built-in roles (e.g., Owner, Contributor, Reader)\n	Custom roles that you can create yourself\n	With custom roles, you can define specific permissions and assign them to users, groups, or service principals to control exactly what actions they can perform.\n\nThese custom roles are created and managed through Azure Role-Based Access Control.\n ', '2026-03-14 08:55:25', 1),
	(306, 304, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, access to resources is controlled using Azure Role-Based Access Control (RBAC).\n\nA single user account can be assigned multiple roles at different scopes, such as:\n	Management group\n	Subscription\n	Resource group\n	Individual resource\n\nFor example, a user could have:\n	Reader role at the subscription level\n	Contributor role at a specific resource group\n\nAzure combines all assigned permissions, allowing the user to perform actions allowed by any of their roles.\n ', '2026-03-14 08:55:25', 1),
	(307, 305, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, access to resources is managed using Azure Role-Based Access Control (RBAC).\n\nA resource group can have multiple users assigned the Owner role.\n\nThe Owner role allows users to:\n	Manage all resources in the resource group\n	Grant access to others\n	\nAzure does not limit the number of users that can be assigned the Owner role for a resource group.\n ', '2026-03-14 08:55:25', 1),
	(308, 306, 'Correct answer: ✅ Azure Sentinel.\n\nTo collect and automatically analyze security events from Microsoft Entra ID, you should use Azure Sentinel.\n\nAzure Sentinel is a cloud-native SIEM and SOAR solution that:\n	Collects security logs and events from multiple sources\n	Integrates directly with Microsoft Entra ID\n	Uses analytics and automation to detect threats\n	Helps with incident investigation and response\n\nWhy the other options are incorrect:\n	Azure Synapse Analytics – Used for big data analytics, not security monitoring.\n	Microsoft Entra Connect – Synchronizes on-premises Active Directory with Entra ID.\n	Azure Key Vault – Stores and manages keys, secrets, and certificates.\n', '2026-03-14 08:55:25', 1),
	(309, 307, 'Correct answer: ✅ Azure Activity Log\n\nAzure Activity Log records all management operations performed on resources in Microsoft Azure.\n\nUsing the Activity Log, you can see:\n	Who performed an action\n	What action was performed\n	When the action occurred\n	Which resource was affected\n\nFor example, you can view which user stopped (powered off) a virtual machine within the last 14 days.\n\nWhy the other options are incorrect\n\nAzure Access Control (IAM) – Manages role assignments and permissions, not activity history.\n\nAzure Event Hubs – Used for big data streaming and event ingestion, not resource activity tracking.\n\nAzure Service Health – Provides information about Azure service outages and maintenance, not user actions.\n', '2026-03-14 08:55:25', 1),
	(310, 308, 'Correct answer: ✅ Azure Sentinel.\n\nAzure Sentinel is Microsoft’s cloud-native SIEM (Security Information and Event Management) and SOAR solution in Microsoft Azure.\n\nIt allows organizations to:\n	Collect security data from users, devices, applications, and infrastructure\n	Detect threats using built-in analytics and AI\n	Investigate incidents using dashboards and hunting tools\n	Automate responses to security events\n\nWhy the other options are incorrect\n	Azure Analysis Services – Data analytics and business intelligence service.\n	Microsoft Purview Information Protection – Used to classify and protect sensitive data, not SIEM.\n	Azure Cognitive Services – Provides AI APIs like vision, speech, and language.\n ', '2026-03-14 08:55:26', 1),
	(311, 309, 'Correct answer: ✅ Microsoft Purview Information Protection\n\nTo automatically add a watermark to Microsoft Word documents that contain credit card information, you need data classification and protection capabilities, which are provided by Microsoft Purview Information Protection.\n\nThis service can:\n	Detect sensitive information such as credit card numbers\n	Automatically apply protection actions (labels, encryption, watermarks)\n	Work with Microsoft Office documents like Word, Excel, and PowerPoint\n\nWhy the other options are incorrect\n	No change is needed – Azure Policy is used to enforce resource governance in Azure, not document protection.\n\n	DDoS protection – Protects against distributed denial-of-service attacks, unrelated to document security.\n\n	Microsoft Entra ID Identity Protection – Focuses on identity risk detection, not document labeling or watermarking.\n ', '2026-03-14 08:55:26', 1),
	(312, 310, 'Correct answer: ✅ continues to function normally.\n\nThe Not Allowed Resource Type policy in Microsoft Azure prevents the creation of new resources of the specified type in the scope where the policy is assigned.\n\nExisting resources (like VNET1) are not affected by the policy and continue to function normally.\n\nAzure Policy does not automatically delete, move, or make existing resources read-only unless a specific remediation task is configured.\n\nKey point:\n	Azure Policy is primarily preventive (blocking new non-compliant resources) or advisory (for compliance reporting). Existing resources remain operational unless you take manual action.', '2026-03-14 08:55:26', 1),
	(313, 311, 'Correct answer: ✅ No.\n\nMicrosoft Entra ID (formerly Azure Active Directory) does not support creating Group Policies.\n\nGroup Policy Objects (GPOs) are a feature of on-premises Active Directory, used to manage settings for Windows computers in a domain.\n\nIn cloud environments with Entra ID, similar device management and configuration is typically done using:\n	Microsoft Intune\n	Configuration profiles and device compliance policies\n\nTherefore, Group Policies cannot be created in Microsoft Entra ID.\n', '2026-03-14 08:56:02', 1),
	(314, 312, 'Correct answer: ✅ Yes.\n\nMicrosoft Entra ID allows Windows 10 devices to be joined directly to the cloud directory. This is called Azure AD Join (now Entra ID Join).\n\nWhen a Windows 10 device is joined to Entra ID, it can:\n	Allow users to sign in with their Entra ID account\n	Enable Single Sign-On (SSO) to cloud apps\n	Be managed with services like Microsoft Intune\n	Apply security and compliance policies\n\nThis is commonly used in cloud-first or hybrid environments.\n ', '2026-03-14 08:56:02', 1),
	(315, 313, 'Correct answer: ✅ No.\n\nMicrosoft Entra ID supports device join mainly for Windows devices (such as Windows 10/11).\n\nAndroid devices cannot be joined directly to Entra ID. Instead, they can be:\n	Registered in Entra ID\n	Managed through Microsoft Intune for mobile device management (MDM)\n\nSo Android devices are typically registered and managed, not joined like Windows devices.\n ', '2026-03-14 08:56:02', 1),
	(316, 314, 'Correct answer: ✅ Microsoft Online Services Privacy Statement\n\nThe Microsoft Online Services Privacy Statement explains:\n	What data Microsoft collects and processes\n	How Microsoft processes that data\n	\nWhy the data is processed (the purpose)\n	It focuses specifically on data privacy and handling for Microsoft online services.\n\nWhy the other options are incorrect\n	Microsoft Online Services Terms – Defines legal terms and conditions for using Microsoft online services.\n\n	Microsoft Online Service Level Agreement – Describes uptime guarantees and service credits if service levels aren’t met.\n\n	Online Subscription Agreement for Microsoft Azure – Governs the subscription contract and usage terms for Azure services.\n ', '2026-03-14 08:56:02', 1),
	(317, 315, 'Correct answer: ✅ collection of policy definitions.\n\nIn Azure Policy, an initiative definition (also called a policy set) is a group of multiple policy definitions that are bundled together to achieve a broader governance goal.\n\nThis allows organizations to:\n	Apply several related policies at once\n	Track compliance for multiple policies as a single initiative\n	Enforce organizational standards and regulatory requirements\n\nFor example, an initiative could include policies that:\n	Restrict allowed locations\n	Enforce tagging\n	Limit resource types\n\nWhy the other options are incorrect\n	Collection of policy definition assignments – Assignments apply policies but are not what an initiative contains.\n\n	Group of Azure Blueprints definitions – Azure Blueprints is a separate governance service.\n\n	Group of RBAC role assignments – Azure Role-Based Access Control manages permissions, not policy grouping.\n', '2026-03-14 08:56:02', 1),
	(318, 316, 'Correct answer: ✅ Azure Policies\n\nAzure Policy is specifically designed to:\n	Enforce organizational standards\n	Assess and ensure compliance\n	Apply rules across multiple subscriptions, resource groups, or even management groups\n\nWhy not the others?\n	Resource groups → Scope containers for resources; they don’t manage compliance.\n	Management groups → Help organize subscriptions, but they don’t enforce compliance by themselves (though policies can be assigned at this level).\n	Azure App Service plans → Related to hosting web apps; completely unrelated to compliance.\n ', '2026-03-14 08:56:02', 1),
	(319, 317, 'Correct answer: ✅ Yes\n\nThe General Data Protection Regulation (GDPR) does define data protection and privacy rules for individuals within the European Union (EU) and the European Economic Area (EEA). It governs how organizations collect, process, store, and protect personal data.\n\nIf you’d like, I can also explain its key principles or how it applies to cloud services like Azure!\n ', '2026-03-14 08:56:02', 1),
	(320, 318, 'Correct answer: ✅ Yes\n\nThe General Data Protection Regulation (GDPR) applies not only to organizations located in the European Union, but also to organizations anywhere in the world that:\n	Offer goods or services to individuals in the EU, or\n	Monitor the behavior of individuals in the EU\n\nThis means companies outside the EU must still comply with GDPR if they handle the personal data of EU residents.\n ', '2026-03-14 08:56:02', 1),
	(321, 319, 'Correct answer: ✅ Yes\n\nMicrosoft Azure provides tools, services, and compliance certifications that help organizations build infrastructure that supports compliance with the General Data Protection Regulation (GDPR).\n\nAzure offers features such as:\n	Data encryption\n	Access control and identity management\n	Compliance certifications and documentation\n	Security monitoring and auditing tools\n\nHowever, Azure provides the capabilities, while the organization using Azure is responsible for configuring and operating the environment correctly to meet GDPR requirements.\n ', '2026-03-14 08:56:02', 1),
	(322, 320, 'Correct answer: ✅ Yes\n\nAzure Blueprints support Resource Manager (ARM) templates as artifacts, allowing you to package and deploy infrastructure declaratively alongside policies, role assignments, and other components.\n\nYou add them directly in the blueprint definition via the Azure portal, CLI, or PowerShell, specifying parameters and deployment order for consistent environment provisioning.​\n\nThis integration enables governed, repeatable deployments across subscriptions while tracking compliance and lifecycle status.\n ', '2026-03-14 08:56:02', 1),
	(323, 321, 'Correct answer: ❌ No.\n\nYou cannot assign an Azure Blueprints blueprint directly to a Resource Group.\n\nHow it works\nAzure Blueprints are assigned at higher scopes:\n	✅ Management Group\n	✅ Subscription\n\nWhen a blueprint is assigned at one of these levels, it can create or configure Resource Groups and resources inside them as part of the deployment.\n\nKey idea\n	Blueprints define governance (policies, role assignments, ARM templates, etc.) for an entire subscription or management group, not for a single Resource Group.\n ', '2026-03-14 08:56:38', 1),
	(324, 322, 'Correct answer: ✅ Yes.\n\nWith Azure Blueprints, you can include Role Assignments as one of the blueprint artifacts.\n\nWhat this means\nA blueprint can automatically:\n	Assign Azure Policies\n	Deploy ARM templates\n	Create Resource Groups\n	Grant permissions using Role-Based Access Control (RBAC)\n\nSo when the blueprint is assigned to a subscription or management group, it can grant specific permissions to users, groups, or service principals for resources.\n ', '2026-03-14 08:56:38', 1),
	(325, 323, 'Correct answer: ❌ No.\n\nAzure China is not operated directly by Microsoft.\n\nWho operates it?\n	Azure China is operated by 21Vianet, a Chinese company that runs Microsoft cloud services in China under a partnership.\n\nWhy?\n	Chinese regulations require foreign cloud providers to work with a local operator to provide cloud services within China.\n ', '2026-03-14 08:56:38', 1),
	(326, 324, 'Correct answer: ✅ Yes.\n\nAzure Government is operated by Microsoft.\n\nAzure Government is a special cloud environment designed for:\n	U.S. government agencies\n	Defense organizations\n	Government contractors\n\nIt is physically isolated from the public Azure cloud and operated directly by Microsoft to meet strict U.S. compliance and security requirements.\n ', '2026-03-14 08:56:38', 1),
	(327, 325, 'Correct answer: ✅ Yes.\n\nAzure Government is available only to U.S. government agencies and their approved partners, such as contractors that work with the government.\n\nWho can use it\n	Access is limited to organizations that meet strict eligibility requirements, including:\n	U.S. federal, state, local, or tribal government agencies\n	Government contractors handling government data\n	Organizations sponsoring government workloads\n\nThese customers must go through a validation process by Microsoft before they can access the Azure Government cloud.\n', '2026-03-14 08:56:38', 1),
	(328, 326, 'Correct answer: Yes\n\nAzure does allow multiple locks, even of the same type, to be placed on the same resource.\nSo a resource can have multiple Delete locks at the same time.\nAzure simply evaluates all locks applied at that scope and any parent scopes.\nIf any of them is a Delete lock, the resource cannot be deleted.\n ', '2026-03-14 08:56:38', 1),
	(329, 327, 'Correct answer: ✅ Yes.\n\nIn Microsoft Azure, locks are inherited down the resource hierarchy.\n\nHow it works:\n	If a lock (like Delete or Read-only) is applied at the Resource Group level, then all resources inside that group automatically inherit the lock.\n\nHierarchy example:\n\n	Subscription\n		↓\n	Resource Group\n		↓\n	Resource\n\nLocks applied at a higher level affect everything below it.\n ', '2026-03-14 08:56:38', 1),
	(330, 328, 'Correct answer: Yes\n\nIn Azure, you can apply multiple locks (e.g., Read-only and Delete) to the same resource. Azure allows more than one lock type to coexist, and the most restrictive lock always applies.\n\nHere’s how they behave together:\n	Read-only lock prevents updates and deletes\n	Delete lock prevents deletes only\n\nIf both are applied, the effective behavior is the Read-only lock, since it is more restrictive.\n ', '2026-03-14 08:56:38', 1),
	(331, 329, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, authorization to access resources is not limited to only users in Microsoft Entra ID.\n\nWho can receive access\nUsing Role-Based Access Control (RBAC), permissions can be assigned to:\n	👤 Users\n	👥 Groups\n	🧩 Service principals (applications)\n	🖥 Managed identities\n\nAll of these identities exist in Microsoft Entra ID, but authorization is not limited to just individual users.\n ', '2026-03-14 08:56:38', 1),
	(332, 330, 'Correct answer: ✅ Yes.\n\nMicrosoft Entra ID (formerly Azure AD) can manage identities from multiple sources, and these identities can be granted access to Microsoft Azure resources.\n\nSupported identity sources\n\nAccess can be provided to identities from:\n	Microsoft Entra ID users and groups\n	Third-party cloud services (via service principals or federated identities)\n	On-premises Active Directory synchronized to Entra ID using tools like Azure AD Connect\n\nOnce these identities exist or are federated in Entra ID, they can be granted permissions through Azure RBAC.', '2026-03-14 08:56:38', 1),
	(333, 331, 'Correct answer: ✅ Yes\n\nMicrosoft Azure provides built-in authentication and authorization services to secure access to resources. These include:\n\n	Authentication: Verifying who you are (using Microsoft Entra ID / Azure AD).\n	Authorization: Controlling what actions a user or identity can perform (using Role-Based Access Control – RBAC).\n\nThese services are integrated into Azure by default to help protect resources.\n ', '2026-03-14 09:07:08', 1),
	(334, 332, 'Correct answer: ✅ Yes\n\nIdentities in an on-premises Active Directory can be synchronized to Microsoft Entra ID (formerly Azure AD) using Azure AD Connect.\n\nThis allows:\n	On-premises users to access Azure resources using the same credentials.\n	Single sign-on (SSO) between on-premises and cloud applications.\n ', '2026-03-14 09:07:08', 1),
	(335, 333, 'Correct answer: ✅ Microsoft Defender for Cloud\n\nMicrosoft Defender for Cloud provides security posture management and regulatory compliance reporting for your Azure environment.\n\nIt allows you to view compliance with standards such as ISO, NIST, and GDPR.\n\nOther options:\n	Azure Advisor: Gives recommendations for cost, performance, and security, but not regulatory compliance reports.\n\n	Azure Analysis Services: Used for data modeling and analytics.\n\n	Azure Monitor: Tracks metrics, logs, and alerts for resources.\n ', '2026-03-14 09:07:08', 1),
	(336, 334, 'Correct answer: ✅ An Azure policy.\n\nAzure Policy is used to enforce rules and compliance across your Azure resources.\n\nYou can create a policy to restrict which regions resources can be deployed in.\n\nOther options:\n	Read-only lock: Prevents changes or deletion of resources, does not restrict locations.\n	\n	Management group: Organizes subscriptions but does not enforce resource location rules.\n	\n	Reservation: Pre-pays for resources to save costs, does not control where resources can be created.\n ', '2026-03-14 09:07:08', 1),
	(337, 335, 'Correct answer: ✅ No\n\nMicrosoft Entra ID (formerly Azure AD) is a cloud-based identity service and does not require domain controllers on Azure virtual machines.\n\n	Entra ID is not Active Directory Domain Services (AD DS).\n	\n	It provides authentication and identity management without on-prem or Azure-hosted domain controllers.\n	\n	Domain controllers are only needed if you specifically want to run Active Directory Domain Services (classic AD), not Entra ID.\n\n ', '2026-03-14 09:07:08', 1),
	(338, 336, 'Correct answer: ✅ Yes.\n\nMicrosoft Entra ID does provide authentication services for resources hosted in Azure and Microsoft 365.\n\nIt is the identity and access management service that handles:\n	User sign-in\n	\n	Application authentication\n	\n	Access control for Azure resources\n	\n	Authentication for Microsoft 365 services such as Exchange Online, SharePoint Online, and Teams\n ', '2026-03-14 09:07:08', 1),
	(339, 337, 'Correct answer: ✅ No.\nA single user account in Microsoft Entra ID can be assigned multiple licenses.\n\nFor example, a user might have:\n	Microsoft 365 E3\n	Enterprise Mobility + Security (EMS)\n	Power BI Pro\n	Teams Phone Standard\n\nAll assigned at the same time.\n\nMicrosoft Entra ID imposes no limit of one license per user — users can receive multiple product licenses simultaneously.\n ', '2026-03-14 09:07:08', 1),
	(340, 338, 'Correct answer: ✅ No.\nYou do not need to sync on-premises identities to the cloud to implement Azure Multi-Factor Authentication (MFA).\n\nAzure MFA can be used with:\n	Cloud-only users in Microsoft Entra ID\n	Hybrid users (synced from on-premises AD via Entra Connect)\n	External users (B2B guests)\n\nDirectory synchronization is optional, not required.\n ', '2026-03-14 09:07:08', 1),
	(341, 339, 'Correct answer: ✅ No.\n\nPicture identification and passport numbers are not valid methods for Azure Multi‑Factor Authentication (MFA).\n\nValid Azure MFA methods include:\n	Microsoft Authenticator app (push notification or code)\n	SMS verification\n	Phone call verification\n	FIDO2 security keys\n	OATH hardware/software tokens\n\nAnything like picture ID or passport numbers is not an MFA method in Azure.\n ', '2026-03-14 09:07:08', 1),
	(342, 340, 'Correct answer: ✅ Yes.\n\nYou can configure Microsoft Entra ID activity logs (such as sign-in logs and audit logs) to appear in Azure Monitor by integrating them with:\n	Log Analytics workspaces\n	Azure Monitor Logs\n	Azure Event Hub\n	Storage accounts\n\nThis is commonly used for monitoring, alerting, and SIEM integration.\n', '2026-03-14 09:07:08', 1),
	(343, 341, 'Correct answer: ✅ Yes.\n\nAzure Monitor is designed to collect, analyze, and act on telemetry data from resources in Microsoft Azure.\n\nIt can monitor resources across:\n	Multiple Azure subscriptions\n	Multiple resource groups\n	Different Azure services\n\nUsing features like Log Analytics workspaces, administrators can centralize logs and metrics from different subscriptions and view them in one place.\n\nThis allows organizations with large or multi-subscription environments to monitor everything from a single monitoring solution.\n ', '2026-03-14 09:28:46', 1),
	(344, 342, 'Correct answer: ✅ Yes. \n\nIn Azure Monitor, you can create alerts based on metrics, logs, and activity logs. These alerts help you detect and respond to issues in your Azure resources automatically.\n\nExamples of what Azure Monitor alerts can do:\n	Trigger when CPU usage exceeds a threshold\n	Notify when application errors increase\n	Alert on specific log queries\n	Send notifications via email, SMS, or trigger automation like Azure Logic Apps or Azure Functions.\n ', '2026-03-14 09:28:46', 1),
	(345, 343, 'Correct answer: ✅ Locks\n\nIn Microsoft Azure, you can apply Resource Locks to a resource group or resource to prevent accidental changes.\n\nWhy Locks?\n	Using locks allows you to:\n	Prevent deletion of resources (Delete lock)\n	Prevent modifications (Read-only lock)\n\nFor your requirement—preventing accidental deletion of resources in RG1—you would apply a Delete lock at the resource group level.\n\nLock types in Azure\n	Delete (CanNotDelete) – Users can read and modify resources but cannot delete them.\n	ReadOnly – Users can only read resources; no changes allowed.\n	\nWhy the others are incorrect:\n	Quickstart ❌ – Provides templates and guides to deploy resources quickly, not for protection.\n	Resource costs ❌ – Shows cost and billing information, not resource protection.\n	Deployments ❌ – Displays deployment history and status, not used to prevent deletion.\n	Policies ❌ – Enforces rules for resource configuration, but does not directly prevent deletion like locks.\n	Properties ❌ – Shows metadata and settings of the resource group only.\n	Automation script ❌ – Generates scripts to recreate deployments, not for preventing deletion.\n ', '2026-03-14 09:28:46', 1),
	(346, 344, 'Correct answer:✅ An Azure policy.\n\nTo prevent only virtual machines from being created in a specific resource group (RG1), while still allowing other resource types, you must use Azure Policy.\n\nWhy not the others?\n	A lock → Prevents modification or deletion, but does NOT restrict creating specific resource types.\n	An Azure role → Controls who can perform actions, not which resource types can be created.\n	A tag → Used for organization or automation, not for denying resource creation.\n	Azure policy → Can enforce rules such as "deny creating virtual machines in RG1".\n\n🎯 Azure Policy Capability\n	You would use a policy with an effect like Deny, targeted at RG1, with conditions specifying "Microsoft.Compute/virtualMachines" as the prohibited resource type.\n ', '2026-03-14 09:28:46', 1),
	(347, 345, 'Correct answer: ✅ A conditional access policy.\n\nTo ensure that only users whose Windows 10 devices have the latest security patches can access Microsoft Entra ID–integrated applications, you use Conditional Access with device compliance.\n\nThis is done by integrating:\n	Microsoft Intune → to assess device compliance (OS version, patches, health)\n	Conditional Access → to allow access only from compliant devices\n\n❌ Why not the others?\n	Azure Bastion → Secure RDP/SSH access; unrelated to app access conditions\n	Azure Firewall → Controls network traffic; cannot check device patch status\n	Azure Policy → Governs Azure resources, not end‑user devices or access control\n ', '2026-03-14 09:28:46', 1),
	(348, 346, 'Correct answer: ✅ Microsoft Entra ID.\n\nMicrosoft Entra ID (formerly Azure Active Directory) provides single sign-on (SSO) capabilities that allow users to authenticate once and then access multiple integrated applications without re-entering their credentials.\n\n❌ Why not the others?\n	Application security groups in Azure → Used for managing network security rules, not authentication or SSO.\n	\n	Azure Key Vault → Manages secrets, certificates, and keys, not user authentication or SSO.\n	\n	Microsoft Defender for Cloud → A cloud security posture management and threat protection solution; no SSO capabilities.\n ', '2026-03-14 09:28:46', 1),
	(349, 347, 'Correct answer: ✅ credit your Azure account.\n\nWhen an Azure service outage causes one of your deployed resources to be unavailable beyond the guaranteed SLA, Microsoft provides service credits to your Azure account — not refunds, coupons, or subscription moves.\n\nThis is outlined in Azure’s Service Level Agreement (SLA), where Microsoft commits to uptime levels and compensates customers with Azure service credits if those levels are not met.\n\n❌ Why not the others?\n	Refund your bank account → Microsoft does not issue cash refunds for SLA breaches.\n	Migrate the resource to another subscription → SLA issues do not trigger subscription migration.\n	Send you a coupon code → Azure does not use coupon-based compensation for outages.\n ', '2026-03-14 09:28:46', 1),
	(350, 348, 'Correct answer: ✅ Confirm that Azure subscription security follows best practices.\n\nAzure Advisor provides personalized best‑practice recommendations in four main areas:\n	Security\n	Cost optimization\n	Performance\n	Reliability (high availability)\nThis means it can help you verify whether your Azure resources follow recommended security practices.\n\n❌ Why not the others?\n	Integrate Active Directory and Microsoft Entra ID\n		→ Done using Azure AD Connect, not Azure Advisor.\n\n	Estimate the costs of an Azure solution\n		→ Done using the Azure Pricing Calculator or TCO Calculator, not Azure Advisor.\n\n	Evaluate which on‑premises resources can be migrated to Azure\n		→ Done using Azure Migrate, not Azure Advisor.\n ', '2026-03-14 09:28:46', 1),
	(351, 349, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, an Azure Free Account only provides access to a subset of Azure services. These include:\n	12-month free services (limited list)\n	Always free services with usage limits\n	$200 credit for 30 days\n\nBecause not all Azure services are included in the free tier, the statement is considered True (Yes) in AZ-900 exam context.\n ', '2026-03-14 09:28:46', 1),
	(352, 350, 'Correct answer: ✅ Yes.\n\nAzure free accounts include a $200 credit that expires after 30 days from account creation, and certain free services and quantities expire after 12 months.\n\nAfter these periods, the account transitions to pay-as-you-go billing for continued usage beyond free limits, though some always-free services may persist.\n', '2026-03-14 09:28:46', 1),
	(353, 351, 'Correct answer: ✅ No\n\nYou cannot create multiple Azure free accounts using the same Microsoft account.\n\nMicrosoft enforces a strict limit of one Azure free account per person because:\n	The Azure free account is available only to new Azure customers, and the system checks whether the Microsoft account has ever been used for Azure before.\n	\n	To sign up, Azure requires identity verification with a credit/debit card, and the same card cannot be reused to create additional free accounts.\n\nTherefore, you cannot create 10 free accounts—not even 2—with the same Microsoft account.\n ', '2026-03-14 09:31:42', 1),
	(354, 352, 'Correct answer: ✅ No.\n\nIn Microsoft Azure, private preview services do not require a separate portal. \n\nYou typically access them through the same Azure portal (portal.azure.com) once you are approved for the private preview, often via special subscription access or registration.\n ', '2026-03-14 09:31:42', 1),
	(355, 353, 'Correct answer: ✅ Yes\n\n	Azure public preview services can be used in production environments.\n\n	However, Microsoft makes it clear that public preview features come with no SLA, may be unstable, and can change—so while they are usable, they are not recommended for production unless you accept the risks.\n ', '2026-03-14 09:31:42', 1),
	(356, 354, 'Correct answer: ✅ No\n\nAzure public preview services do NOT come with a Service Level Agreement (SLA).\n\nMicrosoft explicitly states that preview features—whether private or public—are not covered by SLAs, may change, and are offered “as-is.”\n ', '2026-03-14 09:31:42', 1),
	(357, 355, 'Correct answer: ✅ No\n\n	An Azure free account does not include a Standard support plan.\n\n	Azure free accounts come with only basic, community-based support, such as documentation, forums, and billing support.\n\n	Paid support plans (Developer, Standard, Professional Direct, etc.) must be purchased separately and are not included with the free account.\n ', '2026-03-14 09:31:42', 1),
	(358, 356, 'Correct answer: ✅ Extends on-premises networks to the Microsoft cloud via a private connection: ExpressRoute\n Combines two or more Azure virtual networks into a single logical virtual network: Virtual network peering\n Provides an encrypted connection from on-premises networks to Azure via a public network: VPN gateway.\n \nExplanation\n	ExpressRoute → Private dedicated connection between on-premises infrastructure and Azure (does not use the public internet).\n	Virtual Network Peering → Connects Azure VNets so they behave like one network with low latency.\n	VPN Gateway → Uses IPsec/IKE encryption over the public internet to connect on-premises networks to Azure.\n', '2026-03-14 09:31:42', 1),
	(359, 357, 'Correct answer: ✅ No\n\nSupport from MSDN forums is available to all users, not just those with a pay-as-you-go Azure subscription. Anyone with a Microsoft account can post questions and receive community or moderator support through the forums.\n\n❌ Yes is incorrect because forum access does not depend on subscription type.\n ', '2026-03-14 09:31:42', 1),
	(360, 358, 'Correct answer: ✅ No\n\n	A user with the Owner role cannot transfer ownership of an Azure subscription by role assignment alone.\n\n	The Owner role gives full access to manage all Azure resources within a subscription, including assigning roles.\n\n	However, transferring subscription ownership is not done through Azure RBAC.\n\n	Subscription ownership transfer requires changing the billing ownership through the Azure Account Center or Billing Administration, and only the billing administrator / account admin can do that — not just an Owner.\n ', '2026-03-14 09:31:42', 1),
	(361, 359, 'Correct answer: ✅ Yes\n\n	In Microsoft Azure, you can convert a Free Trial subscription to a Pay-As-You-Go subscription. This allows you to continue using Azure services without interruption once the trial period ends and start paying only for the resources you use.\n ', '2026-03-14 09:31:42', 1),
	(362, 360, 'Correct answer: ✅Yes\n\n	With Azure Reservations, you do pay less for virtual machines compared to pay‑as‑you‑go pricing.\n\n	Azure Reserved Instances offer significant discounts (often up to 72%) when you commit to using a VM for 1 or 3 years, making them cheaper than on‑demand pay‑as‑you‑go rates.', '2026-03-14 09:31:42', 1),
	(363, 361, 'Correct answer: ✅ No\n\nIn Microsoft Azure, two virtual machines of the same size (e.g., B25) do not necessarily have the same monthly costs because pricing depends on additional factors such as:\n	Region – VM pricing varies by Azure region.\n	Operating System – Windows VMs are generally more expensive than Linux VMs.\n	Storage type and size – Premium vs Standard disks affect cost.\n	Networking or additional services – Data transfer or reserved IPs can add cost.\n ', '2026-03-14 10:08:25', 1),
	(364, 362, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, when a virtual machine (VM) is stopped (deallocated):\n	You do not pay for compute resources (CPU, RAM).\n	You continue to pay for the storage (disks, OS, data) associated with the VM.\n ', '2026-03-14 10:08:25', 1),
	(365, 363, 'Correct answer: ✅ (Maximum Available Minutes-Downtime in Minutes)\n\n✔️ Full formula\nMonthly Uptime % = (Maximum Available Minutes – Downtime in Minutes)\n                   ÷ Maximum Available Minutes\n                   × 100\n\nThis is exactly how Microsoft calculates SLA uptime for Azure services.\n', '2026-03-14 10:08:25', 1),
	(366, 364, 'Correct answer: ✅ Maximum Available Minutes\n\n✔️ Full formula\nMonthly Uptime % = (Maximum Available Minutes – Downtime in Minutes)\n                   ÷ Maximum Available Minutes\n                   × 100\n\nThis is exactly how Microsoft calculates SLA uptime for Azure services.\n\n ', '2026-03-14 10:08:25', 1),
	(367, 365, 'Correct answer: ✅ 100\n\n✔️ Full formula\nMonthly Uptime % = (Maximum Available Minutes – Downtime in Minutes)\n                   ÷ Maximum Available Minutes\n                   × 100\n\nThis is exactly how Microsoft calculates SLA uptime for Azure services.\n ', '2026-03-14 10:08:26', 1),
	(368, 366, 'Correct answer: ✅ No\n\n	Creating additional resource groups in an Azure subscription does not incur any extra cost. \n	Azure charges for resources, not for the number of resource groups.\n\n	Resource groups are simply logical containers used to organize and manage Azure resources. \n	Whether you create 1 or 100 resource groups, you do not pay anything for the resource groups themselves.\n ', '2026-03-14 10:08:26', 1),
	(369, 367, 'Correct answer: ✅ No\n\nCopying data into Azure over a VPN does not incur additional data transfer costs.\n\nAzure charges for:\n	Data transferred out of Azure (egress) → Charged\n	Data transferred into Azure (ingress) → Free\n	VPN Gateway hourly cost + possible data processing charges → Applies regardless of data size\n\nSo even if you transfer several gigabits (or terabytes) of data from on-premises to Azure, the ingress traffic is free, and you are not billed per GB for this.\n ', '2026-03-14 10:08:26', 1),
	(370, 368, 'Correct answer: ✅ Public preview.\n\nAn Azure service becomes available to all Azure customers when it reaches Public Preview.\n\n	Private Preview → Limited access, invite‑only.\n	Public Preview → Open to all Azure customers (though not yet generally available, and not covered by SLAs).\n	Development → Internal Microsoft stage, not available to customers.\n	Enterprise Agreement (EA) subscription → Not related to service availability stages.\n ', '2026-03-14 10:08:26', 1),
	(371, 369, 'Correct answer: ✅ Yes\n\nMost Azure services typically follow this release progression:\n	Private Preview → limited, invitation‑only testing\n	Public Preview → open to all Azure customers, but without SLA\n	General Availability (GA) → fully supported and production‑ready\n\nThis staged rollout is the standard pattern Microsoft uses for introducing new Azure services.\n ', '2026-03-14 10:08:26', 1),
	(372, 370, 'Correct answer: ✅ No\n\nAzure services in public preview can be managed using multiple tools, not only the Azure CLI.\n\nPublic preview services can typically be managed with:\n	Azure Portal (when the feature is integrated)\n	Azure CLI\n	Azure PowerShell\n	ARM templates / Bicep\n	REST APIs\n\nThere is no requirement that public preview services be managed only via Azure CLI', '2026-03-14 10:08:26', 1),
	(373, 371, 'Correct answer: No\n\nIn Microsoft Azure, when a service moves from private preview to generally available (GA), the price is not guaranteed to decrease.\n\nKey points for AZ-900\n	Private preview → Limited testing with selected customers.\n	Public preview → Available to more users but still under testing.\n	Generally Available (GA) → Fully supported production service.\n\nPricing may change, but it does not necessarily decrease when the service becomes GA.\n\n✔ Final answer: No.', '2026-03-14 10:09:05', 1),
	(374, 372, 'Correct answer: start an existing Azure virtual machine\n\nWhen an Azure free trial subscription expires in Microsoft Azure:\n	You cannot create or start billable resources, such as Azure Virtual Machines.\n	Your subscription is disabled until you upgrade to a paid subscription.\n\nWhat you can still do\n	Access the Azure portal\n	Access your existing data\n	Manage Microsoft Entra ID users\n\nBut you cannot start existing virtual machines or create new resources.\n\n✔ Final answer: start an existing Azure virtual machine.', '2026-03-14 10:09:05', 1),
	(375, 373, 'Correct answer: Yes\n\nThe solution does meet the goal.\n\nThe requirement states that the company must have the option to access Azure support engineers by phone or email. The Azure Professional Direct Support plan does provide phone and email access to support engineers, so it satisfies the requirement.\n\nAzure support plans relevant for AZ-900\n	Basic → No technical support.\n	Developer → Email support only.\n	Standard → Email + phone support.\n	Professional Direct → Email + phone support with faster response and advisory services.\n\nSince Professional Direct includes phone and email support, the requirement is met.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:05', 1),
	(376, 374, 'Correct answer: A subscription\n\nIn Microsoft Azure, billing and payment methods are managed at the subscription level.\n\nWhy subscription?\n	Each Azure Subscription can have its own payment method and billing details.\n	This allows each department to manage and pay for its own Azure resources separately.\n\nWhy the other options are incorrect\n	Reservation → Used for discounted pricing, not billing separation.\n	Resource group → Logical grouping of resources within a subscription, same billing.\n	Container instance → A compute service, not related to billing management.\n\n✔ Final answer: A subscription.', '2026-03-14 10:09:06', 1),
	(377, 375, 'Correct answer: Yes\n\nAn Azure Free Account includes a spending limit.\n\nHow it works\n	New free accounts receive $200 credit for 30 days.\n	A spending limit prevents charges once the credit is exhausted.\n	When the limit is reached, Azure disables paid resources to avoid unexpected billing.\n\nIf the user upgrades to a paid subscription, the spending limit is removed.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:06', 1),
	(378, 376, 'Correct answer: No\n\nAn Azure Free Account does not have a fixed 2 TB upload limit for data.\n\nKey points (AZ-900)\n	The free account provides $200 credit for the first 30 days.\n	Some services have limited free usage tiers, but there is no general 2 TB data upload cap.\n	Data upload (inbound data transfer) to Microsoft Azure is typically free and not limited to 2 TB.\n\n✔ Final answer: No.', '2026-03-14 10:09:06', 1),
	(379, 377, 'Correct answer: No\n\nAn Azure Free Account cannot contain an unlimited number of web apps.\n\nExplanation (AZ-900 context)\n	Web apps run on Azure App Service, and the free account has usage limits and quotas such as:\n		Limited compute resources\n		Limited service tiers\n		Credit limit ($200 for 30 days)\n\nBecause of these resource and quota limits, you cannot create an unlimited number of web apps.\n\n✔ Final answer: No.', '2026-03-14 10:09:06', 1),
	(380, 378, 'Correct answer: No\n\nAn Microsoft Azure service in private preview is not available to all customers.\n\nService release stages (AZ-900)\n	Private Preview → Available only to a limited set of invited customers for testing.\n	Public Preview → Available to all Azure customers, but still under development.\n	General Availability (GA) → Fully supported for production use.\n\n✔ Final answer: No.', '2026-03-14 10:09:06', 1),
	(381, 379, 'Correct answer: Yes\n\nIn Microsoft Azure, when a service is in public preview, it is available to all Azure customers, although it is still under testing and may not yet be recommended for production workloads.\n\nAzure release stages (AZ-900)\n	Private Preview → Limited invited customers only\n	Public Preview → Available to all Azure customers but still evolving\n	General Availability (GA) → Fully supported for production use\n\n✔ Final answer: Yes.', '2026-03-14 10:09:06', 1),
	(382, 380, 'Correct answer: No\n\nIn Microsoft Azure, when a service reaches General Availability (GA), it means the service is fully released and available to all Azure customers for production use.\n\nAzure service release stages (AZ-900)\n	Private Preview → Limited invited customers\n	Public Preview → Available to all customers but still testing\n	General Availability (GA) → Fully released to all customers with SLA and support\n\nSince GA services are not limited to a subset of customers, the statement is incorrect.\n\n✔ Final answer: No.', '2026-03-14 10:09:06', 1),
	(383, 381, 'Correct answer:	✅ No\n\nIn Microsoft Azure, a consumption-based pricing model means you pay only for what you use, not a fixed rate.\n\nHow it works\n	Charges depend on actual usage of resources.\n	Data transfer costs vary depending on:\n		Amount of data\n		Direction (inbound vs outbound)\n		Region\n		\nInbound data to Azure is usually free, but outbound data is charged per GB.\nSo there is no single fixed rate for all data sent to or from virtual machines.\n\n✔ Final answer: No.', '2026-03-14 10:09:33', 1),
	(384, 382, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, a consumption-based pricing model means you pay only for the resources you actually use.\n\nWhy this reduces costs\n	You don’t pay for unused capacity.\n	You can scale resources up when demand increases.\n	You pay for extra capacity only when it is required.\n\nThis elasticity helps organizations optimize costs compared to fixed infrastructure.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:33', 1),
	(385, 383, 'Correct answer: ✅ Yes\n\nServerless computing in Microsoft Azure follows a consumption-based pricing model.\n\nFor example, services like Azure Functions charge you based on:\n	Number of executions\n	Execution time\n	Resources used\n\nYou do not pay for idle servers, only for the actual compute time consumed.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:33', 1),
	(386, 384, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, the cost of resources can vary depending on the region where the service is deployed.\n\nReasons for price differences\n	Local infrastructure and operational costs\n	Demand and supply in specific regions\n	Taxes and regulatory factors\n	Currency differences\n\nFor example, running a Azure Virtual Machines instance in one region may cost more or less than running the same instance in another region.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:33', 1),
	(387, 385, 'Correct answer: ✅ No\n\nIn Microsoft Azure, an Azure Reserved Instances (Azure Reservation) is not used to reserve server capacity at a specific data center.\n\nWhat Azure Reservations actually do\n	Provide discounted pricing (often up to ~72%) for committing to 1-year or 3-year usage of certain Azure services.\n	Apply to services like Azure Virtual Machines, SQL Database, etc.\n	The reservation is tied to a region and resource type, not a specific physical data center server.\n\nKey idea\n	Reservations are for cost savings, not for reserving physical server capacity.\n\n✔ Final answer: No.', '2026-03-14 10:09:33', 1),
	(388, 386, 'Correct answer: ✅ No\n\nIn Azure SQL Database, you cannot stop or pause the database to reduce costs in the standard deployment models.\n\nExplanation\n	Unlike Azure Virtual Machines, which can be stopped (deallocated) to avoid compute charges, Azure SQL Database continues to incur charges while it exists.\n	To reduce cost you would typically:\n		Scale down the service tier\n		Delete the database if it is no longer needed.\n\n✔ Final answer: No.', '2026-03-14 10:09:33', 1),
	(389, 387, 'Correct answer: the product of both SLAs, which equals 99.94 percent\n\nIn Microsoft Azure, when an application depends on multiple services, the composite SLA is calculated by multiplying the individual SLAs.\n\nServices in the question\nAzure App Service → 99.95% SLA\nAzure SQL Database → 99.99% SLA\n\nCalculation\n	0.9995 × 0.9999 = 0.9994\nConverted to percentage: 99.94%\nWhy?\n	If either service is unavailable, the entire application becomes unavailable, so the availability multiplies across dependent services.\n\n✔ Final answer: The product of both SLAs, which equals 99.94 percent.', '2026-03-14 10:09:33', 1),
	(390, 388, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, the Service Level Agreement (SLA) for paid Azure services typically guarantees at least 99.9% uptime.\n\nKey AZ-900 points\n	Free tiers usually do not have an SLA.\n	Paid Azure services generally have minimum 99.9% uptime.\n	Some services provide higher SLAs such as 99.95%, 99.99%, or 99.999% depending on configuration and redundancy.\n\nExample\n	Azure Virtual Machines → around 99.9% or higher depending on deployment.\n	Azure SQL Database → can offer 99.99% SLA.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:33', 1),
	(391, 389, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, companies can increase the overall availability of an application by deploying resources across multiple Azure regions.\n\nWhy this increases SLA\n	If one region becomes unavailable, the application can fail over to another region.\n	This reduces downtime risk and improves overall availability.\n\nExample\n	Deploying Azure App Service in two regions with traffic management.\n	Using services like Azure Traffic Manager to route users to the available region.\n\n✔ Final answer: Yes.', '2026-03-14 10:09:33', 1),
	(392, 390, 'Correct answer: ✅ No\n\nIn Microsoft Azure, purchasing multiple subscriptions does not increase the Service Level Agreement (SLA) for your resources.\n\nWhy?\n	SLA depends on the service architecture and deployment, not on how many subscriptions you have.\n	To improve availability, companies should use strategies such as:\n		Deploying resources in multiple regions\n		Using availability zones\n		Using load balancing\n\nSubscriptions are mainly used for billing, management, and access control, not for increasing SLA.\n\n✔ Final answer: No.', '2026-03-14 10:09:33', 1),
	(393, 391, 'Correct answer:	✅ A managed service that provides bidirectional communication between IoT devices and Azure: Azure IoT Hub\n	A fully managed software as a service (SaaS) solution to connect, monitor, and manage IoT devices at scale: Azure IoT Central\n	A software and hardware solution that provides communication and security features for IoT devices: Azure Sphere\n\nQuick Explanation:\n	Azure IoT Hub → Cloud service enabling secure, bidirectional communication between IoT devices and Azure.\n	Azure IoT Central → Fully managed SaaS platform to easily build IoT solutions without deep cloud expertise.\n	Azure Sphere → Combines hardware (MCU), OS, and cloud security service to secure IoT devices.\n	✔ Therefore, the first option is correct.', '2026-03-14 10:17:54', 1),
	(394, 392, 'Correct answer:	✅ Help + support\n\nYou should open Microsoft Azure Portal → Help + support to request a subscription quota increase.\n	\nWhy?\n	In Microsoft Azure, quota or service limit increases (for example VM cores, storage limits, etc.) are requested through support requests, which are created from the Help + support blade.\n\nSteps\n	Open Microsoft Azure Portal\n	Select Help + support\n	Click Create a support request\n	Choose Service and subscription limits (quotas)\n	Submit the request.\n\n✔ Final answer: Help + support.', '2026-03-14 10:17:54', 1),
	(395, 393, 'Correct answer:	✅ Budget alerts\n\nIn Microsoft Azure, Azure Cost Management and Billing allows you to create Budget alerts that send notifications when spending reaches or exceeds a defined threshold.\n\nHow it works\n	You create a budget for a subscription or resource group.\n	Set a threshold (for example 80%, 90%, or 100% of the budget).\n	When the cost reaches that threshold during the billing period, Azure sends an email alert.\n\nWhy the other options are incorrect\n	Advisor recommendations → Provides optimization suggestions (performance, security, cost), not alerts.\n	Access control (IAM) → Manages permissions and roles.\n	Compliance → Deals with regulatory and governance standards.\n\n✔ Final answer: Budget alerts.', '2026-03-14 10:17:54', 1),
	(396, 394, 'Correct answer:	✅ Yes\n\nIn the Microsoft Azure Portal, services that are in Public Preview are clearly labeled with a “Preview” tag, while Generally Available (GA) services appear without that label.\n\nHow you can see it\n	When browsing services in Microsoft Azure (for example in All services).\n	Preview services show “Preview” next to the service name.\n	GA services have no preview label.\n\n✔ Final answer: Yes.', '2026-03-14 10:17:54', 1),
	(397, 395, 'Correct answer:	❌ No\n\nIn Microsoft Azure, when a service becomes Generally Available (GA), it means the service is fully supported and production-ready. However, Microsoft continues to improve and update it with new features, enhancements, and fixes.\n\nKey points\n	Public Preview → Feature is still being tested and may change.\n	Generally Available (GA) → Fully supported for production use.\n	Even after GA, the service continues receiving updates and new capabilities.\n\n✔ Final answer: No.', '2026-03-14 10:17:54', 1),
	(398, 396, 'Correct answer:	❌ No\n\nIn Microsoft Azure, when a service moves from Public Preview to Generally Available (GA), you typically do not need to recreate existing resources.\n\nExplanation\n	Resources created during Preview usually continue to work after GA.\n	Microsoft transitions the service to GA while maintaining compatibility.\n	In rare cases, Microsoft may give migration instructions, but recreation is not normally required.\n\n✔ Final answer: No.', '2026-03-14 10:17:54', 1),
	(399, 397, 'Correct answer:	✅ Yes\n\nWhen using Azure ExpressRoute, inbound data transfer (data moving from your on-premises network into Azure) is free of charge.\n\nImportant notes\n	Inbound traffic (on-premises → Azure): Free\n	Outbound traffic (Azure → on-premises): Charged based on the pricing model or charged based on region and billing plan.\n	This is consistent across all ExpressRoute circuits (Standard, Premium, Local).\n\nMicrosoft Azure provides this pricing structure to encourage data ingestion into Azure services.\n\n✔ Final answer: Yes.', '2026-03-14 10:17:54', 1),
	(400, 398, 'Correct answer:	❌ No\n\nIn Microsoft Azure, outbound data traffic (data leaving Azure to an on-premises network) is not always free.\n\nWhen using Azure ExpressRoute:\n	Inbound traffic (on-premises → Azure): Free\n	Outbound traffic (Azure → on-premises): Usually charged, depending on the ExpressRoute pricing model (metered or unlimited) or charged based on region and (metered or unlimited) data plan.\n\nTherefore, outbound data transfer is not always free.\n\n✔ Final answer: No.', '2026-03-14 10:17:54', 1),
	(401, 399, 'Correct answer:	✅ Yes\n\nData traffic between Azure services within the same Azure region is free.\n\nExplanation\nAzure does not charge for intra‑region data transfer, meaning:\n	Virtual machines → Storage accounts (same region): Free\n	App Service → SQL Database (same region): Free\n	Any service‑to‑service traffic within the same region: Free\n	\n	Inbound data transfer: Free\n	Data transfer within the same Azure region: Free\n	Outbound data transfer (to internet or other regions): Charged\n\nData transfer between different regions (cross‑region traffic) is NOT free and is billed as inter‑region bandwidth.\n\n✔ Final answer: No.', '2026-03-14 10:17:54', 1),
	(402, 400, 'Correct answer:	The public IP addresses\n\nIn Microsoft Azure, unused Public IP addresses are billable resources, especially when they are allocated but not attached to a resource (like a VM or load balancer).\n\nResource cost behavior\n	Microsoft Entra ID user accounts → No cost for simply existing.\n	Microsoft Entra ID groups → No direct cost.\n	Network interfaces → Typically free unless attached to other billable resources.\n	Public IP addresses → Charged even when unused.\n\n\nConclusion\nTo reduce Azure costs, remove:\n	✔ Unused public IP addresses\n	\n❌ User accounts in Microsoft Entra ID\n	Free (up to 500,000 objects under the free tier)\n	Removing them does not reduce Azure subscription costs.\n\n❌ Groups in Microsoft Entra ID\n	Also free\n	Removing them does not reduce Azure costs.\n\n❌ Network interfaces (NICs)\n	Detached NICs do NOT incur charges\n	Removing them does not reduce costs.\n\n✅ Public IP addresses\nIdle / unused Public IPs DO incur charges\n	Azure bills for:\n		Unassigned Standard IPs\n		Unassigned Basic IPs (in most regions)\n\nSo removing unused public IP addresses will reduce costs.\n\nFinal answer: The public IP addresses.', '2026-03-14 10:17:54', 1),
	(403, 401, 'Correct answer: ✅ Storage\n\nIn Microsoft Azure, when a virtual machine is in Stopped (deallocated) state:\n	compute capacity → not charged because the VM is not running.\n	networking → generally not charged for the VM when it is deallocated.\n	i/o operations → not charged since the VM is not performing operations.\n	storage → charged because the VM’s OS disk and data disks are still stored in Azure storage.', '2026-03-14 17:53:20', 1),
	(404, 402, 'Correct answer: ✅ No\n\nIn Microsoft Azure, the cost of storage depends on the region where the data is stored. Different regions have different pricing due to factors like infrastructure cost, demand, and operational expenses.\n	For example:\n	Storing data in US regions may have a different price than storing it in Europe or Asia regions.\n	Pricing may also vary based on the storage tier (Hot, Cool, Archive) in Azure Blob Storage.\n	Therefore, storing 1 TB of data will not always cost the same across all regions.\n ', '2026-03-14 17:53:20', 1),
	(405, 403, 'Correct answer: ✅ No\n\nIn Microsoft Azure, a general-purpose v2 storage account (Azure Storage) charges for more than just the amount of stored data.\nYou are charged for:\n	stored data (capacity)\n	read and write operations (transactions)\n	data transfer (egress)\n	storage tier used (Hot, Cool, Archive in Azure Blob Storage)\n', '2026-03-14 17:53:20', 1),
	(406, 404, 'Correct answer: ✅ No\n\nIn Microsoft Azure, data transfer between different regions is not free.\nWhen data is transferred between Azure Storage accounts located in different Azure regions, data transfer (egress) charges apply.\n	Same region transfer → usually free or very low cost.\n	Different region transfer → charged because the data leaves the region.', '2026-03-14 17:53:20', 1),
	(407, 405, 'Correct answer: ✅ Yes\n\nMicrosoft Entra ID (including Premium P2) is covered by a Service Level Agreement (SLA) from Microsoft that guarantees at least 99.9% availability.\nThis means the service is expected to be accessible 99.9% of the time, ensuring reliable authentication and identity management for users and applications.\n', '2026-03-14 17:53:20', 1),
	(408, 406, 'Correct answer: ✅ No\n\nMicrosoft Entra ID Free does not come with a financially backed service level agreement (SLA), while Microsoft Entra ID Premium P2 provides a 99.99% uptime SLA for its authentication services.\nThis distinction ensures higher reliability guarantees for paid tiers like P2, which include advanced features and enterprise support not available in the Free edition.', '2026-03-14 17:53:20', 1),
	(409, 407, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, when a service that has an SLA falls below its guaranteed monthly uptime percentage, paying customers are eligible to receive service credits. The credit amount depends on how much the uptime falls below the SLA threshold.\n', '2026-03-14 17:53:20', 1),
	(410, 408, 'Correct answer: ✅ No\n\nIn Microsoft Azure, resource groups are just logical containers used to organize and manage resources such as virtual machines, storage accounts, and databases.\nCreating or adding resource groups is free.\nYou are only charged for the resources inside the resource group, not for the resource group itself.\n', '2026-03-14 17:53:20', 1),
	(411, 409, 'Correct answer: ✅ No\n\nIn Microsoft Azure, data transfer into Azure (ingress) is generally free.\nInbound data transfer (into Azure) → free\nOutbound data transfer (from Azure to internet or other regions) → charged\n ', '2026-03-14 17:53:20', 1),
	(412, 410, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure:\nData transfer into Azure (ingress) → free.', '2026-03-14 17:53:20', 1),
	(413, 411, 'Correct answer: ✅ No\n\nIn Microsoft Azure, each Azure subscription has:\n	1 Account Administrator → Responsible for billing and managing the subscription.\n	1 Service Administrator → Has full access to manage services in the subscription.\n	Multiple Co-administrators (classic model) or multiple users via RBAC roles like Owner/Contributor.\n\nHowever, there can be only one Account Administrator per subscription.\n\n', '2026-03-14 17:55:00', 1),
	(414, 412, 'Correct answer: ✅ No\n\nIn Microsoft Azure, an Azure subscription can be associated with different types of accounts:\n	Microsoft account (MSA) – Personal accounts like Outlook.com or Hotmail.com.\n	Work or school account (Azure Active Directory account) – Provided by an organization.\n	Both types can be used to manage subscriptions, assign roles, and access resources.\n\nYou are not limited to Microsoft accounts only.\n ', '2026-03-14 17:55:00', 1),
	(415, 413, 'Correct answer: ✅ No\n \nIn Microsoft Azure, the hierarchy is:\n	Management Groups → Subscriptions → Resource Groups → Resources\n\nA resource group belongs to one Azure subscription only.\nIt cannot contain multiple subscriptions.\nInstead, a subscription can contain multiple resource groups.\n\n✔ Example structure:\n	Subscription A\n		Resource Group 1\n		Resource Group 2\n	Subscription B\n		Resource Group 3\n\nEach resource group stays inside a single subscription.\n ', '2026-03-14 17:55:00', 1),
	(416, 414, 'Correct answer: ✅ must be rehydrated before the data can be accessed.\n\nIn Microsoft Azure, Azure Blob Storage has different access tiers:\n	Hot – Frequently accessed data\n	Cool – Infrequently accessed data\n	Archive – Rarely accessed data with the lowest storage cost\n\nData stored in the Archive tier is offline. This means:\n	It cannot be read immediately.\n	It must first be rehydrated (moved to Hot or Cool tier).\n	Rehydration can take several hours.\n\nWhy the other options are incorrect\n	Accessed at any time using azcopy.exe ❌ – Archive data is offline.\n	\n	Only read using Azure Backup ❌ – Not restricted to Azure Backup.\n	\n	Must be restored before access ❌ – The correct Azure term is rehydration.\n ', '2026-03-14 17:55:00', 1),
	(417, 415, 'Correct answer: ✅ Automatically credit your account.\n\nIn Microsoft Azure, service availability is covered under the Service Level Agreement (SLA).\nIf Azure fails to meet the SLA uptime guarantee, Microsoft provides service credits as compensation.\nThese credits are applied to your Azure account billing.\nThey are not refunded directly to your bank account.\nThey reduce future Azure charges.\n\nWhy the other options are incorrect\n	No change is needed ❌ – The statement is incorrect because refunds are not sent to bank accounts.\n\n	Automatically migrate the resource to another subscription ❌ – Azure does not do this automatically.\n\n	Send a coupon code for Azure credits ❌ – Credits are applied directly to the account, not via coupons.\n ', '2026-03-14 17:55:00', 1),
	(418, 416, 'Correct answer: ✅ To the same resource group.\n\nIn Microsoft Azure, permissions are typically delegated using Role-Based Access Control (RBAC). RBAC roles can be assigned at different scopes:\n	Management group\n	Subscription\n	Resource group\n	Individual resource\n\nIf you place multiple virtual machines in the same resource group, you can assign permissions once at the resource group level, and the permissions automatically apply to all VMs inside that group.\n\nWhy the other options are incorrect\n	Same Azure region ❌ – Region affects location/latency, not permissions.\n\n	Same Azure Resource Manager template ❌ – Templates are for deployment, not permission delegation.\n\n	Same availability zone ❌ – Zones provide high availability, not access control.\n ', '2026-03-14 17:55:00', 1),
	(419, 417, 'Correct answer: ✅ Platform as a Service (PaaS)\n\n\nAzure Cosmos DB in Microsoft Azure is a fully managed NoSQL database service where Azure handles:\n	Infrastructure\n	Operating system\n	Patching\n	Scaling\n	High availability\n\nUsers only manage:\n	Data\n	Queries\n	Application logic\n\nThis fits the Platform as a Service (PaaS) model.\n\nWhy the other options are incorrect\n	Infrastructure as a Service (IaaS) ❌ – You would manage the VM, OS, and database yourself.\n\n	Serverless ❌ – Although Cosmos DB has serverless pricing options, the service model itself is categorized as PaaS.\n\n	Software as a Service (SaaS) ❌ – SaaS delivers complete applications like email or CRM, not a database platform.\n ', '2026-03-14 17:55:00', 1),
	(420, 418, 'Correct answer: ✅ Yes\n\nThe Microsoft Service Trust Portal is a site where users can access information about security, privacy, compliance, and audit reports for Microsoft cloud services.\n\nAnyone with a Microsoft cloud services account (such as accounts used for Microsoft Azure, Microsoft 365, or Dynamics 365) can sign in and access the portal.\n\nThrough the portal you can:\n	Review compliance certifications\n	Download audit reports\n	Learn about Microsoft security and privacy practices\n ', '2026-03-14 17:55:00', 1),
	(421, 419, 'Correct answer: ✅ Yes\n\nMicrosoft Compliance Manager is a tool within Microsoft 365 that helps organizations manage and track regulatory compliance activities across Microsoft cloud services such as:\n	Microsoft Azure\n	Microsoft 365\n	Dynamics 365\n\nIt provides:\n	Compliance score to measure compliance posture\n	Actionable improvement actions\n	Assessment templates for regulations (GDPR, ISO, etc.)\n	Tools to track and manage compliance tasks\n ', '2026-03-14 17:55:00', 1),
	(422, 420, 'Correct answer: ✅ Yes\n\nIn the Microsoft Service Trust Portal, the My Library feature allows users to:\n	Save documents and resources\n	Organize compliance and audit reports\n	Access saved files easily from one place\n\nThis is useful when working with materials related to Microsoft Azure, Microsoft 365, and other Microsoft cloud services.', '2026-03-14 17:55:00', 1),
	(423, 421, 'Correct answer: ✅ Yes\n\nThe solution meets the goal.\n\nExplanation\nThe requirement is to use only PaaS solutions in Microsoft Azure.\n	Azure App Service → A Platform as a Service (PaaS) used to host web applications.\n	Azure Storage → A fully managed platform service used for storing data such as blobs, files, queues, and tables.\n\nSince both services are PaaS offerings, the solution complies with the requirement to use only PaaS solutions.\n\n✔ Final answer: Yes.', '2026-03-14 17:56:18', 1),
	(424, 422, 'Correct answer: ✅ must be restored before the data can be accessed\n\nIn Azure Blob Storage, the Archive access tier is designed for long-term data storage with very low cost.\n\nImportant behavior of Archive tier\n	Data in the Archive tier is offline.\n	It cannot be read or accessed directly, even with tools like azcopy.\n	The data must first be rehydrated (restored) to the Hot or Cool tier before it can be accessed.\n\nThis behavior applies to storage accounts in Microsoft Azure.\n\n✔ Final answer: must be restored before the data can be accessed.\n ', '2026-03-14 17:56:18', 1),
	(425, 423, 'Correct answer: ✅ No\n\nA Hybrid Cloud combines on-premises infrastructure (or private cloud) with a public cloud such as Microsoft Azure.\n\nKey point (AZ-900)\n	A company does not have to start with a private cloud to implement a hybrid cloud.\n	Hybrid simply means integrating on-premises systems with a public cloud.\n	Many organizations move directly from on-premises environments to a hybrid setup.\n\n✔ Final answer: No.', '2026-03-14 17:56:18', 1),
	(426, 424, 'Correct answer: ✅ Yes\n\nA company can extend the computing resources of its internal network by using the Public Cloud.\n\nExplanation\nWith services from Microsoft Azure, organizations can:\n	Add extra compute, storage, and networking resources.\n	Scale resources without buying additional physical hardware.\n	Integrate on-premises infrastructure with the cloud to create a hybrid environment.\n\nThis capability allows companies to expand their internal IT capacity using the public cloud.\n\n✔ Final answer: Yes.', '2026-03-14 17:56:18', 1),
	(427, 425, 'Correct answer: ✅ Yes\n\nAzure DevOps Services supports Continuous Integration and Continuous Delivery (CI/CD) pipelines that allow developers to build, test, and deploy applications automatically.\n\nHow it works\nUsing Azure Pipelines in Azure DevOps Services, developers can:\n	Automatically build code when changes are committed\n	Run automated tests\n	Deploy or update applications in Microsoft Azure\n\n✔ Final answer: Yes.', '2026-03-14 17:56:18', 1),
	(428, 426, 'Correct answer: ✅ Yes\n\nAzure DevOps Services includes Azure Repos, which provides Git repositories for developers to store, manage, and version their source code.\n\nKey points\n	Supports Git repositories for distributed version control.\n	Allows collaboration among multiple developers.\n	Integrates with Azure Pipelines for CI/CD workflows.\n\n✔ Final answer: Yes.', '2026-03-14 17:56:18', 1),
	(429, 427, 'Correct answer: ✅ Yes\n\nAzure DevOps Services can be used to build web applications and deploy them to Azure hosting services such as Azure App Service.\n\nKey AZ‑900 points\n	Azure DevOps provides CI/CD pipelines to automate building, testing, and deploying web apps.\n	While DevOps itself does not host the apps, it integrates seamlessly with Azure services to host and run them.\n	This allows developers to manage the full lifecycle of web applications in Azure.\n\n✔ Final answer: Yes.\n ', '2026-03-14 17:56:18', 1),
	(430, 428, 'Correct answer: ✅ No change is needed\n\nThe statement is already correct.\n\nExplanation (AZ-900 context)\n	In Microsoft Azure, virtual machines (VMs) within the same virtual network (VNet) can communicate with each other by default.\n	To isolate VM1 from the other VMs, you must deploy it to a separate virtual network.\n\nWhy the other options are incorrect\n	Different operating system → Does not affect network connectivity.\n	Separate resource group → Only affects management and billing, not network isolation.\n	Two network interfaces → Does not prevent communication.\n\n✔ Final answer: No change is needed (the original answer is correct).\n', '2026-03-14 17:56:18', 1),
	(431, 429, 'Correct answer: ✅ Local network gateways\n\nHere’s why:\n        A local network gateway represents your on-premises VPN appliance in Azure.\n        You configure it with the public IP address of your VPN device (in this case, 131.107.200.1) and the address space of your on-premises network.\n        Azure then uses this definition when setting up a VPN connection between your on-premises network and an Azure virtual network gateway.\n\nWhy not the others?\n        Virtual networks → Define your Azure network, but don’t represent your on-premises VPN appliance.\n        \n        Virtual network gateways → Provide the Azure side of the VPN connection, not the on-premises side.\n        \n        Load balancers, Application gateways, Traffic Manager profiles, CDN profiles → These are for traffic distribution, not VPN connectivity.\n        \n        DNS zones, Network Watcher, Network security groups → These handle name resolution, monitoring, and security, not VPN appliances.\n        \n        ExpressRoute circuits → Used for private dedicated connections, not site-to-site VPNs.\n        \n        Virtual networks (classic) → Legacy, not recommended.\n\n👉 So, to identify your on-premises VPN appliance in Azure, you must create a Local network gateway.', '2026-03-14 17:56:18', 1),
	(432, 430, 'Correct answer: ✅ the virtual machines can be moved to the new subscription\n\nExplanation\n\nIn Microsoft Azure:\n	Azure resources, including virtual machines, can be moved between subscriptions as long as:\n		Both subscriptions are in the same Azure Active Directory tenant.\n		All associated resources (disks, network interfaces, public IPs, etc.) are also moved or exist in the target subscription.\n	There is no requirement that the VMs must be in the same resource group.\n	There is no OS restriction.\n\nSo, with proper planning, VMs can be moved to a new subscription.\n\n✔ Final answer: the virtual machines can be moved to the new subscription', '2026-03-14 17:56:18', 1),
	(433, 431, 'Correct answer: ✅ Authentication\n\nAuthentication is the process of verifying a user\'s credentials (such as username and password) to confirm their identity.\n\nWhy the others are incorrect\n	Authorization → Determines what resources a user can access after authentication.\n	Federation → Allows sharing identity information across different organizations or systems.\n	Ticketing → Not related to verifying user credentials.\n\n✔ Final answer: Authentication.', '2026-03-14 17:57:17', 1),
	(434, 432, 'Correct answer: ✅ the delete lock must be removed before an administrator\n\nIn Microsoft Azure, if a resource group has a delete lock, the resource group cannot be deleted by anyone, even administrators.\n\nThis lock is implemented using Azure Resource Manager to protect resources from accidental deletion.\n\nKey point\n	A Delete Lock (CanNotDelete) prevents deletion of the resource group and its resources.\n	To delete the resource group, the lock must first be removed.\n\n✔ Final answer: the delete lock must be removed before an administrator.\n ', '2026-03-14 17:57:17', 1),
	(435, 433, 'Correct answer: ✅ No\n\nIn a Platform as a Service solution such as Azure App Service, Microsoft manages the underlying infrastructure and operating system.\n\nResponsibility in PaaS\n	Microsoft manages:\n		Servers\n		Operating systems\n		Networking\n		Runtime environment\n\n	Customer manages:\n		Application code\n		Application configuration\n		Data\n\nBecause the operating system is managed by Azure, users do not have full control over it.\n\n✔ Final answer: No.', '2026-03-14 17:57:17', 1),
	(436, 434, 'Correct answer: ✅ Yes\n\nIn a Platform as a Service service like Azure App Service, you can scale resources by changing the pricing tier.\n\nHow it works\n	Each pricing tier provides different levels of:\n		CPU\n		Memory (RAM)\n		Storage\n		Features\n\nWhen you upgrade to a higher pricing tier, the web app receives more compute resources, including additional memory.\n\n✔ Final answer: Yes.', '2026-03-14 17:57:17', 1),
	(437, 435, 'Correct answer: ✅ Yes\n\nA Platform as a Service service such as Azure App Service supports automatic scaling (autoscale).\n\nHow it works\n	You can configure autoscale rules based on metrics like:\n		CPU usage\n		Memory usage\n		Request count\n		Schedule\n\nWhen demand increases, Azure automatically adds more instances, and when demand decreases, it reduces the number of instances.\n\n✔ Final answer: Yes.', '2026-03-14 17:57:17', 1),
	(438, 436, 'Correct answer: ✅ Yes\n\nUsing Azure Cloud Shell with PowerShell allows you to create resources such as Azure Virtual Machines from any device with a web browser, including an Android laptop.\n\nWhy this works\n	Azure Cloud Shell runs in the browser, so no local installation is required.\n	It supports PowerShell and Bash.\n	You can run Azure commands to create and manage VMs directly from the Azure portal.\n\n✔ Final answer: Yes.', '2026-03-14 17:57:17', 1),
	(439, 437, 'Correct answer: ✅ be deployed to a separate virtual network\n\nIn Microsoft Azure, virtual machines that are in the same virtual network can communicate with each other by default.\n\nTo ensure VM1 cannot connect to the other virtual machines, you should place it in a different virtual network using Azure Virtual Network.\n\nWhy the other options are incorrect\n	Different operating system → Does not prevent network connectivity.\n	Separate resource group → Resource groups are for management, not network isolation.\n	Two network interfaces → Does not block communication.\n\n✔ Final answer: be deployed to a separate virtual network.', '2026-03-14 17:57:17', 1),
	(440, 438, 'Correct answer: ✅ No\n\nIn Azure Service Health, administrators can only view the health of Azure services that affect their specific subscriptions and resources.\n\nWhat Azure Service Health shows\n	Service issues affecting your resources\n	Planned maintenance\n	Health advisories\n\nIt does not show the health of all Azure services globally.\n\nFor global Azure service status, you would use Azure Status.\n\n✔ Final answer: No.', '2026-03-14 17:57:17', 1),
	(441, 439, 'Correct answer:	✅ Analyze security log files from Azure virtual machines: Azure Sentinel. \n	Display the secure score for an Azure subscription: Azure Security Center (now should be Microsoft Defender for Cloud). \n	Store passwords for use by Azure Function applications: Azure Key Vault.\n\nExplanation:\n	Microsoft Sentinel analyzes security logs and provides threat detection using SIEM/SOAR capabilities.\n	Microsoft Defender for Cloud shows the Secure Score and security recommendations for your subscription.\n	Azure Key Vault securely stores passwords, secrets, certificates, and keys used by applications such as Azure Functions.\n\n✔ Final answer:\n	Analyze logs → Azure Sentinel\n	Display Secure Score → Azure Security Center / Microsoft Defender for Cloud\n	Store passwords → Azure Key Vault.', '2026-03-14 17:57:17', 1),
	(442, 440, 'Correct answer: ✅ Azure Resource Manager provides\n\nExplanation\nIn Microsoft Azure:\n	Azure Resource Manager (ARM) is the deployment and management layer for Azure.\n	It allows you to:\n		Deploy resources using ARM templates\n		Manage resources consistently\n		Apply policies, role-based access control (RBAC), and tags\n\nWhy others are incorrect\n	Resource groups → Logical containers for resources.\n	Management groups → Used to organize subscriptions.\n	No change is needed → Incorrect because Azure Policy is not the deployment platform.\n\n✔ Final answer: Azure Resource Manager provides.', '2026-03-14 17:57:17', 1),
	(443, 441, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, a Resource Group is simply a logical container for resources. The resources inside it do NOT have to be in the same region.\n\nKey points\n	A Resource Group itself has a location, but that location is only used to store metadata about the group.\n	Individual resources (VMs, storage accounts, databases, etc.) can be deployed to different regions.\n\nExample\nA single resource group could contain:\n	A VM in East US\n	A storage account in West Europe\n	A database in Central India\n\nAll of these can still belong to the same resource group.\n', '2026-03-14 17:59:17', 1),
	(444, 442, 'Correct answer: ✅ Yes\n\nWhen you assign permissions (RBAC roles) to a resource group, all resources inside that resource group automatically inherit those permissions.\nThis is because RBAC in Azure works on a hierarchical inheritance model:\n\n	Management Group → permissions flow down ⬇\n	Subscription → permissions flow down ⬇\n	Resource Group → permissions flow down ⬇\n	Individual Resources\n\nSo, if you give a user Reader, Contributor, or Owner at the resource group level, they automatically get the same access to:\n	VMs\n	Storage Accounts\n	Databases\n	Web Apps\nAny other resources inside that group\n\nUnless you explicitly override with a more restrictive role at the resource level.\n', '2026-03-14 17:59:17', 1),
	(445, 443, 'Correct answer: ❌ No.\n\nIn Microsoft Azure, choosing the same VM size like B2s does not guarantee identical monthly costs.\n\nWhy costs may differ\n\nEven if both VMs use B2s, the total cost can vary because of:\nOperating System\n	Windows VMs cost more due to licensing.\n	Linux VMs are usually cheaper.\n\nStorage type and size\n	Premium SSD, Standard SSD, or HDD pricing differs.\n\nRegion\n	Prices vary between regions like Central India and East US.\n\nUsage time\n	If one VM runs 24/7 and another is stopped part of the time.\n\nAdditional resources\n	Public IPs, managed disks, backup, monitoring, etc.\n\nConclusion\n	Two B2s VMs may have different monthly costs depending on configuration and usage.', '2026-03-14 17:59:17', 1),
	(446, 444, 'Correct answer: ✅ Yes\n\nIn Microsoft Azure, when a virtual machine is stopped (deallocated), you stop paying for compute, but you still pay for the storage associated with the VM.\n\nWhy\nA VM uses disks such as:\n	OS disk\n	Data disks\n\nThese disks are stored in Azure Managed Disks, which continue to exist even when the VM is stopped.\n\nCost behavior\n	Compute (CPU/RAM) → ❌ Not charged when deallocated\n	Storage (disks) → ✅ Still charged\n\nOther resources (like IPs) → May still incur charges depending on type\n\nExample\n	If a VM has:\n	1 OS disk (128 GB)\n	1 data disk (256 GB)\n\nYou will still pay for those disks even if the VM is not running.\n', '2026-03-14 17:59:17', 1),
	(447, 445, 'Correct answer: ✅ To enforce compliance standards\n\nThe primary purpose of Azure Policy assignments is to:\n✔ Enforce compliance standards and ensure resources follow organizational rules.\n\nAzure Policy helps you:\n	Enforce rules (e.g., allowed locations, allowed VM sizes)\n	Prevent non‑compliant resources from being created\n	Audit existing resources for compliance\n	Automatically remediate non‑compliant configurations\n\n❌ Why the other options are incorrect:\n	To create new policy definitions → No, that’s done under Definitions, not assignments.\n	To manage resource groups → Resource groups are unrelated to policy enforcement.\n	To configure network security → Network security is handled by NSGs, Firewalls, etc.\n	To automate resource deployment → That’s for ARM templates or Bicep, not Policy assignments.\n\n', '2026-03-14 17:59:17', 1),
	(448, 446, 'Correct answer: ✅ Use Azure Hybrid Benefit\n\nIn Microsoft Azure, Azure Hybrid Benefit allows you to use existing on-premises licenses with Software Assurance for services running in Azure.\n\nWhy this minimizes cost\n\nSince your company already has Microsoft SQL Server licenses with Microsoft Software Assurance, Azure Hybrid Benefit lets you:\n	Reuse those licenses in Azure Virtual Machines\n	Pay only for the VM compute cost\n	Avoid paying the SQL Server license fee again\n	\nWhy the other options are not the best answer\n	Azure Reservations – Reduces compute cost but does not reuse existing SQL licenses.\n	Deallocate VMs during off hours – Saves compute cost but not specifically SQL licensing.\n	Azure Cost Management budgets – Only tracks spending, not reduces licensing costs.\n	', '2026-03-14 17:59:17', 1),
	(449, 447, 'Correct answer: ❌ No\n\nAn Azure Free Account in Microsoft Azure allows you to use many Azure services, not only virtual machines and storage.\n\nWhat you can deploy with a free account\n	Azure App Service\n	Azure Functions\n	Azure SQL Database\n	Azure Cosmos DB\n	Azure AI Services\n\nThe free account usually includes:\n	Free credits for the first 30 days\n	12 months of certain free services\n	Always-free services with monthly limits\n ', '2026-03-14 17:59:17', 1),
	(450, 448, 'Correct answer: ✅ Yes\n\nUsing the Azure Portal meets the goal.\n\nWhy\nThe Azure portal is a web-based interface for managing Microsoft Azure. Because it runs in a web browser, you can access it from any device, including:\n	Android laptops\n	Tablets\n	Smartphones\n	Windows or macOS computers\n\nAs long as the device has a web browser and internet access, you can create and manage resources such as Azure Virtual Machines.\n\nConclusion\n	Creating a VM from an Android laptop using the Azure Portal is fully supported.\n	', '2026-03-14 17:59:17', 1),
	(451, 449, 'Correct answer: ✅ Yes\n\nUsing Azure Cloud Shell with Bash meets the goal.\n\nWhy this works\n\nAzure Cloud Shell is a browser-based command-line environment available in the Azure Portal. Since it runs in the browser, you can access it from an Android laptop.\n\nCloud Shell includes tools such as:\n	Azure CLI\n	PowerShell\n	Using Azure CLI in Bash, you can create a virtual machine with commands like az vm create.\n\nExample capability\nFrom Cloud Shell you can:\n	Create Azure Virtual Machines\n	Manage storage\n	Configure networking\n	Deploy resources\n\nSince everything runs in the cloud browser session, the device OS (Android in this case) does not matter.\n', '2026-03-14 17:59:17', 1),
	(452, 450, 'Correct answer: ✅ Azure Log Analytics\n\nTo correlate events from multiple resources into a centralized repository, you should use Azure Log Analytics.\n\nWhy Azure Log Analytics\n\nAzure Log Analytics collects and stores log and telemetry data from many Azure resources and lets you:\n	Centralize logs from multiple services\n	Query and analyze events using powerful queries\n	Correlate events across resources to troubleshoot issues\n\nIt is part of Azure Monitor, which gathers monitoring data from across the Microsoft Azure environment.\n\nWhy the other options are incorrect\n	Azure Event Hubs – Used for ingesting and streaming large amounts of event data, not primarily for correlation and analysis.\n	Azure Analysis Services – Used for data modeling and BI analytics.\n	Azure Monitor – Collects data, but Log Analytics is the component used for centralized log storage and querying.', '2026-03-14 17:59:17', 1),
	(453, 451, 'Correct answer: ✅ No change is needed\n\nThe statement already contains the correct requirement:\n	When planning to migrate a public website to Azure, you must plan to pay monthly usage costs.\n\nThis is correct because Microsoft Azure uses a pay-as-you-go pricing model, meaning you pay for the resources your website consumes (compute, storage, bandwidth, etc.).\n\nSince the statement is already correct, the appropriate choice is:\n	No change is needed\n\nWhy the other options are incorrect\n	❌ deploy a VPN – Not required for a public website.\n	❌ pay to transfer all the website data to Azure – Data transfer into Azure is generally free.\n	❌ reduce the number of connections – Azure is designed to scale to handle more connections.\n', '2026-03-15 06:14:05', 1),
	(454, 452, 'Correct answer: ✅ Configuring the SaaS solution\n\nIn a Software as a Service (SaaS) model using platforms like Microsoft Azure or services such as Microsoft 365:\n\nThe cloud provider manages:\n	Infrastructure\n	Servers\n	High availability\n	Scaling\n	Installation and updates\n\nThe customer is responsible for:\n	Configuring the SaaS application\n	Managing users\n	Setting permissions\n	Managing data\n', '2026-03-15 06:14:05', 1),
	(455, 453, 'Correct answer: ✅ Yes\n\nAzure does provide flexibility between Capital Expenditure (CapEx) and Operational Expenditure (OpEx).\nHere’s why:\n	If you move from on‑premises to Azure, you shift from CapEx (buying servers, datacenter equipment) to OpEx (pay‑as‑you‑go monthly billing).\n	Azure also offers options like Reserved Instances, which behave more like CapEx‑style commitments.\n\nThis flexibility allows organizations to choose between:\n	Pay-as-you-go (OpEx)\n	Reserved capacity (CapEx‑like)\n	Or a combination of both\n	', '2026-03-15 06:14:05', 1),
	(456, 454, 'Correct answer: ✅ Azure Machine Learning Designer\n\nTo build, test, and deploy predictive analytics models, Azure provides Azure Machine Learning Designer.\n\nIt allows you to:\n	Build machine learning models\n	Train and test predictive algorithms\n	Deploy models as web services\n	Use a drag-and-drop visual interface\n\nWhy the other options are incorrect\n	Azure Logic Apps → workflow automation\n	Azure Batch → large-scale batch computing jobs\n	Azure Cosmos DB → globally distributed database\n ', '2026-03-15 06:14:05', 1),
	(457, 455, 'Correct answer:❌ No\n\nA Standard Azure support plan does NOT include access to support engineers by phone or email.\nHere is what the Standard plan provides:\n	24/7 technical support via web only\n	No phone support\n	No email support\n\nTo meet the requirement of accessing support engineers by phone or email, your company needs at least:\n✔ Professional Direct support\nor\n✔ Unified / Premier support\n\nThese plans include:\n	24/7 phone support\n	Faster response times\n	Email-based communication with support engineers\n\n\nSummary Table\n\nSupport Plan	Phone Support?	Email Support?\nBasic				❌ No			❌ No\nDeveloper			❌ No			❌ No\nStandard			❌ No			❌ No\nProfessional Direct	✅ Yes			✅ Yes\nUnified/Premier		✅ Yes			✅ Yes\n', '2026-03-15 06:14:05', 1),
	(458, 456, 'Correct answer: ✅ portal\n\nTo manage all Azure resources in Microsoft Azure, you use the Azure portal.\n\nThe correct URL is:\nhttps://portal.azure.com\n\nSo in the format given:\nhttps://[1].[2].com\n	[1] = portal\n	[2] = azure\n\nThis portal allows you to manage:\n	Web apps\n	Virtual machines\n	Storage accounts\n	Databases\n	Networking resources\n	', '2026-03-15 06:14:05', 1),
	(459, 457, 'Correct answer: ✅ azure\n\nTo manage all resources in Microsoft Azure, you use the Azure portal, whose full URL is:\nhttps://portal.azure.com\n\nGiven the format:\nhttps://[1].[2].com\n	[1] = portal\n	[2] = azure\n\nTherefore, the correct option for [2] is:\n	✅ azure', '2026-03-15 06:14:05', 1),
	(460, 458, 'Correct answer: ✅ Blobs (REST-based object storage for unstructured data)\n\n\nIn Microsoft Azure, the data disks of Azure Virtual Machines are stored as page blobs in Azure Blob Storage.\n\nAzure Blob Storage is designed for storing large amounts of unstructured data and is used internally by Azure to store virtual hard disks (VHD files) that back VM disks.\n\nWhy the other options are incorrect\n	Files → Used for shared file storage via SMB protocol (Azure Files).\n	Tables → NoSQL key-value storage for structured data (Azure Table Storage).\n	Queues → Used for messaging between application components (Azure Queue Storage).\n', '2026-03-15 06:14:05', 1),
	(461, 459, 'Correct answer: ❌ No\n\nTo create an Azure virtual machine from any device (including an Android laptop/tablet), you must use:\n	Azure Portal (https://portal.azure.com), or\n	Azure CLI, or\n	Azure PowerShell, or\n	ARM templates\n\nPowerApps portal cannot be used to create Azure virtual machines.\nPowerApps (now part of Microsoft Power Platform):\n	Is used to build business applications\n	Cannot provision Azure infrastructure resources like VMs, storage accounts, or virtual networks\n\nTherefore, using PowerApps portal does NOT meet the requirement.\n\n✔ Correct ways to create an Azure VM from an Android laptop:\n	Use a browser → Azure Portal\n	Install Azure CLI (Cloud Shell works on any device)\n	Use Azure Cloud Shell directly in the browser\n	', '2026-03-15 06:14:05', 1),
	(462, 460, 'Correct answer: ❌ No\n\nYou do NOT need to deploy a federation solution or sync on‑premises identities to the cloud to use Azure Multi‑Factor Authentication (MFA).\n\nAzure MFA can be used with:\n	Cloud‑only users (no on‑premises directory required)\n	Microsoft Entra ID without federation\n	Security Defaults\n	Conditional Access policies\n\nDirectory synchronization (Azure AD Connect) or federation (ADFS) is optional, not required.\n✔ Key AZ‑900 takeaway:\nAzure MFA works with cloud identities directly, without any on‑premises infrastructure.', '2026-03-15 06:14:05', 1),
	(463, 461, 'Correct answer: ✅ Yes\n\nAzure Multi-Factor Authentication in Microsoft Azure can be enabled for any user account, including:\n\n	Administrative accounts (e.g., global admins)\n	Non-administrative users (regular users)\n\nMFA adds an extra layer of security by requiring users to provide two or more verification methods, such as:\n	Password\n	Mobile app notification\n	SMS code\n	Phone call\nOrganizations often enforce MFA using Conditional Access policies to require it for specific users, groups, or all users.\n', '2026-03-15 06:14:35', 1),
	(464, 462, 'Correct answer: ✅ Help + support\n\nTo see upcoming planned maintenance, service health alerts, and Azure service issues, you navigate to:\n	Azure Portal → Help + support → Service Health\n\nIn the Service Health section, you can view:\n	Planned maintenance\n	Service issues\n	Health advisories\n	Service health history\n', '2026-03-15 06:14:35', 1),
	(465, 463, 'Correct answer: ✅ Yes\n\nA company can extend the capacity of its internal (on‑premises) network by using the public cloud.\nThis is a core concept of hybrid cloud:\n	On‑premises environment + public cloud = extended capacity\n	Azure services like VPN Gateway, ExpressRoute, or VNet Peering allow seamless extension.\n\n✔ Examples:\n	Running out of storage? → Extend to Azure Storage.\n	Need more compute capacity? → Add Azure VMs.\n	Need failover capability? → Use Azure as a backup site.\n\nThis is known as cloud bursting or hybrid scaling.\n', '2026-03-15 06:14:35', 1),
	(466, 464, 'Correct answer: ❌ No\n\nPlacing virtual machines in different resource groups does NOT provide availability if a single datacenter fails.\nA resource group is only a logical container for management (RBAC, lifecycle, tagging).\nIt has no impact on physical availability, redundancy, or fault tolerance.\nTo survive a datacenter failure, you must use:\n	✔ Availability Zones (different datacenters within the same region)\n	or\n	✔ Multiple regions (geographic redundancy)\n	\n❌ What does not provide datacenter-level resiliency:\n	Resource Groups\n	VNets alone\n	Tags\n	Subscriptions\n ', '2026-03-15 06:14:35', 1),
	(467, 465, 'Correct answer:✅ Azure Resource Manager templates provide\n\nAzure Resource Manager templates provide a common platform for deploying resources (objects) to Azure in a consistent way.\n\nThey allow you to:\n	Define infrastructure using Infrastructure as Code (IaC)\n	Deploy multiple resources together\n	Ensure consistent configurations across environments\n	Reuse the same template for repeated deployments\n\nARM templates work through Azure Resource Manager, the deployment and management service of Microsoft Azure.\n\nWhy the other options are incorrect\n	Azure policies → enforce rules and compliance, not deployment\n	Resource groups → organize resources\n	Management groups → organize subscriptions\n', '2026-03-15 06:14:35', 1),
	(468, 466, 'Correct answer: ✅ Infrastructure as a service (laaS)\n\nMicrosoft Azure provides different cloud service models.\n	Infrastructure as a Service (IaaS) → You manage the OS, applications, and data while the cloud provider manages the infrastructure.\n\nExamples:\n	Azure Virtual Machines → classic IaaS service where you control the VM, OS, and software.\n\nAlthough Azure SQL Database is technically a Platform as a Service (PaaS) offering, exam questions that group Virtual Machines and SQL databases together typically expect IaaS as the answer because VMs are clearly IaaS and SQL can also run on a VM.\n\nWhy others are incorrect\n	PaaS → Used for services where Azure manages OS and runtime (e.g., Azure App Service).\n	SaaS → Fully managed applications like Microsoft 365.\n', '2026-03-15 06:14:35', 1),
	(469, 467, 'Correct answer: ✅ Pay monthly usage costs\n\nWhen you migrate a public website to Microsoft Azure, you use cloud resources such as:\n	Azure App Service\n	Azure Virtual Machines\n	Storage and networking services\nAzure follows a pay-as-you-go pricing model, meaning you pay for the resources you use, usually billed monthly (or based on usage during that period).\n\nWhy the other options are incorrect\n	❌ Deploy a VPN → Not required for a public website. VPN is mainly for private network connections.\n	❌ Pay to transfer all the website data → Data transfer into Azure is usually free; costs mainly apply to resources and outbound data.\n	❌ Reduce the number of connections → Azure is designed to scale and handle more connections, not reduce them.\n', '2026-03-15 06:14:35', 1),
	(470, 468, 'Correct answer: ❌ No\n\nMicrosoft Azure Pay-As-You-Go pricing is an example of Operational Expenditure (OpEx), not Capital Expenditure (CapEx).\n	OpEx → Pay for services as you use them (monthly or based on consumption).\n	CapEx → Large upfront investment, such as buying servers, hardware, or datacenter equipment.\n\nWith Azure’s pay-as-you-go model, you:\n	Do not buy hardware\n	Pay only for the resources you consume\n	\nTherefore, it is OpEx, not CapEx.\n', '2026-03-15 06:14:35', 1),
	(471, 469, 'Correct answer: ✅ Yes\n\nAzure Reserved VM Instances in Microsoft Azure are still considered Operational Expenditure (OpEx).\n\nEven though you commit to 1-year or 3-year reservations (and may pay upfront), you are paying for a cloud service, not purchasing physical infrastructure.\n\nKey idea\n	CapEx → Buying physical hardware (servers, datacenter equipment).\n	OpEx → Paying for cloud services over time.\n\nReserved VM Instances simply reduce the cost of running Azure Virtual Machines compared to pay-as-you-go pricing, but they remain an operational expense.', '2026-03-15 06:14:35', 1),
	(472, 470, 'Correct answer: ✅ Yes\n\nDeploying your own datacenter requires buying physical infrastructure, such as:\n	Servers\n	Storage systems\n	Networking equipment\n	Cooling and power systems\n	Physical building costs\n\nThese are one-time, upfront investments, which is the definition of Capital Expenditure (CapEx).\n\nIn contrast:\nOperational Expenditure (OpEx) is paying for services over time, like Microsoft Azure Pay-As-You-Go or Reserved VM Instances.', '2026-03-15 06:14:35', 1),
	(473, 471, 'Correct answer: ❌ No.\n\nPublic clouds, such as AWS or Azure, operate on shared, virtualized infrastructure managed by the provider, so companies cannot directly add their own physical servers to them.\n\n ', '2026-03-15 06:15:10', 1),
	(474, 472, 'Correct answer:  ✅ YES\n\nA hybrid cloud combines:\n	Private cloud / on-premises infrastructure (your own datacenter)\n	Public cloud resources\n\nTo make it hybrid, you must have resources running in the public cloud as well as resources on-premises. These environments are connected and can share workloads.\n\nFor example with Microsoft Azure:\n	Some workloads run on on-premises servers\n	Some workloads run in Azure virtual machines or services\n	They are connected using services like Azure VPN Gateway or Azure ExpressRoute\n\nWithout deploying anything to the public cloud, it would just remain a private cloud or on-premises environment, not hybrid.\n', '2026-03-15 06:15:10', 1),
	(475, 473, 'Correct answer: ❌ No\n\nA private cloud does not have to be disconnected from the internet. It simply means the cloud infrastructure is dedicated to a single organization.\n\nA private cloud can:\n	Be hosted on-premises in a company’s datacenter\n	Be hosted by a provider\n	Still have internet access if the organization allows it\n\nSo the key point:\n	Private cloud = dedicated to one organization\n	Internet connection = optional\n	', '2026-03-15 06:15:10', 1),
	(476, 474, 'Correct answer: ❌ No\n\nDeploying virtual machines to a scale set alone does NOT guarantee availability if a single datacenter fails.\nHere’s why:\n	A scale set gives you autoscaling and load balancing across multiple VMs.\n	But by default, all instances in a scale set can still be placed in the same datacenter.\n	To survive a datacenter outage, you must deploy VMs across:\n		Availability Zones (different datacenters), or\n		Availability Sets (different fault & update domains inside one datacenter)\n\nA scale set does not automatically distribute VMs across Availability Zones unless you configure it to use zone redundancy.\nSince the question doesn\'t mention zones, the solution does NOT meet the goal.\n\nCorrect requirement to meet the goal:\n✔ Deploy the VMs to a scale set with zone redundancy, or\n✔ Deploy VMs across Availability Zones\n', '2026-03-15 06:15:10', 1),
	(477, 475, 'Correct answer:✅ Yes\n\nDeploying Azure virtual machines across two or more Availability Zones does ensure that your services remain available even if one entire datacenter fails.\nWhy?\n	Availability Zones represent physically separate datacenters within the same Azure region.\n	If one zone (datacenter) goes down due to power or network failure, the VMs in the other zone continue running.\n	This provides the highest level of resiliency within a region.\n', '2026-03-15 06:15:10', 1),
	(478, 476, 'Correct answer: ✅ Configuring the SaaS solution\n\nIn a Software as a Service (SaaS) model, the cloud provider manages most of the infrastructure and platform tasks.\nFor example with Microsoft Azure SaaS services like Microsoft 365:\n\nCloud provider is responsible for:\n	Infrastructure\n	Servers\n	Networking\n	High availability\n	Scaling\n	Installing and maintaining the software\n\nCustomer is responsible for:\n	Configuring the SaaS application\n	Managing users and settings\n	Controlling data and permissions\n	Evaluate the options\n\n❌ Configuring high availability → Provider responsibility\n❌ Defining scalability rules → Provider responsibility\n❌ Installing the SaaS solution → Provider responsibility\n✅ Configuring the SaaS solution → Customer responsibility\n', '2026-03-15 06:15:10', 1),
	(479, 477, 'Correct answer: ✅ Yes\n\nDeploying virtual machines to two or more Azure regions does ensure that your services remain available even if a single datacenter fails — or even if an entire region fails.\nHere’s why:\n\n	A region contains multiple independent datacenters.\n	If you place VMs in multiple regions, then:\n\nA datacenter outage in one region will not affect the other region.\nYour application remains available.\n', '2026-03-15 06:15:10', 1),
	(480, 478, 'Correct answer: ❌ No\n\nIn Microsoft Azure, a resource group is mainly used for organizing and managing resources, not for restricting communication.\n\nResources in Azure can interact with resources in other resource groups, as long as:\n	They are in the same subscription or allowed through permissions.\n	Networking and access rules allow the connection.\n\nFor example:\n\nA Virtual Machine in Resource Group A can connect to a Storage Account in Resource Group B.\nA Web App in one resource group can access a Database in another resource group.\n\nResource groups help with:\n	Management\n	Deployment\n	Access control (RBAC at group level)\nBut they do not limit resource communication by default.\n', '2026-03-15 06:15:10', 1),
	(481, 479, 'Correct answer:✅ Yes\n\nWhen you delete an Azure resource group, all resources inside that resource group are automatically deleted.\nThis includes resources such as:\n	Virtual machines\n	Storage accounts\n	Virtual networks\n	Public IP addresses\n	Databases\n	App services\nA resource group is a container, and deleting the container deletes everything inside it.\n', '2026-03-15 06:15:10', 1),
	(482, 480, 'Correct answer:✅ Yes\n\nA resource group is a logical container for Azure resources, and it does NOT depend on region.\n\nYou can place resources from multiple different Azure regions inside the same resource group.\nThe resource group itself has a location, but this only specifies where the metadata is stored, not where the resources must be deployed.\n\n✔ Example:\nA single resource group can contain:\n	A VM in East US\n	A Storage Account in West Europe\n	A SQL Database in Southeast Asia\n\nThis is allowed and common in Azure designs.', '2026-03-15 06:15:10', 1),
	(483, 481, 'Correct answer: ✅ Yes.\n\nExplanation \nIn Microsoft Azure Storage, data that is copied to a storage account is automatically replicated to ensure durability and high availability. By default, Azure uses Locally Redundant Storage (LRS), which keeps at least three copies of the data within a single datacenter in the same region.\n\nThis automatic replication protects the data from hardware failures, disk crashes, or server issues. Azure manages this replication internally, so users do not need to manually create the copies.\n\nDepending on the selected replication option (LRS, ZRS, GRS, etc.), Azure may keep even more copies across different zones or regions, but the minimum default redundancy is three copies.\n', '2026-03-15 06:15:35', 1),
	(484, 482, 'Correct answer: ✅ Replacing failed server hardware & Managing physical server security\n\nExplanation \nResponsibilities Eliminated After Moving to Azure VMs\n	Replacing failed server hardware\n		Azure manages all physical hardware in the datacenter.\n		If hardware fails: Microsoft automatically replaces it.\n		Your VM is moved to healthy infrastructure.\n		So network admins no longer replace physical servers.\n\n	Managing physical server security\n		Azure datacenters handle:Physical building security, Access control, Surveillance, Hardware protection\n\n		Responsibilities That Remain With Your Company\n		Backing up application data : You still need to configure backups.\n		Example: Azure Backup\n\n	Updating server operating systems: VM OS patching is still your responsibility.\n		You may automate it with Azure Update Management.\n\n	Managing permissions to shared documents: Access control is still managed by your organization.\n		Typically through Microsoft Entra ID (formerly Azure AD).\n', '2026-03-15 06:15:35', 1),
	(485, 483, 'Correct answer: ✅ No change is needed.\n\nExplanation \nAzure Cosmos DB is an example of a Platform as a Service (PaaS) offering. No change is needed\n\n	Infrastructure as a Service (IaaS): Incorrect, as users manage OS and apps (e.g., Azure VMs), not abstracted like Cosmos DB.\n	Serverless: While it supports serverless models, it\'s fundamentally PaaS, not purely serverless like Azure Functions.\n	Software as a Service (SaaS): Incorrect, as SaaS offers complete apps, whereas Cosmos DB is a database platform\n', '2026-03-15 06:15:35', 1),
	(486, 484, 'Correct answer: ✅ Authentication.\n\nExplanation \n[Authorization] is not the process of verifying a user\'s credentials. Change it to [Authentication]\n\nNo change is needed: Incorrect, as the statement misattributes credential verification to authorization.\nFederation: Involves trusting external identity providers for authentication across systems, not core credential verification.\nTicketing: Refers to token-based systems like Kerberos for authorization after authentication, not the verification process itself.\n​', '2026-03-15 06:15:35', 1),
	(487, 485, 'Correct answer: ✅ The public cloud is a shared entity whereby multiple corporations each use a portion of the resources in the cloud.\n\n\nExplanation \nThe primary benefit of using a public cloud service for the servers is that the public cloud is a shared entity whereby multiple corporations each use a portion of the resources in the cloud.\n\nWhy Shared Resources?\n	Migrating on-premises servers to Azure\'s public cloud allows multiple organizations to leverage the same underlying infrastructure efficiently through multi-tenancy, enabling cost savings via pay-as-you-go models, scalability, and reduced hardware ownership. \n	This shared model provides high availability across global data centers without dedicated physical resources per customer.\n\n	Owned by the public: Incorrect, as public clouds like Azure are owned by private corporations (Microsoft), not the general public.\n	Freely accessed by everyone: False, access is controlled via subscriptions, authentication, and permissions, not open to all.\n	Crowd-sourcing solution: Wrong, public cloud isn\'t crowd-sourced; it\'s professionally managed infrastructure shared among paying customers.\n\n​', '2026-03-15 06:15:35', 1);
