INSERT INTO `question` (`question_id`, `topic_id`, `question_text`, `question_type`, `difficulty`, `created_at`, `is_active`) VALUES
	(1, 1, 'If you plan to host a web application in the Azure platform as a service solution of Azure Web Apps, then the platform will have the ability to scale automatically?', 'SINGLE', 'MEDIUM', '2026-01-25 17:44:39', 1),
	(2, 1, 'You decide to create 2 Virtual machines. Each virtual machine is of the size D2s v3. Would these machines always generate the same monthly cost?', 'SINGLE', 'MEDIUM', '2026-01-25 17:53:06', 1),
	(3, 1, 'Your team needs to have a tool that provides a digital online assistant that can provide speech support. ', 'SINGLE', 'MEDIUM', '2026-01-25 17:59:44', 1),
	(4, 1, 'Your team needs to have a tool that can use past trainings to provide predictions of very high probability. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:11:22', 1),
	(5, 1, 'Your team needs to have a tool that can provide serverless computing capabilities. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:17:04', 1),
	(6, 1, 'Your team needs to have a tool that can be used to process data from millions of sensors. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:23:18', 1),
	(7, 1, 'A company needs to deploy a set of resources to Azure. Below are the key requirements for the deployment: The need to be deployed across several departments. The resources that need to be deployed are all of the same type. You need to recommend a solution to automate the deployment of the Azure resources. Which of the following would you use for this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:27:35', 1),
	(8, 1, 'Your company needs to deploy an application to virtual machines hosted in Azure. The solution must ensure an SLA of 99.99%. What is the minimum number of virtual machines and availability zones that you need to recommend for the deployment?', 'SINGLE', 'MEDIUM', '2026-01-25 18:32:03', 1),
	(9, 1, 'Your team needs a tool that can be used to correlate events from multiple resources into a central repository. Which of the following can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:36:34', 1),
	(10, 1, 'A company is planning on hosting an application on an Azure Virtual Machine. It needs to be ensured that the application hosted on the virtual machine is accessible from the Internet over HTTPS. You decide to implement a DDoS protection plan. Would this satisfy the requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:41:21', 1),
	(11, 1, 'A company is planning on hosting an application on an Azure Virtual Machine. It needs to be ensured that the application hosted on the virtual machine is accessible from the Internet over HTTPS. You decide to implement an Azure Traffic Manager profile. Would this satisfy the requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:47:53', 1),
	(12, 1, 'Which of the following customers are eligible to use Azure Government to develop a cloud solution? Choose 2 answers from the options given below.', 'MULTIPLE', 'MEDIUM', '2026-01-25 18:48:15', 1),
	(13, 1, 'A team is currently planning on using Azure for hosting resources. They are going to create users which would have access to the Azure resources. They want to implement Multi-Factor authentication for the users. Is it required to deploy a federated solution to implement Multi-Factor authentication?', 'SINGLE', 'MEDIUM', '2026-01-25 18:48:42', 1),
	(14, 1, 'A team is currently planning on using Azure for hosting resources. They are going to create users which would have access to the Azure resources. They want to implement Multi-Factor authentication for the users. Are two valid methods for Azure Multi-Factor authentication picture identification and entering a passport number.', 'SINGLE', 'MEDIUM', '2026-01-25 18:48:57', 1),
	(15, 1, 'Which of the following support plan gives you access to best practice information, health status and notifications, and 24/7 access to billing information at the lowest possible cost.', 'SINGLE', 'MEDIUM', '2026-01-25 18:49:05', 1),
	(16, 1, 'If you plan to host a web application in the Azure platform as a service solution of Azure Web Apps, then you will have complete control over the underlying operating system.', 'SINGLE', 'MEDIUM', '2026-01-25 18:49:14', 1),
	(17, 1, 'You decide to create a virtual machine which is of the size D2s_v3. If you plan to stop the virtual machine, will you incur any costs for the storage associated with the virtual machine.', 'SINGLE', 'MEDIUM', '2026-01-25 18:49:22', 1),
	(18, 1, 'Your company is planning on using Azure for hosting Infrastructure level resources such as Azure Virtual Machines. When planning for the costing aspect for these resources, is there a flexibility offered when it comes to Capital and Operational Expenditure.', 'SINGLE', 'MEDIUM', '2026-01-25 18:49:29', 1),
	(19, 1, 'You are looking at using a Software as a Service in Azure. Which of the following would you be responsible for?', 'SINGLE', 'MEDIUM', '2026-01-25 18:49:52', 1),
	(20, 1, 'A company is planning on migrating all of their on-premises servers to Azure. Their business continuity department has advised that they need to ensure that servers hosted in Azure are available even if an Azure Data Center were to go down. Which of the following is a concept that would be involved in the design stage for this requirement.', 'SINGLE', 'MEDIUM', '2026-01-25 18:50:02', 1),
	(21, 1, 'Under which of the following circumstances could a company look at decommissioning its data center?', 'SINGLE', 'MEDIUM', '2026-01-25 18:53:10', 1),
	(22, 1, 'A company is planning on migrating a web site to Azure. This is a public web site that is used by users on the Internet. Which of the following must the company plan for if they are planning to migrate the web site to Azure?', 'SINGLE', 'MEDIUM', '2026-01-25 18:53:24', 1),
	(23, 1, 'An administrator needs to run a script written in PowerShell. This script is going to create a virtual machine in Azure. Would the script run on a computer that runs Linux and has the Azure CLI tools installed?', 'SINGLE', 'MEDIUM', '2026-01-25 18:53:33', 1),
	(24, 1, 'An administrator needs to run a script written in PowerShell. This script is going to create a virtual machine in Azure. Would you be able to run the script on a machine that has Chrome OS installed and uses Azure Cloud Shell?', 'SINGLE', 'MEDIUM', '2026-01-25 18:53:41', 1),
	(25, 1, 'An administrator needs to run a script written in PowerShell. This script is going to create a virtual machine in Azure. Would you be able to run the script on a machine that has macOS and PowerShell core installed?', 'SINGLE', 'MEDIUM', '2026-01-25 18:53:50', 1),
	(26, 1, 'An Administrator needs to view the list of planned maintenance events that could potentially affect the availability of the resources hosted in an Azure subscription. Which of the following blade in the Azure portal should the administrator consider for this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:54:01', 1),
	(27, 1, 'Your team needs to have an integrated solution in place that can be used for the deployment of code. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:54:15', 1),
	(28, 1, 'Your team needs a tool that can provide guidance and recommendations that can be used to improve an Azure environment. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:54:29', 1),
	(29, 1, 'Your team needs to use a tool that can be used to build intelligent Artificial Intelligence based applications. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:54:41', 1),
	(30, 1, 'Your team needs to have a tool that can be used to monitor web applications deployed to Azure. Which of the following service can be used for this purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 18:54:52', 1),
	(31, 1, 'A team currently has several computers in their on-premises environment that runs on Windows 10. They need to share files by enabling mapped drives from the computers. Which of the following would be an ideal storage solution for this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:58:51', 1),
	(32, 1, 'A company wants to have a data store hosted in Azure. Below are the key requirements for the data store: The data store must be able to store JSON documents. The data store must be able to handle data writes from multiple regions. Which of the following would be the ideal data store for this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:06', 1),
	(33, 1, 'A team is planning on deploying Azure Virtual Machines to a resource group named demogroup. The group has been created in the US Central region. Do the virtual machines deployed to the resource group also need to be deployed to the US Central region only?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:17', 1),
	(34, 1, 'A team is planning on assigning tags to a resource group. Would the tag be inherited by resources in the resource group?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:26', 1),
	(35, 1, 'A set of IAM permissions have been assigned to a resource group. Would the resources in the resource group automatically inherit the IAM permissions assigned to the resource group?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:35', 1),
	(36, 1, 'Which of the following service can be used to build, test and deploy a predictive analytics solution that could subsequently be used to deploy an Artificial Intelligence solution to Azure?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:43', 1),
	(37, 1, 'Your team is planning on using the Azure Advisor tool. Would the Azure Advisor tool give recommendations on how to configure network settings for Azure virtual machines?', 'SINGLE', 'MEDIUM', '2026-01-25 18:59:53', 1),
	(38, 1, 'Your team is planning on using the Azure Advisor tool. Would the Azure Advisor tool give recommendations on how to save costs when it comes to hosting virtual machines in Azure?', 'SINGLE', 'MEDIUM', '2026-01-25 19:00:04', 1),
	(39, 1, 'Your team is planning on using the Azure Advisor tool. Would the Azure Advisor tool give recommendations on how to improve the security for Microsoft Entra ID?', 'SINGLE', 'MEDIUM', '2026-01-25 19:00:13', 1),
	(40, 1, 'A support engineer currently has a computer that runs Ubuntu. Which of the following Azure Management tools could be run from this computer?', 'MULTIPLE', 'MEDIUM', '2026-01-25 19:02:01', 1),
	(41, 1, 'Your company has just setup an Azure account and Microsoft Entra ID. They need to ensure that when users connect to Microsoft Entra ID from the Internet from an Anonymous IP address, they are prompted to change their password automatically. Which of the following Azure service can help them achieve this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 19:05:48', 1),
	(42, 1, 'A company is planning to create several virtual machines that will be used to host web and database servers. You need to limit the type of connections from the web and database servers. Which of the following can be used to fulfil this requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 19:05:57', 1),
	(43, 1, 'Which of the following can be used to allow an organization to manage the compliance of resources across multiple subscriptions?', 'SINGLE', 'MEDIUM', '2026-01-25 19:06:53', 1),
	(44, 1, 'Your company is planning on setting an Azure environment by setting up a subscription and Microsoft Entra ID. They need to purchase a low-cost option support plan. The support plan needs to ensure 24*7 access to support engineers by phone or email. You suggest opting for the Basic Support plan. Does this support the requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 19:07:26', 1),
	(45, 1, 'Your company is planning on setting an Azure environment by setting up a subscription and Microsoft Entra ID. They need to purchase a low-cost option support plan. The support plan needs to ensure 24*7 access to support engineers by phone or email. You suggest opting for the Standard Support plan. Does this support the requirement?', 'SINGLE', 'MEDIUM', '2026-01-25 19:07:45', 1),
	(46, 1, 'Does Microsoft release most of the Azure services in private preview before being introduced in public preview?', 'SINGLE', 'MEDIUM', '2026-01-25 19:08:00', 1),
	(47, 1, 'Is it true that Azure services released in public preview can only be managed via the Azure command line interface?', 'SINGLE', 'MEDIUM', '2026-01-25 19:08:14', 1),
	(48, 1, 'Is it true that an Azure service that is released in private preview is made available to all Azure customers?', 'SINGLE', 'MEDIUM', '2026-01-25 19:08:31', 1),
	(49, 1, 'Is it true that an Azure service that is released in public preview is made available to all Azure customers?', 'SINGLE', 'MEDIUM', '2026-01-25 19:09:37', 1),
	(50, 1, 'Is it true that an Azure service that is released as generally available is made available to all Azure customers?', 'SINGLE', 'MEDIUM', '2026-01-25 19:09:55', 1),
	(51, 1, 'Can a single Microsoft Account be used to manage multiple Azure subscriptions?', 'SINGLE', 'MEDIUM', '2026-01-25 19:12:09', 1),
	(52, 1, 'Is it possible to merge subscriptions into a single subscription?', 'SINGLE', 'MEDIUM', '2026-01-25 19:13:16', 1),
	(53, 1, 'A company has just started using Azure. They have setup a subscription and started deploying resources to Azure. Would they be guaranteed a service level agreement of at least 99.9% for paid Azure services?', 'SINGLE', 'MEDIUM', '2026-01-25 19:13:29', 1),
	(54, 1, 'A company has just started using Azure. They have setup a subscription and started deploying resources to Azure. Could the company increase the SLA for their resources by deploying resources across multiple regions?', 'SINGLE', 'MEDIUM', '2026-01-25 19:13:40', 1),
	(55, 1, 'A company has just started using Azure. They have setup a subscription and started deploying resources to Azure. Could the company increase the SLA for their resources by purchasing multiple subscriptions?', 'SINGLE', 'MEDIUM', '2026-01-25 19:13:55', 1),
	(56, 1, 'A set of virtual machines have been created in a subscription. You have now paid for a new subscription. Is it possible to move the virtual machines to the new subscription?', 'SINGLE', 'MEDIUM', '2026-01-25 19:14:09', 1),
	(57, 1, 'A company has defined the following resources in Azure: 10 Public IP addresses. 20 users in Microsoft Entra ID. 5 user groups in Microsoft Entra ID. They now want to reduce the costs associated with the Azure account. Would the removal of the users from the account help reduce the cost?', 'SINGLE', 'MEDIUM', '2026-01-25 19:14:23', 1),
	(58, 1, 'A company has defined the following resources in Azure: 10 Public IP addresses. 20 users in Microsoft Entra ID. 5 user groups in Microsoft Entra ID. They now want to reduce the costs associated with the Azure account. Would the removal of the user groups from the account help reduce the cost?', 'SINGLE', 'MEDIUM', '2026-01-25 19:14:40', 1),
	(59, 1, 'A company has defined the following resources in Azure: 10 Public IP addresses. 20 users in Microsoft Entra ID. 5 user groups in Microsoft Entra ID. They now want to reduce the costs associated with the Azure account. Would the removal of the public IP addresses from the account help reduce the cost?', 'SINGLE', 'MEDIUM', '2026-01-25 19:14:55', 1),
	(60, 1, 'A team member currently has a laptop that is based on the Android OS. The team member wants to create a virtual machine in Azure. The team member decides to use the Azure portal to create the virtual machine. Would this suit the purpose?', 'SINGLE', 'MEDIUM', '2026-01-25 19:15:35', 1),
	(61, 1, 'A team member currently has a laptop that is based on the Android OS. The team member wants to create a virtual machine in Azure. The team member decides to use the PowerApps portal to create the virtual machine. Would this suit the purpose?', 'SINGLE', 'MEDIUM', '2026-02-13 02:56:03', 1),
	(62, 1, 'Which of the following URL is used to manage the creation of Azure resources?', 'SINGLE', 'MEDIUM', '2026-02-13 02:58:13', 1),
	(63, 1, 'You need to create a virtual machine in Azure. Which of the following storage account service is used to store the data disks for the virtual machine?', 'SINGLE', 'MEDIUM', '2026-02-13 02:59:59', 1),
	(64, 1, 'Your company needs to have a data store in Azure. Below are the key requirements for the data store: The data store should be capable of storing 10TB of data. The data would be accessed infrequently. The data would need to be visualised using PowerBI. Which of the following services could you use for this requirement? Choose 2 answers from the options given below.', 'MULTIPLE', 'MEDIUM', '2026-02-13 03:01:32', 1),
	(65, 1, 'You need to deploy several virtual machines to Azure. You need to ensure that you can assign permissions to the virtual machines simultaneously. Which of the following can be implemented to fulfil this requirement?', 'SINGLE', 'MEDIUM', '2026-02-13 03:03:48', 1),
